uint16_t Assets::CalculateChecksum(const char *data, uint32_t size)
{
    uint32_t checksum = 0;

    // Sum all bytes in the data buffer
    for (uint32_t i = 0; i < size; i++) {
        checksum += static_cast<uint8_t>(data[i]);
    }

    // Mask to 16 bits to get the final checksum
    return static_cast<uint16_t>(checksum & 0xFFFF);
}

bool Assets::InitializePartition()
{
    // Find the assets partition
    const esp_partition_t* partition = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");
    if (partition == nullptr) {
        ESP_LOGE(TAG, "Assets partition not found");
        return false;
    }

    // Check if partition has sufficient space
    if (partition->size == 0) {
        ESP_LOGE(TAG, "Assets partition has zero size");
        return false;
    }

    // Map the partition into memory
    spi_flash_mmap_handle_t mmap_handle;
    const void* mapped_ptr;
    esp_err_t err = esp_partition_mmap(partition, 0, partition->size, SPI_FLASH_MMAP_DATA, &mapped_ptr, &mmap_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    // Store mapping information
    m_mapped_data = static_cast<const uint8_t*>(mapped_ptr);
    m_mapped_size = partition->size;
    m_mmap_handle = mmap_handle;

    // Verify checksum (assuming first 4 bytes are checksum)
    if (m_mapped_size < sizeof(uint32_t)) {
        ESP_LOGE(TAG, "Assets partition too small for checksum");
        UnmapPartition();
        return false;
    }

    // Simple checksum validation (assuming checksum is first 4 bytes)
    uint32_t stored_checksum = *reinterpret_cast<const uint32_t*>(m_mapped_data);
    uint32_t calculated_checksum = 0;

    // Calculate checksum of remaining data (simple sum for example)
    for (size_t i = sizeof(uint32_t); i < m_mapped_size && i < 1024; i++) {
        calculated_checksum += m_mapped_data[i];
    }

    if (stored_checksum != calculated_checksum) {
        ESP_LOGW(TAG, "Checksum mismatch - stored: 0x%08X, calculated: 0x%08X", stored_checksum, calculated_checksum);
        // Depending on requirements, we might want to continue or fail here
        // For now, let's continue but log the warning
    }

    // Build asset index
    BuildAssetIndex();

    ESP_LOGI(TAG, "Assets partition initialized successfully, size: %d bytes", m_mapped_size);
    return true;
}

void Assets::UnmapPartition()
{
    if (m_mapped_data != nullptr) {
        spi_flash_munmap(m_mmap_handle);
        m_mapped_data = nullptr;
        m_mapped_size = 0;
    }
}

void Assets::BuildAssetIndex()
{
    // Clear existing index
    m_asset_index.clear();

    // Parse asset table from mapped data
    // Assuming asset table starts after checksum (4 bytes)
    const size_t table_offset = sizeof(uint32_t);
    const size_t entry_size = sizeof(mmap_assets_table);

    if (m_mapped_size <= table_offset) {
        ESP_LOGE(TAG, "No space for asset table");
        return;
    }

    // Read number of assets (assuming first 4 bytes after checksum indicate count)
    if (m_mapped_size < table_offset + sizeof(uint32_t)) {
        ESP_LOGE(TAG, "Insufficient space for asset count");
        return;
    }

    uint32_t asset_count = *reinterpret_cast<const uint32_t*>(m_mapped_data + table_offset);

    // Validate reasonable asset count
    if (asset_count > 1000) {
        ESP_LOGE(TAG, "Unreasonable asset count: %d", asset_count);
        return;
    }

    // Parse asset entries
    const size_t entries_offset = table_offset + sizeof(uint32_t);
    const size_t required_size = entries_offset + (asset_count * entry_size);

    if (m_mapped_size < required_size) {
        ESP_LOGE(TAG, "Insufficient space for asset entries");
        return;
    }

    const mmap_assets_table* table = reinterpret_cast<const mmap_assets_table*>(m_mapped_data + entries_offset);

    for (uint32_t i = 0; i < asset_count; i++) {
        AssetInfo info;
        info.name = std::string(table[i].asset_name);
        info.size = table[i].asset_size;
        info.offset = table[i].asset_offset;
        info.width = table[i].asset_width;
        info.height = table[i].asset_height;

        // Validate asset data
        if (info.offset + info.size <= m_mapped_size) {
            m_asset_index[info.name] = info;
        } else {
            ESP_LOGW(TAG, "Asset '%s' extends beyond partition bounds", info.name.c_str());
        }
    }

    ESP_LOGI(TAG, "Built asset index with %d assets", m_asset_index.size());
}

bool Assets::Apply()
{
    ESP_LOGI(TAG, "Applying assets from index.json");

    // Check if LCD display is available
    #ifdef HAVE_LVGL
    if (!lcd_display_is_initialized()) {
        ESP_LOGE(TAG, "LCD display not initialized");
        return false;
    }
    #endif

    // Load index.json configuration
    FILE* fp = fopen("/spiffs/index.json", "r");
    if (!fp) {
        ESP_LOGE(TAG, "Failed to open index.json");
        return false;
    }

    // Get file size
    fseek(fp, 0, SEEK_END);
    long file_size = ftell(fp);
    fseek(fp, 0, SEEK_SET);

    // Allocate buffer and read file
    char* json_buffer = (char*)malloc(file_size + 1);
    if (!json_buffer) {
        ESP_LOGE(TAG, "Failed to allocate memory for JSON buffer");
        fclose(fp);
        return false;
    }

    size_t bytes_read = fread(json_buffer, 1, file_size, fp);
    fclose(fp);

    if (bytes_read != file_size) {
        ESP_LOGE(TAG, "Failed to read complete index.json file");
        free(json_buffer);
        return false;
    }

    json_buffer[file_size] = '\0';

    // Parse JSON
    cJSON* root = cJSON_Parse(json_buffer);
    if (!root) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        free(json_buffer);
        return false;
    }

    free(json_buffer);

    // Validate asset version
    cJSON* version_obj = cJSON_GetObjectItem(root, "version");
    if (!version_obj || !cJSON_IsString(version_obj)) {
        ESP_LOGE(TAG, "Missing or invalid version in index.json");
        cJSON_Delete(root);
        return false;
    }

    const char* version = cJSON_GetStringValue(version_obj);
    ESP_LOGI(TAG, "Asset version: %s", version);

    // Process speech recognition models
    cJSON* sr_models = cJSON_GetObjectItem(root, "speech_recognition_models");
    if (sr_models && cJSON_IsArray(sr_models)) {
        int model_count = cJSON_GetArraySize(sr_models);
        ESP_LOGI(TAG, "Processing %d speech recognition models", model_count);

        for (int i = 0; i < model_count; i++) {
            cJSON* model = cJSON_GetArrayItem(sr_models, i);
            if (!model) continue;

            cJSON* name_obj = cJSON_GetObjectItem(model, "name");
            cJSON* path_obj = cJSON_GetObjectItem(model, "path");

            if (name_obj && path_obj && cJSON_IsString(name_obj) && cJSON_IsString(path_obj)) {
                const char* name = cJSON_GetStringValue(name_obj);
                const char* path = cJSON_GetStringValue(path_obj);

                ESP_LOGI(TAG, "Loading SR model: %s from %s", name, path);
                // TODO: Implement actual speech recognition model loading
                // This would typically involve loading model files and initializing SR engine
            }
        }
    }

    // Process UI themes
    cJSON* themes = cJSON_GetObjectItem(root, "ui_themes");
    if (themes && cJSON_IsArray(themes)) {
        int theme_count = cJSON_GetArraySize(themes);
        ESP_LOGI(TAG, "Processing %d UI themes", theme_count);

        for (int i = 0; i < theme_count; i++) {
            cJSON* theme = cJSON_GetArrayItem(themes, i);
            if (!theme) continue;

            cJSON* name_obj = cJSON_GetObjectItem(theme, "name");
            cJSON* font_obj = cJSON_GetObjectItem(theme, "font");
            cJSON* emoji_obj = cJSON_GetObjectItem(theme, "emoji_support");

            if (name_obj && cJSON_IsString(name_obj)) {
                const char* theme_name = cJSON_GetStringValue(name_obj);
                ESP_LOGI(TAG, "Applying theme: %s", theme_name);

                // Process fonts
                if (font_obj && cJSON_IsObject(font_obj)) {
                    cJSON* font_path = cJSON_GetObjectItem(font_obj, "path");
                    cJSON* font_size = cJSON_GetObjectItem(font_obj, "size");

                    if (font_path && font_size && cJSON_IsString(font_path) && cJSON_IsNumber(font_size)) {
                        const char* path = cJSON_GetStringValue(font_path);
                        int size = cJSON_GetNumberValue(font_size);

                        ESP_LOGI(TAG, "Loading font: %s (size: %d)", path, size);

                        #ifdef HAVE_LVGL
                        // Load font and apply to LVGL theme
                        lv_font_t* loaded_font = lvgl_load_font(path, size);
                        if (loaded_font) {
                            lvgl_theme_set_font(loaded_font);
                        } else {
                            ESP_LOGW(TAG, "Failed to load font: %s", path);
                        }
                        #endif
                    }
                }

                // Process emoji support
                if (emoji_obj && cJSON_IsBool(emoji_obj)) {
                    bool emoji_enabled = cJSON_IsTrue(emoji_obj);
                    ESP_LOGI(TAG, "Emoji support: %s", emoji_enabled ? "enabled" : "disabled");

                    if (emoji_enabled) {
                        #ifdef HAVE_LVGL
                        // Initialize emoji display system
                        emote_display_init();
                        #endif
                    }
                }
            }
        }
    }

    // Clean up
    cJSON_Delete(root);

    ESP_LOGI(TAG, "Assets applied successfully");
    return true;
}

bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    ESP_LOGI(TAG, "Starting asset download from: %s", url.c_str());

    // Initialize HTTP client
    esp_http_client_config_t config = {};
    config.url = url.c_str();
    config.timeout_ms = 30000;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    // Open HTTP connection
    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Get content length
    int content_length = esp_http_client_fetch_headers(client);
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Invalid content length: %d", content_length);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    ESP_LOGI(TAG, "Content length: %d bytes", content_length);

    // Get flash partition for assets
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, 
        ESP_PARTITION_SUBTYPE_DATA_SPIFFS, 
        "assets"
    );

    if (!partition) {
        ESP_LOGE(TAG, "Assets partition not found");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Check if content fits in partition
    if ((size_t)content_length > partition->size) {
        ESP_LOGE(TAG, "Content too large for partition. Content: %d, Partition: %u", 
                 content_length, partition->size);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Erase partition
    ESP_LOGI(TAG, "Erasing partition...");
    err = esp_partition_erase_range(partition, 0, partition->size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Download and write data
    const size_t buffer_size = 4096;
    uint8_t* buffer = (uint8_t*)malloc(buffer_size);
    if (!buffer) {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    size_t total_written = 0;
    size_t offset = 0;
    int last_progress = -1;
    int64_t start_time = esp_timer_get_time();
    bool success = true;

    ESP_LOGI(TAG, "Starting download...");

    while (total_written < (size_t)content_length) {
        int data_read = esp_http_client_read(client, (char*)buffer, buffer_size);

        if (data_read < 0) {
            ESP_LOGE(TAG, "HTTP read error");
            success = false;
            break;
        }

        if (data_read == 0) {
            // No more data
            break;
        }

        // Write to flash
        err = esp_partition_write(partition, offset, buffer, data_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to partition: %s", esp_err_to_name(err));
            success = false;
            break;
        }

        total_written += data_read;
        offset += data_read;

        // Calculate and report progress
        int current_progress = (total_written * 100) / content_length;
        if (current_progress != last_progress) {
            last_progress = current_progress;

            // Calculate speed (bytes/second)
            int64_t elapsed_us = esp_timer_get_time() - start_time;
            size_t speed = 0;
            if (elapsed_us > 0) {
                speed = (total_written * 1000000ULL) / elapsed_us;
            }

            // Call progress callback
            if (progress_callback) {
                progress_callback(current_progress, speed);
            }

            ESP_LOGD(TAG, "Download progress: %d%%, Speed: %zu bytes/sec", 
                     current_progress, speed);
        }
    }

    free(buffer);
    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    if (success && total_written == (size_t)content_length) {
        ESP_LOGI(TAG, "Download completed successfully: %zu bytes", total_written);
        return true;
    } else {
        ESP_LOGE(TAG, "Download failed. Written: %zu, Expected: %d", 
                 total_written, content_length);
        return false;
    }
}

bool Assets::GetAssetData(const std::string &asset_name, void *&data, size_t &size)
{
    // Assuming there's a member variable storing the mapped memory or asset table
    // This would typically be initialized elsewhere in the class

    // First, find the asset in our asset table
    const mmap_assets_table *asset_table = nullptr;
    size_t asset_count = 0;

    // Assuming we have access to the asset table (this would be a member variable)
    // For now, I'll assume there's a way to access it
    extern const mmap_assets_table _binary_assets_start[];
    extern const mmap_assets_table _binary_assets_end[];

    asset_table = _binary_assets_start;
    asset_count = (_binary_assets_end - _binary_assets_start);

    const mmap_assets_table *found_asset = nullptr;

    // Search for the asset by name
    for (size_t i = 0; i < asset_count; i++) {
        if (strcmp(asset_table[i].asset_name, asset_name.c_str()) == 0) {
            found_asset = &asset_table[i];
            break;
        }
    }

    // If asset not found, return false
    if (found_asset == nullptr) {
        ESP_LOGW(TAG, "Asset '%s' not found", asset_name.c_str());
        return false;
    }

    // Assuming there's a base address for the memory-mapped assets
    // This would typically be a member variable of the Assets class
    extern const uint8_t _binary_assets_data_start[];
    const uint8_t *base_addr = _binary_assets_data_start;

    // Calculate the address of the asset data
    const uint8_t *asset_ptr = base_addr + found_asset->asset_offset;

    // Assuming the asset format includes a header with a magic number
    // Typical structure might be: [MAGIC(4 bytes)][SIZE(4 bytes)][DATA...]
    if (found_asset->asset_size < sizeof(uint32_t) * 2) {
        ESP_LOGE(TAG, "Asset '%s' size too small", asset_name.c_str());
        return false;
    }

    // Read magic number (assuming it's the first 4 bytes)
    const uint32_t *magic_ptr = reinterpret_cast<const uint32_t*>(asset_ptr);
    uint32_t magic_number = *magic_ptr;

    // Define expected magic number (this should be defined somewhere as a constant)
    const uint32_t ASSET_MAGIC_NUMBER = 0x41534554; // "TESA" in little-endian

    // Validate magic number
    if (magic_number != ASSET_MAGIC_NUMBER) {
        ESP_LOGE(TAG, "Asset '%s' has invalid magic number: 0x%08X", asset_name.c_str(), magic_number);
        return false;
    }

    // Read the stored size from the header (assuming it's the second 4 bytes)
    const uint32_t *size_ptr = reinterpret_cast<const uint32_t*>(asset_ptr + sizeof(uint32_t));
    uint32_t stored_size = *size_ptr;

    // Validate the stored size matches what we expect
    if (stored_size != (found_asset->asset_size - sizeof(uint32_t) * 2)) {
        ESP_LOGE(TAG, "Asset '%s' size mismatch", asset_name.c_str());
        return false;
    }

    // Set output parameters
    // Data pointer points to the actual data (after magic and size header)
    data = const_cast<uint8_t*>(asset_ptr + sizeof(uint32_t) * 2);
    size = stored_size;

    ESP_LOGD(TAG, "Successfully loaded asset '%s', size: %d bytes", asset_name.c_str(), size);
    return true;
}

const char *DeviceStateMachine::GetStateName(DeviceState state)
{
    // Check if state is within valid range
    if (state >= DeviceState::UNKNOWN && state < DeviceState::INVALID_STATE) {
        return STATE_STRINGS[static_cast<int>(state)];
    }

    // Return "unknown" for invalid states
    return STATE_STRINGS[static_cast<int>(DeviceState::UNKNOWN)];
}

bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const
{
    // Self-transitions are always valid
    if (from == to) {
        return true;
    }

    // Define valid transitions based on device logic
    switch (from) {
        case DeviceState::unknown:
            return to == DeviceState::starting;

        case DeviceState::starting:
            return to == DeviceState::wifi_configuring || 
                   to == DeviceState::idle;

        case DeviceState::wifi_configuring:
            return to == DeviceState::idle;

        case DeviceState::idle:
            return to == DeviceState::connecting || 
                   to == DeviceState::upgrading || 
                   to == DeviceState::activating || 
                   to == DeviceState::audio_testing ||
                   to == DeviceState::fatal_error;

        case DeviceState::connecting:
            return to == DeviceState::listening || 
                   to == DeviceState::speaking || 
                   to == DeviceState::idle;

        case DeviceState::listening:
            return to == DeviceState::speaking || 
                   to == DeviceState::idle;

        case DeviceState::speaking:
            return to == DeviceState::listening || 
                   to == DeviceState::idle;

        case DeviceState::upgrading:
            return to == DeviceState::idle || 
                   to == DeviceState::fatal_error;

        case DeviceState::activating:
            return to == DeviceState::idle || 
                   to == DeviceState::fatal_error;

        case DeviceState::audio_testing:
            return to == DeviceState::idle || 
                   to == DeviceState::fatal_error;

        case DeviceState::fatal_error:
            // Generally no transitions out of fatal error state
            return false;

        default:
            // Invalid states cannot transition anywhere
            return false;
    }
}

bool DeviceStateMachine::TransitionTo(DeviceState new_state)
{
    DeviceState old_state = current_state_;

    // Check if transition is valid
    if (!IsValidTransition(old_state, new_state)) {
        ESP_LOGW(TAG, "Invalid state transition from %s to %s", 
                 GetStateName(old_state), GetStateName(new_state));
        return false;
    }

    // Perform the transition
    current_state_ = new_state;

    ESP_LOGI(TAG, "State transition: %s -> %s", 
             GetStateName(old_state), GetStateName(new_state));

    // Notify observers
    NotifyObservers(old_state, new_state);

    return true;
}

bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to)
{
    // Define valid transitions
    switch (from) {
        case DEVICE_STATE_UNKNOWN:
            return to == DEVICE_STATE_STARTING || 
                   to == DEVICE_STATE_WIFI_CONFIGURING ||
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_STARTING:
            return to == DEVICE_STATE_IDLE || 
                   to == DEVICE_STATE_WIFI_CONFIGURING ||
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_WIFI_CONFIGURING:
            return to == DEVICE_STATE_IDLE || 
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_IDLE:
            return to == DEVICE_STATE_CONNECTING || 
                   to == DEVICE_STATE_UPGRADING ||
                   to == DEVICE_STATE_ACTIVATING ||
                   to == DEVICE_STATE_AUDIO_TESTING ||
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_CONNECTING:
            return to == DEVICE_STATE_LISTENING || 
                   to == DEVICE_STATE_SPEAKING ||
                   to == DEVICE_STATE_IDLE ||
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_LISTENING:
            return to == DEVICE_STATE_SPEAKING || 
                   to == DEVICE_STATE_IDLE ||
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_SPEAKING:
            return to == DEVICE_STATE_LISTENING || 
                   to == DEVICE_STATE_IDLE ||
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_UPGRADING:
            return to == DEVICE_STATE_IDLE || 
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_ACTIVATING:
            return to == DEVICE_STATE_IDLE || 
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_AUDIO_TESTING:
            return to == DEVICE_STATE_IDLE || 
                   to == DEVICE_STATE_FATAL_ERROR;

        case DEVICE_STATE_FATAL_ERROR:
            // Fatal error state should only transition to starting or remain in fatal
            return to == DEVICE_STATE_STARTING;

        default:
            return false;
    }
}

void DeviceStateMachine::NotifyObservers(DeviceState from, DeviceState to)
{
    // Notify all registered observers about the state change
    for (auto& observer : observers_) {
        observer->OnStateChanged(from, to);
    }
}

const char *DeviceStateMachine::GetStateName(DeviceState state)
{
    if (state >= 0 && state < sizeof(STATE_STRINGS) / sizeof(STATE_STRINGS[0])) {
        return STATE_STRINGS[state];
    }
    return "invalid_state";
}

uint32_t DeviceStateMachine::AddStateChangeListener(StateCallback callback)
{
    std::lock_guard<std::mutex> lock(listener_mutex_);

    // Generate unique ID (simple incrementing approach)
    uint32_t listener_id = next_listener_id_++;

    // Handle wraparound case (unlikely but good practice)
    if (next_listener_id_ == 0) {
        next_listener_id_ = 1;
    }

    // Store the callback with its ID
    state_listeners_[listener_id] = std::move(callback);

    ESP_LOGD(TAG, "Added state change listener with ID: %lu", listener_id);

    return listener_id;
}

void DeviceStateMachine::RemoveStateChangeListener(int listenerId)
{
    std::lock_guard<std::mutex> lock(listenerMutex_);

    auto it = std::find_if(stateChangeListeners_.begin(), stateChangeListeners_.end(),
        [listenerId](const StateChangeListener& listener) {
            return listener.id == listenerId;
        });

    if (it != stateChangeListeners_.end()) {
        stateChangeListeners_.erase(it);
        ESP_LOGD(TAG, "Removed state change listener with ID: %d", listenerId);
    } else {
        ESP_LOGW(TAG, "Attempted to remove non-existent state change listener with ID: %d", listenerId);
    }
}

void DeviceStateMachine::NotifyStateChange(DeviceState old_state, DeviceState new_state)
{
    ESP_LOGD(TAG, "State changed from %s to %s", 
             STATE_STRINGS[old_state], STATE_STRINGS[new_state]);

    // Create a local copy of callbacks to minimize lock time
    std::vector<std::function<void(DeviceState, DeviceState)>> callbacks_copy;

    // Lock the mutex to safely access the callbacks list
    {
        std::lock_guard<std::mutex> lock(callbacks_mutex_);
        callbacks_copy = state_change_callbacks_;
    }

    // Invoke all callbacks with the state change information
    for (const auto& callback : callbacks_copy) {
        if (callback) {
            try {
                callback(old_state, new_state);
            } catch (const std::exception& e) {
                ESP_LOGE(TAG, "Exception in state change callback: %s", e.what());
            } catch (...) {
                ESP_LOGE(TAG, "Unknown exception in state change callback");
            }
        }
    }
}

extern "C" void app_main(void)
{
    // Initialize NVS flash storage
    esp_err_t ret = nvs_flash_init();

    // Handle NVS corruption by erasing and reinitializing if necessary
    if (ret == ESP_ERR_NVS_NO_FREE_PAGES || ret == ESP_ERR_NVS_NEW_VERSION_FOUND) {
        // NVS partition was truncated or version changed, erase and reinitialize
        ESP_LOGW(TAG, "NVS flash initialization failed, erasing and retrying...");
        ESP_ERROR_CHECK(nvs_flash_erase());
        ret = nvs_flash_init();
    }

    // Check if NVS initialization was successful
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize NVS flash storage: %s", esp_err_to_name(ret));
        return;
    }

    ESP_LOGI(TAG, "NVS flash storage initialized successfully");

    // Initialize the system information module
    system_info_init();

    // Log system information
    ESP_LOGI(TAG, "System started - Chip: %s, SDK Version: %s", 
             system_info_get_chip_model(), 
             system_info_get_sdk_version());

    // Create and start the main application instance
    Application* app = new Application();
    if (app != nullptr) {
        ESP_LOGI(TAG, "Starting main application...");
        app->start();

        // The application should handle its own event loop
        // If we reach here, the application has finished or encountered an error
        delete app;
    } else {
        ESP_LOGE(TAG, "Failed to create application instance");
    }

    // If we reach this point, something went wrong
    ESP_LOGE(TAG, "Application terminated unexpectedly");
}

Ota::Ota()
{
    // Initialize serial number from eFuse user data
    uint8_t mac_addr[6];
    esp_err_t err = esp_efuse_mac_get_default(mac_addr);

    if (err == ESP_OK) {
        // Convert MAC address to string format as serial number
        char serial_str[18]; // Format: XX:XX:XX:XX:XX:XX + null terminator
        snprintf(serial_str, sizeof(serial_str), "%02X:%02X:%02X:%02X:%02X:%02X",
                 mac_addr[0], mac_addr[1], mac_addr[2], 
                 mac_addr[3], mac_addr[4], mac_addr[5]);

        m_serial_number = std::string(serial_str);
        ESP_LOGI(TAG, "Device serial number initialized: %s", m_serial_number.c_str());
    } else {
        // Fallback: Generate serial from chip ID or other unique identifier
        uint32_t chip_id = 0;
        #ifdef CONFIG_IDF_TARGET_ESP32
            chip_id = REG_READ(EFUSE_BLK0_RDATA3_REG) & 0xFFFFFFF0;
        #elif defined(CONFIG_IDF_TARGET_ESP32S2)
            chip_id = REG_READ(EFUSE_RD_CHIPID_REG);
        #elif defined(CONFIG_IDF_TARGET_ESP32C3) || defined(CONFIG_IDF_TARGET_ESP32S3)
            chip_id = REG_READ(EFUSE_RD_CHIPID_REG);
        #endif

        if (chip_id != 0) {
            char serial_str[32];
            snprintf(serial_str, sizeof(serial_str), "ESP32-%08X", chip_id);
            m_serial_number = std::string(serial_str);
            ESP_LOGI(TAG, "Device serial number initialized from chip ID: %s", m_serial_number.c_str());
        } else {
            // Last resort: use generic identifier
            m_serial_number = "UNKNOWN_DEVICE";
            ESP_LOGW(TAG, "Failed to read device serial number, using default: %s", m_serial_number.c_str());
        }
    }

    // Ensure we have a valid serial number
    if (m_serial_number.empty()) {
        m_serial_number = "UNIDENTIFIED_DEVICE";
        ESP_LOGW(TAG, "Serial number was empty, set to default: %s", m_serial_number.c_str());
    }
}

std::string Ota::GetCheckVersionUrl()
{
    // Try to get URL from Wi-Fi settings first
    std::string url = Settings::GetInstance().GetWifiSettings().ota_check_version_url;

    // If URL is empty or not set, fall back to default
    if (url.empty()) {
        // Use default configuration value
        url = CONFIG_OTA_DEFAULT_VERSION_CHECK_URL;

        // Log that we're using the default URL
        ESP_LOGI(TAG, "Using default OTA version check URL: %s", url.c_str());
    } else {
        // Log that we're using the configured URL
        ESP_LOGI(TAG, "Using configured OTA version check URL: %s", url.c_str());
    }

    return url;
}

esp_http_client_handle_t Ota::SetupHttp()
{
    esp_http_client_config_t config = {};
    config.url = Settings::GetInstance().GetOtaUrl().c_str();
    config.timeout_ms = 30000;
    config.transport_type = HTTP_TRANSPORT_UNKNOWN;

    esp_http_client_handle_t client = esp_http_client_init(&config);

    if (client == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return nullptr;
    }

    // Set device identification header
    std::string deviceId = SystemInfo::GetDeviceId();
    esp_http_client_set_header(client, "X-Device-ID", deviceId.c_str());

    // Set user agent
    esp_http_client_set_header(client, "User-Agent", "ESP32-OTA-Client/1.0");

    // Set language header
    const char* langCode = LangConfig::GetCurrentLanguageCode();
    if (langCode != nullptr) {
        esp_http_client_set_header(client, "Accept-Language", langCode);
    }

    // Set content type for firmware binary
    esp_http_client_set_header(client, "Content-Type", "application/octet-stream");

    // Conditionally set serial number if device is provisioned
    if (SystemInfo::IsProvisioned()) {
        std::string serialNumber = SystemInfo::GetSerialNumber();
        if (!serialNumber.empty()) {
            esp_http_client_set_header(client, "X-Serial-Number", serialNumber.c_str());
        }
    }

    // Set accept header for firmware updates
    esp_http_client_set_header(client, "Accept", "application/octet-stream");

    ESP_LOGI(TAG, "HTTP client configured for OTA update");
    return client;
}

esp_err_t Ota::CheckVersion()
{
    esp_err_t ret = ESP_OK;

    // Get current firmware version
    const esp_app_desc_t* app_desc = esp_ota_get_app_description();
    const char* current_version = app_desc->version;

    ESP_LOGI(TAG, "Current firmware version: %s", current_version);

    // Prepare HTTP client configuration
    esp_http_client_config_t config = {};
    config.url = Settings::GetInstance().GetUpdateServerUrl().c_str();
    config.transport_type = HTTP_TRANSPORT_UNKNOWN;
    config.timeout_ms = 10000; // 10 second timeout

    // Create HTTP client
    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return ESP_FAIL;
    }

    // Perform HTTP GET request
    esp_err_t err = esp_http_client_perform(client);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "HTTP GET request failed: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return err;
    }

    int status_code = esp_http_client_get_status_code(client);
    if (status_code != 200) {
        ESP_LOGE(TAG, "HTTP request failed with status code: %d", status_code);
        esp_http_client_cleanup(client);
        return ESP_FAIL;
    }

    // Read response data
    int content_length = esp_http_client_get_content_length(client);
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Invalid content length");
        esp_http_client_cleanup(client);
        return ESP_FAIL;
    }

    std::vector<char> response_data(content_length + 1, 0);
    int read_len = esp_http_client_read(client, response_data.data(), content_length);
    if (read_len <= 0) {
        ESP_LOGE(TAG, "Failed to read HTTP response");
        esp_http_client_cleanup(client);
        return ESP_FAIL;
    }

    response_data[read_len] = '\0';
    esp_http_client_cleanup(client);

    // Parse JSON response
    cJSON* json = cJSON_Parse(response_data.data());
    if (!json) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        const char* error_ptr = cJSON_GetErrorPtr();
        if (error_ptr) {
            ESP_LOGE(TAG, "Error before: %s", error_ptr);
        }
        return ESP_FAIL;
    }

    // Extract version information from JSON
    cJSON* version_item = cJSON_GetObjectItemCaseSensitive(json, "version");
    if (!version_item || !cJSON_IsString(version_item)) {
        ESP_LOGE(TAG, "Version field not found or invalid in JSON response");
        cJSON_Delete(json);
        return ESP_FAIL;
    }

    const char* latest_version = version_item->valuestring;
    ESP_LOGI(TAG, "Latest firmware version: %s", latest_version);

    // Compare versions
    if (strcmp(current_version, latest_version) == 0) {
        ESP_LOGI(TAG, "Firmware is up to date");
        cJSON_Delete(json);
        return ESP_OK;
    }

    // Check if it's a newer version (simple string comparison - could be enhanced)
    // For now, we'll assume any different version that's not identical should be updated
    ESP_LOGI(TAG, "New firmware version available: %s", latest_version);

    // Check for firmware URL
    cJSON* firmware_url_item = cJSON_GetObjectItemCaseSensitive(json, "firmware_url");
    if (firmware_url_item && cJSON_IsString(firmware_url_item)) {
        std::string firmware_url = firmware_url_item->valuestring;
        ESP_LOGI(TAG, "Firmware URL: %s", firmware_url.c_str());

        // Store firmware URL for later use in actual update process
        // This would typically trigger the full OTA update procedure
    }

    // Handle activation-related data
    cJSON* activation_item = cJSON_GetObjectItemCaseSensitive(json, "activation");
    if (activation_item && cJSON_IsObject(activation_item)) {
        cJSON* token_item = cJSON_GetObjectItemCaseSensitive(activation_item, "token");
        if (token_item && cJSON_IsString(token_item)) {
            std::string activation_token = token_item->valuestring;
            ESP_LOGI(TAG, "Activation token received");
            // Store activation token in settings or handle as needed
        }
    }

    // Handle MQTT configuration updates
    cJSON* mqtt_item = cJSON_GetObjectItemCaseSensitive(json, "mqtt");
    if (mqtt_item && cJSON_IsObject(mqtt_item)) {
        Settings& settings = Settings::GetInstance();

        cJSON* broker_item = cJSON_GetObjectItemCaseSensitive(mqtt_item, "broker");
        if (broker_item && cJSON_IsString(broker_item)) {
            settings.SetMqttBroker(broker_item->valuestring);
        }

        cJSON* port_item = cJSON_GetObjectItemCaseSensitive(mqtt_item, "port");
        if (port_item && cJSON_IsNumber(port_item)) {
            settings.SetMqttPort(port_item->valueint);
        }

        cJSON* username_item = cJSON_GetObjectItemCaseSensitive(mqtt_item, "username");
        if (username_item && cJSON_IsString(username_item)) {
            settings.SetMqttUsername(username_item->valuestring);
        }

        cJSON* password_item = cJSON_GetObjectItemCaseSensitive(mqtt_item, "password");
        if (password_item && cJSON_IsString(password_item)) {
            settings.SetMqttPassword(password_item->valuestring);
        }

        cJSON* topic_item = cJSON_GetObjectItemCaseSensitive(mqtt_item, "topic");
        if (topic_item && cJSON_IsString(topic_item)) {
            settings.SetMqttTopic(topic_item->valuestring);
        }

        ESP_LOGI(TAG, "MQTT configuration updated from server response");
    }

    // Save settings if any changes were made
    Settings::GetInstance().Save();

    // Clean up
    cJSON_Delete(json);

    // Return success but indicate update is available
    // In a real implementation, you might want to return a specific code
    // to indicate that an update is available vs. no update needed
    return ESP_OK;
}

void Ota::MarkCurrentVersionValid()
{
    // Get the currently running partition
    const esp_partition_t* current_partition = esp_ota_get_running_partition();
    if (current_partition == nullptr) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    // Skip validation for factory partition
    if (current_partition->type == ESP_PARTITION_TYPE_APP && 
        current_partition->subtype == ESP_PARTITION_SUBTYPE_APP_FACTORY) {
        ESP_LOGI(TAG, "Factory partition running, skipping validation");
        return;
    }

    // Check if the partition is in pending verification state
    esp_ota_img_states_t ota_state;
    esp_err_t err = esp_ota_get_state_partition(current_partition, &ota_state);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get partition state: %s", esp_err_to_name(err));
        return;
    }

    // Only mark as valid if it's in pending verification state
    if (ota_state == ESP_OTA_IMG_PENDING_VERIFY) {
        ESP_LOGI(TAG, "Marking current firmware as valid");
        err = esp_ota_mark_app_valid_cancel_rollback();
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mark app as valid: %s", esp_err_to_name(err));
        } else {
            ESP_LOGI(TAG, "Successfully marked firmware as valid");
        }
    } else {
        ESP_LOGD(TAG, "Partition not in pending verify state (state: %d), no action needed", ota_state);
    }
}

bool Ota::Upgrade(const std::string& url, std::function<void(int progress, size_t speed)> progressCallback)
{
    ESP_LOGI(TAG, "Starting OTA upgrade from URL: %s", url.c_str());

    esp_err_t err;
    esp_http_client_config_t config = {};
    config.url = url.c_str();
    config.timeout_ms = 30000; // 30 second timeout

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    int content_length = esp_http_client_fetch_headers(client);
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Invalid content length: %d", content_length);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Get OTA partition
    const esp_partition_t* update_partition = esp_ota_get_next_update_partition(NULL);
    if (!update_partition) {
        ESP_LOGE(TAG, "Failed to get next update partition");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x", 
             update_partition->subtype, update_partition->address);

    // Begin OTA
    esp_ota_handle_t update_handle = 0;
    err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed: %s", esp_err_to_name(err));
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Download and write firmware
    const int buffer_size = 4096;
    std::vector<uint8_t> buffer(buffer_size);
    int binary_file_length = 0;
    int last_progress = -1;
    uint32_t start_time = esp_timer_get_time() / 1000; // ms

    while (true) {
        int data_read = esp_http_client_read(client, reinterpret_cast<char*>(buffer.data()), buffer_size);
        if (data_read < 0) {
            ESP_LOGE(TAG, "Error reading data from HTTP stream");
            esp_ota_abort(update_handle);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        } else if (data_read == 0) {
            // End of stream
            break;
        }

        err = esp_ota_write(update_handle, buffer.data(), data_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Error writing data to partition: %s", esp_err_to_name(err));
            esp_ota_abort(update_handle);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        binary_file_length += data_read;

        // Report progress
        if (progressCallback && content_length > 0) {
            int progress = (binary_file_length * 100) / content_length;
            if (progress != last_progress) {
                uint32_t elapsed_time = (esp_timer_get_time() / 1000) - start_time;
                size_t speed = 0;
                if (elapsed_time > 0) {
                    speed = (binary_file_length * 1000) / elapsed_time; // bytes per second
                }
                progressCallback(progress, speed);
                last_progress = progress;
                ESP_LOGD(TAG, "OTA progress: %d%%, Speed: %d bytes/sec", progress, speed);
            }
        }
    }

    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    ESP_LOGI(TAG, "Total binary data written: %d bytes", binary_file_length);

    // Verify firmware header
    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed: %s", esp_err_to_name(err));
        return false;
    }

    // Check if the binary is a valid app
    esp_app_desc_t app_desc;
    err = esp_ota_get_partition_description(update_partition, &app_desc);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read app description: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "New firmware version: %s", app_desc.version);

    // Optional: Check version compatibility here
    // For example, compare with current version from system_info.h
    // This would depend on how version checking is implemented

    // Set boot partition
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA upgrade completed successfully. Next boot will use this partition.");
    return true;
}

std::vector<int> Ota::ParseVersion(const std::string &version)
{
    std::vector<int> result;
    std::stringstream ss(version);
    std::string component;

    while (std::getline(ss, component, '.')) {
        try {
            // Remove any whitespace
            component.erase(0, component.find_first_not_of(" \t"));
            component.erase(component.find_last_not_of(" \t") + 1);

            // Convert to integer and add to result
            if (!component.empty()) {
                int num = std::stoi(component);
                result.push_back(num);
            }
        } catch (const std::exception& e) {
            // If conversion fails, log warning and treat as 0
            ESP_LOGW(TAG, "Failed to parse version component: %s", component.c_str());
            result.push_back(0);
        }
    }

    return result;
}

bool Ota::IsNewVersionAvailable(const std::string& current_version, const std::string& candidate_version)
{
    // Helper lambda to parse version string into vector of integers
    auto parse_version = [](const std::string& version_str) -> std::vector<int> {
        std::vector<int> components;
        std::stringstream ss(version_str);
        std::string segment;

        while (std::getline(ss, segment, '.')) {
            try {
                // Remove any non-digit characters and convert to integer
                std::string clean_segment;
                for (char c : segment) {
                    if (std::isdigit(c)) {
                        clean_segment += c;
                    }
                }
                if (!clean_segment.empty()) {
                    components.push_back(std::stoi(clean_segment));
                } else {
                    components.push_back(0);
                }
            } catch (const std::exception&) {
                components.push_back(0);
            }
        }

        // Ensure we have at least 3 components (major.minor.patch)
        while (components.size() < 3) {
            components.push_back(0);
        }

        return components;
    };

    // Parse both versions
    std::vector<int> current_components = parse_version(current_version);
    std::vector<int> candidate_components = parse_version(candidate_version);

    // Compare components sequentially
    size_t max_size = std::max(current_components.size(), candidate_components.size());

    for (size_t i = 0; i < max_size; ++i) {
        int current_val = (i < current_components.size()) ? current_components[i] : 0;
        int candidate_val = (i < candidate_components.size()) ? candidate_components[i] : 0;

        if (candidate_val > current_val) {
            return true;  // Candidate version is newer
        } else if (candidate_val < current_val) {
            return false; // Candidate version is older
        }
        // If equal, continue to next component
    }

    // Versions are identical
    return false;
}

std::string Ota::GetActivationPayload(const std::string& challenge)
{
    // Get device serial number
    std::string serial_number = SystemInfo::GetSerialNumber();

    // Return empty JSON object if serial number is not available
    if (serial_number.empty()) {
        return "{}";
    }

    // Prepare data to be signed (serial number + challenge)
    std::string data_to_sign = serial_number + challenge;

    // Compute HMAC-SHA256 signature
    std::vector<uint8_t> signature(32); // SHA256 produces 32 bytes
    size_t signature_len = 0;

#ifdef SOC_HMAC_SUPPORTED
    // Use hardware HMAC if supported
    esp_err_t err = esp_hmac_calculate(HMAC_KEY0, 
                                      reinterpret_cast<const uint8_t*>(data_to_sign.c_str()), 
                                      data_to_sign.length(), 
                                      signature.data());
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Hardware HMAC calculation failed: %s", esp_err_to_name(err));
        return "{}";
    }
    signature_len = 32;
#else
    // Fallback - this would typically use software HMAC implementation
    // For now, we'll return empty object as hardware support is expected
    ESP_LOGW(TAG, "HMAC hardware support not available");
    return "{}";
#endif

    // Convert signature to hex string
    std::stringstream ss;
    for (size_t i = 0; i < signature_len; i++) {
        ss << std::hex << std::setfill('0') << std::setw(2) << static_cast<int>(signature[i]);
    }
    std::string signature_hex = ss.str();

    // Create JSON payload
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        return "{}";
    }

    cJSON_AddStringToObject(root, "serial_number", serial_number.c_str());
    cJSON_AddStringToObject(root, "challenge", challenge.c_str());
    cJSON_AddStringToObject(root, "signature", signature_hex.c_str());

    char* json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string ? json_string : "{}");

    if (json_string) {
        cJSON_free(json_string);
    }
    cJSON_Delete(root);

    return result;
}

esp_err_t Ota::Activate()
{
    esp_err_t ret = ESP_OK;

    // Get current running partition info
    const esp_partition_t* running_partition = esp_ota_get_running_partition();
    if (running_partition == nullptr) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return ESP_FAIL;
    }

    // Get system information
    SystemInfo sys_info;
    std::string device_id = sys_info.GetDeviceId();
    std::string firmware_version = sys_info.GetFirmwareVersion();

    // Construct activation URL (assuming it's stored in settings or constructed from base URL)
    Settings& settings = Settings::GetInstance();
    std::string base_url = settings.GetServerUrl();
    if (base_url.empty()) {
        ESP_LOGE(TAG, "Server URL not configured");
        return ESP_ERR_INVALID_STATE;
    }

    // Ensure URL ends with proper path
    std::string activation_url = base_url;
    if (activation_url.back() != '/') {
        activation_url += "/";
    }
    activation_url += "api/v1/devices/activate";

    // Prepare JSON payload
    cJSON* root = cJSON_CreateObject();
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to create JSON object");
        return ESP_ERR_NO_MEM;
    }

    cJSON_AddStringToObject(root, "device_id", device_id.c_str());
    cJSON_AddStringToObject(root, "firmware_version", firmware_version.c_str());
    cJSON_AddStringToObject(root, "partition_label", running_partition->label);
    cJSON_AddNumberToObject(root, "partition_address", running_partition->address);

    char* json_string = cJSON_PrintUnformatted(root);
    if (json_string == nullptr) {
        ESP_LOGE(TAG, "Failed to print JSON");
        cJSON_Delete(root);
        return ESP_ERR_NO_MEM;
    }

    cJSON_Delete(root);

    // TODO: Implement actual HTTP POST request
    // This would typically involve:
    // 1. Initialize HTTP client
    // 2. Set URL, headers (Content-Type: application/json)
    // 3. Set POST data (json_string)
    // 4. Perform request
    // 5. Check response status code
    // 6. Parse response body if needed

    // For now, simulating the HTTP request logic:
    esp_http_client_config_t config = {
        .url = activation_url.c_str(),
        .method = HTTP_METHOD_POST,
        .cert_pem = nullptr, // Add certificate validation in production
    };

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        free(json_string);
        return ESP_FAIL;
    }

    // Set headers
    esp_http_client_set_header(client, "Content-Type", "application/json");
    esp_http_client_set_post_field(client, json_string, strlen(json_string));

    // Perform the request
    int http_status = 0;
    esp_err_t http_ret = esp_http_client_perform(client);

    if (http_ret == ESP_OK) {
        http_status = esp_http_client_get_status_code(client);
        ESP_LOGI(TAG, "HTTP POST Status = %d", http_status);

        if (http_status >= 200 && http_status < 300) {
            ESP_LOGI(TAG, "Activation successful");
            ret = ESP_OK;
        } else if (http_status == 400) {
            ESP_LOGE(TAG, "Bad request - invalid activation data");
            ret = ESP_ERR_INVALID_ARG;
        } else if (http_status == 401) {
            ESP_LOGE(TAG, "Unauthorized - device not registered");
            ret = ESP_ERR_INVALID_STATE;
        } else if (http_status == 404) {
            ESP_LOGE(TAG, "Device not found");
            ret = ESP_ERR_NOT_FOUND;
        } else if (http_status >= 500) {
            ESP_LOGE(TAG, "Server error");
            ret = ESP_ERR_HTTP_BASE + http_status;
        } else {
            ESP_LOGE(TAG, "Unexpected HTTP status: %d", http_status);
            ret = ESP_FAIL;
        }
    } else {
        ESP_LOGE(TAG, "HTTP POST request failed: %s", esp_err_to_name(http_ret));
        ret = http_ret;
    }

    // Cleanup
    esp_http_client_cleanup(client);
    free(json_string);

    // If activation was successful, mark the current partition as bootable
    if (ret == ESP_OK) {
        esp_ota_img_states_t ota_state;
        if (esp_ota_get_state_partition(running_partition, &ota_state) == ESP_OK) {
            if (ota_state == ESP_OTA_IMG_PENDING_VERIFY) {
                esp_err_t ota_ret = esp_ota_mark_app_valid_cancel_rollback();
                if (ota_ret != ESP_OK) {
                    ESP_LOGW(TAG, "Failed to mark app as valid: %s", esp_err_to_name(ota_ret));
                }
            }
        }
    }

    return ret;
}

Settings::~Settings()
{
    if (read_write_) {
        esp_err_t err = nvs_commit(nvs_handle_);
        if (err != ESP_OK) {
            ESP_LOGW(TAG, "Failed to commit NVS changes: %s", esp_err_to_name(err));
        }
    }

    nvs_close(nvs_handle_);
}

std::string Settings::GetString(const std::string &key, const std::string &default_value)
{
    size_t required_size = 0;

    // First call to get the required buffer size
    esp_err_t err = nvs_get_str(nvs_handle_, key.c_str(), nullptr, &required_size);

    // If key doesn't exist or other error, return default value
    if (err != ESP_OK || required_size == 0) {
        return default_value;
    }

    // Allocate buffer for the string (including null terminator)
    char *value_buffer = new char[required_size];

    // Second call to actually retrieve the string
    err = nvs_get_str(nvs_handle_, key.c_str(), value_buffer, &required_size);

    if (err != ESP_OK) {
        delete[] value_buffer;
        return default_value;
    }

    // Create string from buffer and clean up trailing null characters
    std::string result(value_buffer);
    delete[] value_buffer;

    // Remove trailing null characters if any
    while (!result.empty() && result.back() == '\0') {
        result.pop_back();
    }

    return result;
}

void Settings::SetString(const std::string &key, const std::string &value)
{
    if (!read_write_) {
        ESP_LOGW(TAG, "Attempt to write to read-only namespace '%s'", ns_.c_str());
        return;
    }

    esp_err_t err = nvs_set_str(nvs_handle_, key.c_str(), value.c_str());
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set string key '%s' in namespace '%s': %s", 
                 key.c_str(), ns_.c_str(), esp_err_to_name(err));
        return;
    }

    dirty_ = true;
}

int32_t Settings::GetInt(const std::string &key, int32_t default_value)
{
    int32_t value = default_value;
    esp_err_t err = nvs_get_i32(nvs_handle_, key.c_str(), &value);

    if (err != ESP_OK) {
        if (err == ESP_ERR_NVS_NOT_FOUND) {
            ESP_LOGI(TAG, "Key '%s' not found, returning default value: %ld", key.c_str(), default_value);
        } else {
            ESP_LOGE(TAG, "Error reading key '%s' from NVS: %s", key.c_str(), esp_err_to_name(err));
        }
        return default_value;
    }

    ESP_LOGD(TAG, "Retrieved key '%s' with value: %ld", key.c_str(), value);
    return value;
}

void Settings::SetInt(const std::string &key, int32_t value)
{
    if (!read_write_) {
        ESP_LOGW(TAG, "Attempt to write to read-only settings namespace");
        return;
    }

    esp_err_t err = nvs_set_i32(nvs_handle_, key.c_str(), value);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set int value for key '%s': %s", key.c_str(), esp_err_to_name(err));
        return;
    }

    err = nvs_commit(nvs_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to commit NVS changes: %s", esp_err_to_name(err));
        return;
    }

    dirty_ = true;
}

bool Settings::GetBool(const std::string &key, bool default_value)
{
    if (nvs_handle_ == 0) {
        ESP_LOGE(TAG, "NVS handle is not initialized");
        return default_value;
    }

    uint8_t value = 0;
    esp_err_t err = nvs_get_u8(nvs_handle_, key.c_str(), &value);

    if (err == ESP_OK) {
        ESP_LOGD(TAG, "Retrieved boolean setting %s: %s", key.c_str(), value ? "true" : "false");
        return value != 0;
    } else if (err == ESP_ERR_NVS_NOT_FOUND) {
        ESP_LOGD(TAG, "Boolean setting %s not found, returning default: %s", key.c_str(), default_value ? "true" : "false");
        return default_value;
    } else {
        ESP_LOGE(TAG, "Error retrieving boolean setting %s: %s", key.c_str(), esp_err_to_name(err));
        return default_value;
    }
}

void Settings::SetBool(const std::string &key, bool value)
{
    if (read_write_) {
        uint8_t bool_value = value ? 1 : 0;
        esp_err_t err = nvs_set_u8(nvs_handle_, key.c_str(), bool_value);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to set boolean value for key '%s': %s", key.c_str(), esp_err_to_name(err));
        } else {
            dirty_ = true;
        }
    } else {
        ESP_LOGW(TAG, "Attempt to write boolean value to read-only namespace");
    }
}

void Settings::EraseKey(const std::string &key)
{
    if (!read_write_) {
        ESP_LOGW(TAG, "Cannot erase key '%s' - namespace '%s' is read-only", key.c_str(), ns_.c_str());
        return;
    }

    esp_err_t err = nvs_erase_key(nvs_handle_, key.c_str());

    if (err == ESP_ERR_NVS_NOT_FOUND) {
        // Key doesn't exist, which is fine - handle gracefully
        ESP_LOGD(TAG, "Key '%s' not found in namespace '%s' - nothing to erase", key.c_str(), ns_.c_str());
        return;
    } else if (err != ESP_OK) {
        // Other error occurred
        ESP_LOGE(TAG, "Failed to erase key '%s' from namespace '%s': %s", 
                 key.c_str(), ns_.c_str(), esp_err_to_name(err));
        return;
    }

    // Successfully marked key for erasure, now commit
    err = nvs_commit(nvs_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to commit NVS changes after erasing key '%s': %s", 
                 key.c_str(), esp_err_to_name(err));
    } else {
        ESP_LOGD(TAG, "Successfully erased key '%s' from namespace '%s'", key.c_str(), ns_.c_str());
    }
}

void Settings::EraseAll()
{
    if (!read_write_) {
        ESP_LOGW(TAG, "Cannot erase settings: namespace '%s' is read-only", ns_.c_str());
        return;
    }

    esp_err_t err = nvs_erase_all(nvs_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase all settings in namespace '%s': %s", 
                 ns_.c_str(), esp_err_to_name(err));
        return;
    }

    err = nvs_commit(nvs_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to commit erase operation in namespace '%s': %s", 
                 ns_.c_str(), esp_err_to_name(err));
        return;
    }

    ESP_LOGI(TAG, "Successfully erased all settings in namespace '%s'", ns_.c_str());
}

