std::string SystemInfo::GetMacAddress() {
    uint8_t mac[6];
    char mac_str[18]; // 12 hex chars + 5 colons + 1 null terminator

    // Read the MAC address for WiFi station interface
    esp_err_t err = esp_read_mac(mac, ESP_MAC_WIFI_STA);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read MAC address: %s", esp_err_to_name(err));
        return "";
    }

    // Format as hexadecimal string with colons
    snprintf(mac_str, sizeof(mac_str), "%02x:%02x:%02x:%02x:%02x:%02x",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);

    return std::string(mac_str);
}

std::string SystemInfo::GetUserAgent() {
    // Get the application description which contains version info
    const esp_app_desc_t* app_desc = esp_app_get_description();

    // Check if app description is valid
    if (app_desc == nullptr) {
        ESP_LOGE(TAG, "Failed to get application description");
        return "UNKNOWN/unknown";
    }

    // Get version string from app description
    const char* version = app_desc->version;

    // Define board name - this could be made configurable
    const char* board_name = "ESP32"; // Default board name

    // Construct user agent string in format "BOARD_NAME/version"
    std::string user_agent = std::string(board_name) + "/" + std::string(version);

    ESP_LOGI(TAG, "User Agent: %s", user_agent.c_str());

    return user_agent;
}

void SystemInfo::PrintTaskCpuUsage(TickType_t xDelayTicks) {
    // Get initial task states
    UBaseType_t uxArraySize = uxTaskGetNumberOfTasks();
    TaskStatus_t* pxTaskStatusArrayInitial = (TaskStatus_t*)malloc(uxArraySize * sizeof(TaskStatus_t));
    TaskStatus_t* pxTaskStatusArrayFinal = (TaskStatus_t*)malloc(uxArraySize * sizeof(TaskStatus_t));

    if (pxTaskStatusArrayInitial == NULL || pxTaskStatusArrayFinal == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task status arrays");
        free(pxTaskStatusArrayInitial);
        free(pxTaskStatusArrayFinal);
        return;
    }

    // Capture initial task states and run times
    UBaseType_t uxInitialCount = uxTaskGetSystemState(pxTaskStatusArrayInitial, uxArraySize, NULL);

    // Wait for the specified time interval
    vTaskDelay(xDelayTicks);

    // Capture final task states and run times
    UBaseType_t uxFinalCount = uxTaskGetSystemState(pxTaskStatusArrayFinal, uxArraySize, NULL);

    // Calculate total run time difference
    configRUN_TIME_COUNTER_TYPE ulTotalRunTimeDiff = 0;
    for (UBaseType_t x = 0; x < uxFinalCount; x++) {
        for (UBaseType_t y = 0; y < uxInitialCount; y++) {
            if (pxTaskStatusArrayFinal[x].xHandle == pxTaskStatusArrayInitial[y].xHandle) {
                configRUN_TIME_COUNTER_TYPE ulRunTimeDiff = 
                    pxTaskStatusArrayFinal[x].ulRunTimeCounter - pxTaskStatusArrayInitial[y].ulRunTimeCounter;
                ulTotalRunTimeDiff += ulRunTimeDiff;
                break;
            }
        }
    }

    // Display CPU usage for each task
    ESP_LOGI(TAG, "Task CPU Usage Report:");
    ESP_LOGI(TAG, "--------------------");

    for (UBaseType_t x = 0; x < uxFinalCount; x++) {
        bool bTaskFound = false;
        for (UBaseType_t y = 0; y < uxInitialCount; y++) {
            if (pxTaskStatusArrayFinal[x].xHandle == pxTaskStatusArrayInitial[y].xHandle) {
                bTaskFound = true;
                configRUN_TIME_COUNTER_TYPE ulRunTimeDiff = 
                    pxTaskStatusArrayFinal[x].ulRunTimeCounter - pxTaskStatusArrayInitial[y].ulRunTimeCounter;

                // Calculate percentage
                uint32_t ulUsagePercent = 0;
                if (ulTotalRunTimeDiff > 0) {
                    ulUsagePercent = (ulRunTimeDiff * 100) / (ulTotalRunTimeDiff / 100);
                }

                ESP_LOGI(TAG, "Task: %-16s CPU: %3u.%02u%% Stack: %u",
                         pxTaskStatusArrayFinal[x].pcTaskName,
                         (unsigned int)(ulUsagePercent / 100),
                         (unsigned int)(ulUsagePercent % 100),
                         (unsigned int)pxTaskStatusArrayFinal[x].usStackHighWaterMark);
                break;
            }
        }

        // If task not found in initial array, it was created during measurement
        if (!bTaskFound) {
            ESP_LOGI(TAG, "Task: %-16s CPU: New Task      Stack: %u",
                     pxTaskStatusArrayFinal[x].pcTaskName,
                     (unsigned int)pxTaskStatusArrayFinal[x].usStackHighWaterMark);
        }
    }

    // Check for deleted tasks
    for (UBaseType_t y = 0; y < uxInitialCount; y++) {
        bool bTaskFound = false;
        for (UBaseType_t x = 0; x < uxFinalCount; x++) {
            if (pxTaskStatusArrayFinal[x].xHandle == pxTaskStatusArrayInitial[y].xHandle) {
                bTaskFound = true;
                break;
            }
        }

        // If task not found in final array, it was deleted during measurement
        if (!bTaskFound) {
            ESP_LOGI(TAG, "Task: %-16s CPU: Deleted Task",
                     pxTaskStatusArrayInitial[y].pcTaskName);
        }
    }

    // Clean up allocated memory
    free(pxTaskStatusArrayInitial);
    free(pxTaskStatusArrayFinal);
}

