bool AudioCodec::InputData(std::vector<int16_t>& buffer)
{
    if (buffer.empty()) {
        ESP_LOGW(TAG, "Input buffer is empty");
        return false;
    }

    size_t bytes_read = 0;
    esp_err_t result = Read(buffer.data(), buffer.size() * sizeof(int16_t), &bytes_read);

    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read audio data: %s", esp_err_to_name(result));
        return false;
    }

    // Convert bytes read back to sample count
    size_t samples_read = bytes_read / sizeof(int16_t);

    // Resize buffer to actual samples read
    if (samples_read != buffer.size()) {
        buffer.resize(samples_read);
    }

    // Return true if we successfully read some data
    return samples_read > 0;
}

esp_err_t AudioCodec::Start()
{
    esp_err_t ret = ESP_OK;

    // Initialize I2S configuration for both TX and RX
    i2s_chan_config_t chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_AUTO, I2S_ROLE_MASTER);
    chan_cfg.auto_clear = true;

    // Install I2S transmit channel
    ret = i2s_new_channel(&chan_cfg, &tx_handle_, nullptr);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create I2S TX channel: %s", esp_err_to_name(ret));
        return ret;
    }

    // Install I2S receive channel
    ret = i2s_new_channel(&chan_cfg, nullptr, &rx_handle_);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create I2S RX channel: %s", esp_err_to_name(ret));
        return ret;
    }

    // Configure I2S standard format
    i2s_std_config_t std_cfg = {
        .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(48000), // Default sample rate
        .slot_cfg = I2S_STD_PHILIP_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
        .gpio_cfg = {
            .mclk = I2S_GPIO_UNUSED,
            .bclk = (gpio_num_t)BOARD_I2S_BCK_PIN,
            .ws = (gpio_num_t)BOARD_I2S_WS_PIN,
            .dout = (gpio_num_t)BOARD_I2S_DOUT_PIN,
            .din = (gpio_num_t)BOARD_I2S_DIN_PIN,
            .invert_flags = {
                .mclk_inv = false,
                .bclk_inv = false,
                .ws_inv = false,
            },
        },
    };

    // Initialize I2S TX
    if (tx_handle_) {
        ret = i2s_channel_init_std_mode(tx_handle_, &std_cfg);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to initialize I2S TX: %s", esp_err_to_name(ret));
            return ret;
        }

        ret = i2s_channel_enable(tx_handle_);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to enable I2S TX: %s", esp_err_to_name(ret));
            return ret;
        }
    }

    // Initialize I2S RX
    if (rx_handle_) {
        ret = i2s_channel_init_std_mode(rx_handle_, &std_cfg);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to initialize I2S RX: %s", esp_err_to_name(ret));
            return ret;
        }

        ret = i2s_channel_enable(rx_handle_);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to enable I2S RX: %s", esp_err_to_name(ret));
            return ret;
        }
    }

    // Load volume settings from NVS or use defaults
    Settings& settings = Settings::GetInstance();
    int volume = settings.GetVolume();
    if (volume < 0 || volume > 100) {
        volume = DEFAULT_VOLUME; // Assuming DEFAULT_VOLUME is defined in settings.h
    }

    // Apply volume settings to codec
    ret = SetVolume(volume);
    if (ret != ESP_OK) {
        ESP_LOGW(TAG, "Failed to set initial volume, continuing anyway");
    }

    // Enable audio codec input/output paths
    ret = EnableCodec(true);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to enable audio codec: %s", esp_err_to_name(ret));
        return ret;
    }

    ESP_LOGI(TAG, "Audio codec started successfully with volume %d%%", volume);
    return ESP_OK;
}

