int ref_input_sample_rate, gpio_num_t pa_power_gpio, gpio_num_t reset_gpio, 
    gpio_num_t mute_gpio, gpio_num_t ref_input_gpio, gpio_num_t input_gpio, 
    gpio_num_t output_gpio, uint8_t i2c_address, bool enable_ref_input)
    : i2c_master_handle_(i2c_master_handle)
    , i2c_port_(i2c_port)
    , input_sample_rate_(input_sample_rate)
    , output_sample_rate_(output_sample_rate)
    , ref_input_sample_rate_(ref_input_sample_rate)
    , pa_power_gpio_(pa_power_gpio)
    , reset_gpio_(reset_gpio)
    , mute_gpio_(mute_gpio)
    , ref_input_gpio_(ref_input_gpio)
    , input_gpio_(input_gpio)
    , output_gpio_(output_gpio)
    , i2c_address_(i2c_address)
    , enable_ref_input_(enable_ref_input) {

    // Initialize GPIO pins
    gpio_config_t io_conf = {};
    io_conf.mode = GPIO_MODE_OUTPUT;
    io_conf.pin_bit_mask = (1ULL << pa_power_gpio_) | (1ULL << reset_gpio_) | (1ULL << mute_gpio_);
    io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
    io_conf.pull_up_en = GPIO_PULLUP_DISABLE;
    gpio_config(&io_conf);

    // Configure input GPIOs
    io_conf.mode = GPIO_MODE_INPUT;
    io_conf.pin_bit_mask = (1ULL << ref_input_gpio_) | (1ULL << input_gpio_) | (1ULL << output_gpio_);
    gpio_config(&io_conf);

    // Reset the codec
    gpio_set_level(reset_gpio_, 0);
    vTaskDelay(pdMS_TO_TICKS(10));
    gpio_set_level(reset_gpio_, 1);
    vTaskDelay(pdMS_TO_TICKS(10));

    // Power on sequence
    gpio_set_level(pa_power_gpio_, 1);  // Enable power amplifier

    // Initialize ES8388 codec
    es8388_init();

    // Configure sample rates
    es8388_set_sample_rate(ES_MODULE_ADC, input_sample_rate_);
    es8388_set_sample_rate(ES_MODULE_DAC, output_sample_rate_);

    // Configure for full-duplex operation
    es8388_config_adc_input(ES_ADC_INPUT_LINPUT2_RINPUT2);
    es8388_config_dac_output(ES_DAC_OUTPUT_LOUT1_ROUT1);

    // Set default volume levels
    es8388_set_voice_volume(50);  // 50% volume

    // Configure reference input for AEC if enabled
    if (enable_ref_input_) {
        // Enable reference input path
        es8388_write_reg(0x00, 0x01);  // Enable reference input
        es8388_set_sample_rate(ES_MODULE_REF, ref_input_sample_rate_);
    }

    ESP_LOGI(TAG, "ES8388 Audio Codec initialized - Input SR: %d, Output SR: %d", 
             input_sample_rate_, output_sample_rate_);
}

Es8388AudioCodec::~Es8388AudioCodec() {
    ESP_LOGD(TAG, "Destroying ES8388 Audio Codec");

    // Close input device if open
    if (input_device_handle_ != nullptr) {
