    input_sample_rate_ = 0;
    output_sample_rate_ = 0;

    ESP_LOGD(TAG, "ES8388 Audio Codec destroyed successfully");
}

bool Es8388AudioCodec::CreateDuplexChannels(gpio_num_t bck_pin, gpio_num_t ws_pin, gpio_num_t data_out_pin, gpio_num_t data_in_pin, gpio_num_t mck_pin) {
    // Configure I2S driver for duplex communication
    i2s_driver_config_t i2s_config = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX),
        .sample_rate = m_output_sample_rate,
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = I2S_COMM_FORMAT_I2S,
        .intr_alloc_flags = 0,
        .dma_buf_count = 8,
        .dma_buf_len = 64,
        .use_apll = true,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0,
        .mclk_multiple = I2S_MCLK_MULTIPLE_256,
        .bits_per_chan = I2S_BITS_PER_SAMPLE_16BIT,
    };

    // Install I2S driver
    esp_err_t err = i2s_driver_install(I2S_NUM_0, &i2s_config, 0, NULL);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to install I2S driver: %s", esp_err_to_name(err));
        return false;
    }

    // Configure I2S pins
    i2s_pin_config_t pin_config = {
        .mck_io_num = mck_pin,
        .bck_io_num = bck_pin,
        .ws_io_num = ws_pin,
        .data_out_num = data_out_pin,
        .data_in_num = data_in_pin
    };

    err = i2s_set_pin(I2S_NUM_0, &pin_config);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set I2S pins: %s", esp_err_to_name(err));
        i2s_driver_uninstall(I2S_NUM_0);
        return false;
    }

    // Set clock configuration
    err = i2s_set_clk(I2S_NUM_0, m_output_sample_rate, I2S_BITS_PER_SAMPLE_16BIT, I2S_CHANNEL_STEREO);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to configure I2S clock: %s", esp_err_to_name(err));
        i2s_driver_uninstall(I2S_NUM_0);
        return false;
    }

    // Zero-initialize the DMA buffers to avoid noise
    i2s_zero_dma_buffer(I2S_NUM_0);

    ESP_LOGI(TAG, "Successfully created duplex channels with sample rate: %d Hz", m_output_sample_rate);
    return true;
}

bool Es8388AudioCodec::SetOutputVolume(int volume) {
    // Validate volume range (assuming 0-100 scale)
    if (volume < 0) {
        volume = 0;
    } else if (volume > 100) {
        volume = 100;
    }

    // Store the volume in internal state
    output_volume_ = volume;

    // Convert volume percentage to ES8388 register value
    // ES8388 typically uses 0x00 (mute) to 0xFF (maximum volume) for DAC volume
    // Assuming linear mapping from 0-100 to 0xC0-0x00 (inverted scale)
    uint8_t dac_volume = 0xC0 - (volume * 0xC0 / 100);

    // Write to Left DAC Volume Control Register (0x25)
    if (!WriteRegister(0x25, dac_volume)) {
        ESP_LOGE(TAG, "Failed to set left DAC volume");
        return false;
    }

    // Write to Right DAC Volume Control Register (0x26)
    if (!WriteRegister(0x26, dac_volume)) {
        ESP_LOGE(TAG, "Failed to set right DAC volume");
        return false;
    }

    // Optionally unmute if volume is being set to non-zero
    if (volume > 0) {
        // Clear mute bits in DAC Control Register 1 (0x18)
        uint8_t dac_ctrl1;
        if (!ReadRegister(0x18, &dac_ctrl1)) {
            ESP_LOGE(TAG, "Failed to read DAC control register");
            return false;
        }

        dac_ctrl1 &= ~0x40; // Clear LMUTE bit (bit 6)
        if (!WriteRegister(0x18, dac_ctrl1)) {
            ESP_LOGE(TAG, "Failed to unmute left DAC");
            return false;
        }

        if (!ReadRegister(0x19, &dac_ctrl1)) {
            ESP_LOGE(TAG, "Failed to read DAC control register");
            return false;
        }

        dac_ctrl1 &= ~0x40; // Clear RMUTE bit (bit 6)
        if (!WriteRegister(0x19, dac_ctrl1)) {
            ESP_LOGE(TAG, "Failed to unmute right DAC");
            return false;
        }
    }

    ESP_LOGI(TAG, "Output volume set to %d%%", volume);
    return true;
}

esp_err_t Es8388AudioCodec::EnableInput(bool enable) {
    esp_err_t ret = ESP_OK;

    if (enable) {
        // Power up ADC and related analog circuits
        ret = WriteRegister(ES8388_ADCPOWER, 0x00); // Power up ADC
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to power up ADC");
            return ret;
        }

        // Configure ADC control register
        uint8_t adc_ctrl = 0x00;
        // Set bit depth (assuming 16-bit)
        adc_ctrl |= 0x00; // 16-bit format
        // Set data format (I2S standard)
        ret = WriteRegister(ES8388_ADCCONTROL1, adc_ctrl);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to configure ADC control 1");
            return ret;
        }

        // Set ADC volume (gain control)
        // Assuming default gain setting, can be adjusted based on requirements
        ret = WriteRegister(ES8388_ADCCONTROL2, 0x00); // LADC volume
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to set LADC volume");
            return ret;
        }

        ret = WriteRegister(ES8388_ADCCONTROL3, 0x00); // RADC volume
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to set RADC volume");
            return ret;
        }

        // Configure ADC MUX for microphone input
        ret = WriteRegister(ES8388_ADCCONTROL4, 0x0C); // LINSEL & RINSEL, LIN1/RIN1 connected to ADC
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to configure ADC MUX");
            return ret;
        }

        // Set clock and sampling rate
        ret = ConfigureClockAndSampleRate(input_sample_rate_, true);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to configure input clock and sample rate");
            return ret;
        }

        // Enable ADC digital filter
        ret = WriteRegister(ES8388_ADCPOWER, 0x00); // Ensure ADC is powered on
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to enable ADC digital filter");
            return ret;
        }

        ESP_LOGI(TAG, "Audio input enabled with sample rate: %d Hz", input_sample_rate_);
    } else {
        // Disable input by powering down ADC
        ret = WriteRegister(ES8388_ADCPOWER, 0xFF); // Power down ADC
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to power down ADC");
            return ret;
        }

        // Reset ADC configuration
        ret = WriteRegister(ES8388_ADCCONTROL1, 0x00);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to reset ADC control 1");
            return ret;
        }

        ESP_LOGI(TAG, "Audio input disabled");
    }

    input_enabled_ = enable;
    return ESP_OK;
}

bool Es8388AudioCodec::EnableOutput(bool enable) {
    if (enable) {
        // Configure codec for output
        // Set sample rate
        if (!SetSampleRate(output_sample_rate_)) {
            ESP_LOGE(TAG, "Failed to set output sample rate");
            return false;
        }

        // Set volume settings
        if (!SetVolume(volume_)) {
            ESP_LOGE(TAG, "Failed to set output volume");
            return false;
        }

        // Configure analog output levels
        // Power up DAC and output stages
        if (!WriteRegister(ES8388_DACPOWER, 0xC0)) {  // Power up DAC
            ESP_LOGE(TAG, "Failed to power up DAC");
            return false;
        }

        if (!WriteRegister(ES8388_CHIPPOWER, 0x00)) {  // Power up chip
            ESP_LOGE(TAG, "Failed to power up chip");
            return false;
        }

        if (!WriteRegister(ES8388_ANAVOLMANAG, 0x00)) {  // Analog volume management
            ESP_LOGE(TAG, "Failed to configure analog volume");
            return false;
        }

        // Activate power amplifier pin if present
        if (power_amp_pin_ >= 0) {
            gpio_set_level((gpio_num_t)power_amp_pin_, 1);
        }

        output_enabled_ = true;
        ESP_LOGI(TAG, "Audio output enabled");
    } else {
        // Disable output
        // Close codec output device
        if (!WriteRegister(ES8388_DACPOWER, 0x00)) {  // Power down DAC
            ESP_LOGE(TAG, "Failed to power down DAC");
            return false;
        }

        // Deactivate power amplifier pin if present
        if (power_amp_pin_ >= 0) {
            gpio_set_level((gpio_num_t)power_amp_pin_, 0);
        }

        output_enabled_ = false;
        ESP_LOGI(TAG, "Audio output disabled");
    }

    return true;
}

int Es8388AudioCodec::Read(int16_t *buffer, int num_samples) {
    // Check if input is enabled before reading
    if (!input_enabled_) {
        return 0;
    }

    // Use ESP-IDF codec device API to read audio data
    // The ES8388 typically works with 16-bit stereo PCM data
    // Each sample is 16 bits (2 bytes), so we need to convert count appropriately

    size_t bytes_to_read = num_samples * sizeof(int16_t);
    size_t bytes_read = 0;

    // Call the ESP-IDF I2S read function or codec-specific read function
    // Assuming there's a handle to the codec device
    esp_err_t result = codec_dev_read(&codec_dev_, (void*)buffer, bytes_to_read, &bytes_read, portMAX_DELAY);

    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read audio data from ES8388 codec: %s", esp_err_to_name(result));
        return 0;
    }

    // Convert bytes read back to number of samples
    int samples_read = bytes_read / sizeof(int16_t);

    // Return the number of samples read
    return samples_read;
}

int Es8388AudioCodec::Write(const int16_t* data, int sample_count) {
    // Check if data pointer is valid
    if (data == nullptr) {
        ESP_LOGE(TAG, "Invalid data pointer");
        return 0;
    }

    // Check if output is enabled
    if (!output_enabled_) {
        ESP_LOGE(TAG, "Output is not enabled");
        return 0;
    }

    // Check if device is valid
    if (!is_initialized_) {
        ESP_LOGE(TAG, "Device is not initialized");
        return 0;
    }

    // Convert sample count to byte size (int16_t = 2 bytes per sample)
    size_t byte_size = sample_count * sizeof(int16_t);

    // Write data to the output device
    // Assuming there's an I2S or similar interface for audio output
    esp_err_t result = i2s_write_bytes(i2s_port_, (const void*)data, byte_size, portMAX_DELAY);

    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to write audio data: %s", esp_err_to_name(result));
        return 0;
    }

    // Return the number of samples written
    return sample_count;
}

AudioDebugger::AudioDebugger()
{
#if CONFIG_USE_AUDIO_DEBUGGER
    m_socket = -1;
    m_enabled = false;

    // Get configuration values (assuming they exist in sdkconfig)
    const char* server_ip = CONFIG_AUDIO_DEBUGGER_SERVER_IP;
    int server_port = CONFIG_AUDIO_DEBUGGER_SERVER_PORT;

    if (!server_ip || server_port <= 0) {
        ESP_LOGE(TAG, "Invalid debugger configuration: IP=%s, Port=%d", 
                 server_ip ? server_ip : "NULL", server_port);
        return;
    }

    // Create UDP socket
    m_socket = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (m_socket < 0) {
        ESP_LOGE(TAG, "Failed to create UDP socket: %s", strerror(errno));
        return;
    }

    // Configure server address
    memset(&m_server_addr, 0, sizeof(m_server_addr));
    m_server_addr.sin_family = AF_INET;
    m_server_addr.sin_port = htons(server_port);

    // Convert IP address string to binary form
    if (inet_pton(AF_INET, server_ip, &m_server_addr.sin_addr) <= 0) {
        ESP_LOGE(TAG, "Invalid server IP address: %s", server_ip);
        close(m_socket);
        m_socket = -1;
        return;
    }

    m_enabled = true;
    ESP_LOGI(TAG, "Audio debugger initialized: %s:%d", server_ip, server_port);
#else
    m_socket = -1;
    m_enabled = false;
#endif
}

AudioDebugger::~AudioDebugger()
{
#if CONFIG_USE_AUDIO_DEBUGGER
    if (socket_fd >= 0) {
        close(socket_fd);
        socket_fd = -1;
        ESP_LOGI(TAG, "Audio debugger UDP socket closed");
    }
#endif
}

void AudioDebugger::Feed(const std::vector<int16_t>& samples)
{
    static int sockfd = -1;
    static struct sockaddr_in servaddr;
    static bool initialized = false;

    // Initialize UDP socket on first call
    if (!initialized) {
        sockfd = socket(AF_INET, SOCK_DGRAM, 0);
        if (sockfd < 0) {
            ESP_LOGE(TAG, "Failed to create socket: %s", strerror(errno));
            return;
        }

        memset(&servaddr, 0, sizeof(servaddr));
        servaddr.sin_family = AF_INET;
        servaddr.sin_port = htons(CONFIG_AUDIO_DEBUGGER_PORT);
        servaddr.sin_addr.s_addr = inet_addr(CONFIG_AUDIO_DEBUGGER_HOST);

        initialized = true;
    }

    if (samples.empty()) {
        return;
    }

    // Send audio data as raw bytes
    ssize_t sent_bytes = sendto(sockfd, samples.data(), 
                               samples.size() * sizeof(int16_t),
                               0, (const struct sockaddr*)&servaddr, 
                               sizeof(servaddr));

    if (sent_bytes < 0) {
        ESP_LOGW(TAG, "Failed to send audio data: %s", strerror(errno));
    } else if (sent_bytes != (ssize_t)(samples.size() * sizeof(int16_t))) {
        ESP_LOGW(TAG, "Incomplete send: %d/%d bytes sent", 
                 sent_bytes, samples.size() * sizeof(int16_t));
    } else {
        ESP_LOGD(TAG, "Sent %d audio samples (%d bytes)", 
                 samples.size(), sent_bytes);
    }
}

AfeWakeWord::AfeWakeWord() {
    // Initialize member variables
    this->codec = nullptr;
    this->models_list = nullptr;
    this->afe_handler = nullptr;
    this->event_group = nullptr;
    this->is_initialized = false;
    this->is_running = false;

    // Create event group for managing wake word detection events
    this->event_group = xEventGroupCreate();
    if (this->event_group == nullptr) {
        ESP_LOGE(TAG, "Failed to create event group");
    }

    ESP_LOGI(TAG, "AfeWakeWord constructor completed");
}

AfeWakeWord::~AfeWakeWord() {
    // Stop any ongoing wake word detection
    Stop();

    // Clean up event group
    if (event_group_) {
        vEventGroupDelete(event_group_);
        event_group_ = nullptr;
    }

    // Deinitialize AFE instance
    if (afe_handle_) {
        afe_destroy(afe_handle_);
        afe_handle_ = nullptr;
    }

    // Free wake word encoding task stack
    if (task_stack_) {
        free(task_stack_);
        task_stack_ = nullptr;
    }

    // Free wake word buffer
    if (ww_buffer_) {
        free(ww_buffer_);
        ww_buffer_ = nullptr;
    }

    // Clean up speech recognition models
    if (models_list_) {
        // Assuming there's a function to deinitialize model list
        // This might involve freeing individual models within the list
        srmodel_list_deinit(models_list_);
        models_list_ = nullptr;
    }

    // Additional cleanup for any other allocated resources
    if (audio_buffer_) {
        free(audio_buffer_);
        audio_buffer_ = nullptr;
    }

    ESP_LOGI(TAG, "AfeWakeWord resources cleaned up successfully");
}

bool AfeWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list) {
    ESP_LOGI(TAG, "Initializing AFE wake word detection");

    // Store codec reference
    this->codec_ = codec;

    // Check if models are provided
    if (!models_list || models_list->num_models == 0) {
        ESP_LOGE(TAG, "No wake word models provided");
        return false;
    }

    // Initialize AFE configuration
    afe_config_t afe_config = {
        .aec_en = true,
        .se_en = true,
        .vad_en = true,
        .wakenet_en = true,
        .voice_communication_en = false,
        .voice_communication_agc_en = false,
        .voice_communication_agc_gain = 0,
        .vad_mode = VAD_MODE_3,
        .wakenet_model_name = nullptr,
        .wakenet_mode = DET_MODE_3,
        .afe_mode = SRMODE_WAKEUP_VOICE_COMMAND,
        .afe_memory_alloc_mode = AFE_MEMORY_ALLOC_MORE_PSRAM,
        .afe_linear_gain = 1.0,
        .afe_snr = 20,
        .afe_channel_num = 1,
    };

    // Create AFE feed
    this->feed_ = afe_handle->create_from_config(&afe_config);
    if (!this->feed_) {
        ESP_LOGE(TAG, "Failed to create AFE feed");
        return false;
    }

    // Load wake word models
    this->multinet_ = multinet_init(models_list);
    if (!this->multinet_) {
        ESP_LOGE(TAG, "Failed to initialize multinet");
        afe_handle->destroy(this->feed_);
        return false;
    }

    // Set up detection running flag
    this->detection_running_ = true;

    // Create detection task
    BaseType_t result = xTaskCreate(
        AfeWakeWord::DetectionTask,
        "AfeWakeWordDetection",
        4096,
        this,
        5,
        &this->detection_task_handle_
    );

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create detection task");
        this->detection_running_ = false;
        multinet_deinit(this->multinet_);
        afe_handle->destroy(this->feed_);
        return false;
    }

    ESP_LOGI(TAG, "AFE wake word detection initialized successfully");
    return true;
}

void AfeWakeWord::Stop() {
    // Clear the detection running event flag
    detection_running_flag = 0;

    // Reset the audio front-end buffer if initialized
    if (afe_handle != nullptr) {
        // Reset AFE buffer and stop processing
        afe_reset_buffer(afe_handle);
        // Stop the AFE processing
        afe_stop_processing(afe_handle);
    }

    // Clear any pending audio data
    if (audio_buffer != nullptr) {
        memset(audio_buffer, 0, audio_buffer_size);
    }

    ESP_LOGI(TAG, "AFE wake word detection stopped");
}

void AfeWakeWord::Feed(const std::vector<int16_t>& samples) {
    if (samples.empty()) {
        return;
    }

    // Ensure AFE is properly initialized and running
    if (!afe_handler_ || !is_running_) {
        ESP_LOGW(TAG, "AFE not initialized or not running");
        return;
    }

    // Feed samples to AFE processing pipeline
    // Typical AFE interface expects raw PCM data
    int ret = afe_process(afe_handler_, samples.data(), samples.size());

    if (ret != 0) {
        ESP_LOGW(TAG, "AFE processing failed with error: %d", ret);
        return;
    }

    // Check for wake word detection result
    afe_result_t result;
    ret = afe_get_result(afe_handler_, &result);

    if (ret == 0 && result.wakeup_state == WAKENET_DETECTED) {
        // Wake word detected, notify audio service
        ESP_LOGI(TAG, "Wake word detected with confidence: %f", result.confidence);

        // Create wake word event and send to audio service
        WakeWordEvent event;
        event.word_id = result.word_id;
        event.confidence = result.confidence;
        event.timestamp = esp_timer_get_time();

        if (audio_service_) {
            audio_service_->OnWakeWordDetected(event);
        }
    } else if (ret != 0) {
        ESP_LOGW(TAG, "Failed to get AFE result: %d", ret);
    }
}

int AfeWakeWord::GetFeedSize()
{
    // Check if AFE data is initialized
    if (afe_data == nullptr) {
        return 0;
    }

    // Retrieve the feed size from the AFE interface
    // This is typically a fixed size required by the AFE processing engine
    // for optimal real-time voice activity detection
    return afe_get_feed_size(afe_data);
}

void AfeWakeWord::AudioDetectionTask() {
    ESP_LOGI(TAG, "Starting audio detection task");

    while (running_) {
        // Check if detection is enabled
        if (!detection_enabled_) {
            vTaskDelay(pdMS_TO_TICKS(10));
            continue;
        }

        // Feed audio data to the acoustic front-end for processing
        int keyword_id = afe_handle_->feed_afe(AFE_FETCH_MODE_VOICE_DATA);

        // Check if a wake word was detected
        if (keyword_id > 0) {
            ESP_LOGI(TAG, "Wake word detected with ID: %d", keyword_id);

            // Stop the detection process temporarily
            detection_enabled_ = false;

            // Get the detected keyword name from the model list
            const char* keyword_name = nullptr;
            if (models_list_ && keyword_id <= models_list_->num) {
                keyword_name = models_list_->model_list[keyword_id - 1];
            }

            // Store relevant audio data if needed
            // This would typically involve buffering or saving the audio clip

            // Trigger callback with the identified wake word
            if (callback_ && keyword_name) {
                std::string wake_word(keyword_name);
                callback_(wake_word);
            }

            // Small delay to prevent immediate re-triggering
            vTaskDelay(pdMS_TO_TICKS(1000));

            // Re-enable detection
            detection_enabled_ = true;
        }
        else if (keyword_id == 0) {
            // No keyword detected, continue monitoring
            vTaskDelay(pdMS_TO_TICKS(10));
        }
        else {
            // Error condition
            ESP_LOGW(TAG, "Error in AFE processing: %d", keyword_id);
            vTaskDelay(pdMS_TO_TICKS(100));
        }
    }

    ESP_LOGI(TAG, "Audio detection task stopped");
}

void AfeWakeWord::StoreWakeWordData(const int16_t* data, size_t len) {
    if (!data || len == 0) {
        return;
    }

    // Add new audio data to the buffer
    for (size_t i = 0; i < len; ++i) {
        // Add new sample to the end of buffer
        wake_word_data_buffer_.push_back(data[i]);
    }

    // Maintain approximately 2 seconds of audio data
    // Remove old data if buffer exceeds the limit
    while (wake_word_data_buffer_.size() > wake_word_buffer_max_size_) {
        wake_word_data_buffer_.pop_front();
    }
}

void AfeWakeWord::EncodeWakeWordData(const int16_t* pcm_data, size_t pcm_length) {
    // Static variables for task and buffer management
    static TaskHandle_t encode_task_handle = nullptr;
    static uint8_t* opus_buffer = nullptr;
    static size_t opus_buffer_size = 0;
    static OpusEncoder* opus_encoder = nullptr;
    static SemaphoreHandle_t buffer_mutex = nullptr;
    static StaticSemaphore_t buffer_mutex_buffer;
    static SemaphoreHandle_t completion_semaphore = nullptr;
    static StaticSemaphore_t completion_semaphore_buffer;

    // Initialize synchronization primitives if not already done
    if (buffer_mutex == nullptr) {
        buffer_mutex = xSemaphoreCreateMutexStatic(&buffer_mutex_buffer);
    }

    if (completion_semaphore == nullptr) {
        completion_semaphore = xSemaphoreCreateBinaryStatic(&completion_semaphore_buffer);
    }

    // Structure to pass data to encoding task
    struct EncodeTaskData {
        const int16_t* pcm_data;
        size_t pcm_length;
        int16_t* task_stack;
        size_t stack_size;
    };

    // Encoding task function
    auto encode_task = [](void* pvParameters) -> void {
        EncodeTaskData* task_data = static_cast<EncodeTaskData*>(pvParameters);

        // Initialize Opus encoder if not already done
        static OpusEncoder* local_opus_encoder = nullptr;
        if (local_opus_encoder == nullptr) {
            int opus_error;
            local_opus_encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, &opus_error);
            if (opus_error != OPUS_OK || local_opus_encoder == nullptr) {
                ESP_LOGE(TAG, "Failed to create Opus encoder: %s", opus_strerror(opus_error));
                vTaskDelete(nullptr);
                return;
            }

            // Configure for low complexity and real-time encoding
            opus_encoder_ctl(local_opus_encoder, OPUS_SET_COMPLEXITY(1));
            opus_encoder_ctl(local_opus_encoder, OPUS_SET_SIGNAL(OPUS_SIGNAL_VOICE));
            opus_encoder_ctl(local_opus_encoder, OPUS_SET_BITRATE(24000));
        }

        // Allocate buffer for encoded data
        const size_t max_packet_size = 4000;
        static uint8_t* encoded_buffer = nullptr;
        if (encoded_buffer == nullptr) {
            // Try SPIRAM first, fall back to internal memory
            if (heap_caps_get_free_size(MALLOC_CAP_SPIRAM) > max_packet_size) {
                encoded_buffer = static_cast<uint8_t*>(heap_caps_malloc(max_packet_size, MALLOC_CAP_SPIRAM));
            } else {
                encoded_buffer = static_cast<uint8_t*>(malloc(max_packet_size));
            }

            if (encoded_buffer == nullptr) {
                ESP_LOGE(TAG, "Failed to allocate encoded buffer");
                vTaskDelete(nullptr);
                return;
            }
        }

        // Process PCM data in chunks (assuming 20ms frames at 16kHz = 320 samples)
        const size_t frame_size = 320; // 20ms at 16kHz
        size_t samples_processed = 0;

        while (samples_processed < task_data->pcm_length) {
            size_t current_frame_size = std::min(frame_size, task_data->pcm_length - samples_processed);

            // Encode the frame
            int encoded_bytes = opus_encode(local_opus_encoder, 
                                          &task_data->pcm_data[samples_processed],
                                          current_frame_size,
                                          encoded_buffer,
                                          max_packet_size);

            if (encoded_bytes < 0) {
                ESP_LOGE(TAG, "Opus encoding failed: %s", opus_strerror(encoded_bytes));
                break;
            }

            // Store encoded packet in thread-safe buffer
            if (xSemaphoreTake(buffer_mutex, pdMS_TO_TICKS(100)) == pdTRUE) {
                // In a real implementation, this would push to a proper buffer/queue
                // For now, we'll just simulate storing the data
                ESP_LOGD(TAG, "Encoded %d bytes of Opus data", encoded_bytes);

                // Signal that data is available (in real implementation, notify consumers)
                xSemaphoreGive(buffer_mutex);
            }

            samples_processed += current_frame_size;
        }

        // Signal completion
        xSemaphoreGive(completion_semaphore);

        // Clean up task resources
        if (task_data->task_stack) {
            free(task_data->task_stack);
        }
        delete task_data;

        vTaskDelete(nullptr);
    };

    // Create task data
    EncodeTaskData* task_data = new EncodeTaskData();
    task_data->pcm_data = pcm_data;
    task_data->pcm_length = pcm_length;

    // Allocate stack for the task (prefer SPIRAM if available)
    const size_t stack_size = 4096;
    uint8_t* task_stack = nullptr;

    if (heap_caps_get_free_size(MALLOC_CAP_SPIRAM) > stack_size) {
        task_stack = static_cast<uint8_t*>(heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM));
    } else {
        task_stack = static_cast<uint8_t*>(malloc(stack_size));
    }

    task_data->task_stack = task_stack;
    task_data->stack_size = stack_size;

    if (task_stack == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate task stack");
        delete task_data;
        return;
    }

    // Create the encoding task with dedicated stack
    BaseType_t result = xTaskCreate(encode_task,
                                   "OpusEncode",
                                   stack_size / sizeof(StackType_t),
                                   task_data,
                                   configMAX_PRIORITIES - 2, // High priority for real-time processing
                                   &encode_task_handle);

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create encoding task");
        if (task_stack) {
            free(task_stack);
        }
        delete task_data;
        return;
    }

    // Wait for completion with timeout
    const TickType_t timeout = pdMS_TO_TICKS(5000); // 5 second timeout
    if (xSemaphoreTake(completion_semaphore, timeout) != pdTRUE) {
        ESP_LOGW(TAG, "Encoding task timed out");
        if (encode_task_handle != nullptr) {
            vTaskDelete(encode_task_handle);
            encode_task_handle = nullptr;
        }
    }
}

bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opus_data) {
    std::unique_lock<std::mutex> lock(queue_mutex_);

    // Wait until there's data available in the queue
    wake_word_queue_cv_.wait(lock, [this] { return !wake_word_opus_queue_.empty(); });

    // Check again if queue has data (in case of spurious wakeup)
    if (!wake_word_opus_queue_.empty()) {
        // Retrieve the front element
        opus_data = std::move(wake_word_opus_queue_.front());
        wake_word_opus_queue_.pop();
        return true;
    }

    return false;
}

