bool CustomWakeWord::ParseWakenetModelConfig()
{
    // Load the index.json file from assets
    std::string json_content;
    if (!Assets::GetInstance().LoadFile("index.json", json_content)) {
        ESP_LOGE(TAG, "Failed to load index.json");
        return false;
    }

    // Parse JSON content
    cJSON* root = cJSON_Parse(json_content.c_str());
    if (!root) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return false;
    }

    // Extract language
    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (language_item && cJSON_IsString(language_item)) {
        language_ = std::string(language_item->valuestring);
        ESP_LOGI(TAG, "Language: %s", language_.c_str());
    }

    // Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
        ESP_LOGI(TAG, "Duration: %d", duration_);
    }

    // Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item && cJSON_IsNumber(threshold_item)) {
        threshold_ = static_cast<float>(threshold_item->valuedouble);
        ESP_LOGI(TAG, "Threshold: %.2f", threshold_);
    }

    // Extract commands array
    cJSON* commands_array = cJSON_GetObjectItem(root, "commands");
    if (commands_array && cJSON_IsArray(commands_array)) {
        int commands_count = cJSON_GetArraySize(commands_array);
        ESP_LOGI(TAG, "Found %d commands", commands_count);

        commands_.clear();

        for (int i = 0; i < commands_count; i++) {
            cJSON* command_item = cJSON_GetArrayItem(commands_array, i);
            if (command_item && cJSON_IsObject(command_item)) {
                cJSON* id_item = cJSON_GetObjectItem(command_item, "id");
                cJSON* name_item = cJSON_GetObjectItem(command_item, "name");
                cJSON* phrase_item = cJSON_GetObjectItem(command_item, "phrase");

                if (id_item && cJSON_IsNumber(id_item) && 
                    name_item && cJSON_IsString(name_item)) {

                    WakeWordCommand command;
                    command.id = id_item->valueint;
                    command.name = std::string(name_item->valuestring);

                    if (phrase_item && cJSON_IsString(phrase_item)) {
                        command.phrase = std::string(phrase_item->valuestring);
                    }

                    commands_.push_back(command);

                    ESP_LOGI(TAG, "Command[%d]: ID=%d, Name=%s, Phrase=%s", 
                             i, command.id, command.name.c_str(), 
                             command.phrase.c_str());
                }
            }
        }
    }

    // Extract model file path
    cJSON* model_file_item = cJSON_GetObjectItem(root, "model_file");
    if (model_file_item && cJSON_IsString(model_file_item)) {
        model_file_path_ = std::string(model_file_item->valuestring);
        ESP_LOGI(TAG, "Model file: %s", model_file_path_.c_str());
    }

    // Clean up JSON parser
    cJSON_Delete(root);

    ESP_LOGI(TAG, "Successfully parsed wakenet model configuration");
    return true;
}

bool CustomWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* model_list)
{
    ESP_LOGI(TAG, "Initializing custom wake word detection");

    // Store codec reference
    audio_codec_ = codec;

    // Check if model list is valid
    if (!model_list || model_list->num_models == 0) {
        ESP_LOGE(TAG, "Invalid model list provided");
        return false;
    }

    // Select appropriate model based on language preference
    const esp_mn_iface_t* model_iface = nullptr;
    char* chosen_model = nullptr;

    // Try to find a suitable model from the list
    for (int i = 0; i < model_list->num_models; i++) {
        const char* model_name = model_list->models[i];
        if (model_name) {
            // Get model interface
            model_iface = esp_mn_handle_from_name(model_name);
            if (model_iface) {
                chosen_model = (char*)model_name;
                break;
            }
        }
    }

    if (!model_iface || !chosen_model) {
        ESP_LOGE(TAG, "Failed to load wake word model");
        return false;
    }

    ESP_LOGI(TAG, "Using wake word model: %s", chosen_model);

    // Initialize the model
    model_data_ = model_iface->create(chosen_model);
    if (!model_data_) {
        ESP_LOGE(TAG, "Failed to create model data");
        return false;
    }

    model_iface_ = model_iface;

    // Get model info
    esp_mn_model_info_t* model_info = model_iface->get_model_info();
    if (model_info) {
        ESP_LOGI(TAG, "Model wake word: %s", model_info->wake_word_name);
        sample_rate_ = model_info->sample_rate;
        chunk_size_ = model_info->chunk_size;
        sensitivity_ = DEFAULT_WAKE_WORD_SENSITIVITY;
    }

    // Initialize PCM buffer for wake word detection
    wake_word_pcm_.resize(chunk_size_);

    // Register custom voice commands if any
    if (!RegisterCustomCommands()) {
        ESP_LOGW(TAG, "Failed to register custom voice commands");
        // Continue initialization even if custom commands fail
    }

    // Configure audio codec
    if (audio_codec_) {
        AudioCodec::Config config = {};
        config.sample_rate = sample_rate_;
        config.bits_per_sample = 16;
        config.channels = 1;

        if (!audio_codec_->Configure(config)) {
            ESP_LOGE(TAG, "Failed to configure audio codec");
            return false;
        }

        ESP_LOGI(TAG, "Audio codec configured successfully");
    }

    // Set default threshold/sensitivity
    SetSensitivity(sensitivity_);

    initialized_ = true;
    ESP_LOGI(TAG, "Custom wake word initialization completed successfully");
    return true;
}

void CustomWakeWord::Feed(const std::vector<int16_t>& audio_data)
{
    if (audio_data.empty()) {
        return;
    }

    // Get system info to check if wake word detection is enabled
    auto& system_info = SystemInfo::GetInstance();
    if (!system_info.IsWakeWordEnabled()) {
        return;
    }

    // Get the multinet model interface
    const esp_mn_iface_t* iface = esp_mn_models_get_multinet_model();
    if (!iface) {
        ESP_LOGE(TAG, "Failed to get multinet model");
        return;
    }

    // Handle stereo to mono conversion if needed
    std::vector<int16_t> mono_audio;
    const int16_t* audio_ptr;
    size_t audio_len;

    // Assuming stereo input (2 channels), extract left channel
    if (audio_data.size() % 2 == 0) {
        mono_audio.reserve(audio_data.size() / 2);
        for (size_t i = 0; i < audio_data.size(); i += 2) {
            mono_audio.push_back(audio_data[i]); // Left channel only
        }
        audio_ptr = mono_audio.data();
        audio_len = mono_audio.size();
    } else {
        // Already mono
        audio_ptr = audio_data.data();
        audio_len = audio_data.size();
    }

    // Append audio data to internal buffer
    wake_word_pcm_.insert(wake_word_pcm_.end(), audio_ptr, audio_ptr + audio_len);

    // Process audio chunks (typically 160 samples at 16kHz = 10ms frames)
    const size_t chunk_size = 160;
    while (wake_word_pcm_.size() >= chunk_size) {
        // Get a chunk of audio data
        std::vector<int16_t> chunk(wake_word_pcm_.begin(), wake_word_pcm_.begin() + chunk_size);

        // Run wake word detection
        esp_mn_state_t* mn_state = nullptr; // This would typically be initialized elsewhere
        // For demonstration, assuming we have access to the model state

        // In a real implementation, you'd call something like:
        // int command_id = esp_mn_iface_detect(iface, mn_state, chunk.data());

        // Placeholder for actual detection logic
        int command_id = -1; // -1 means no detection

        if (command_id >= 0) {
            // Wake word detected
            const char* wake_word = esp_mn_speech_commands_get_string(command_id);

            if (wake_word) {
                ESP_LOGI(TAG, "Wake word detected: %s", wake_word);

                // Trigger callback
                auto& audio_service = AudioService::GetInstance();
                audio_service.OnWakeWordDetected(wake_word);

                // Clear buffer to prevent multiple detections
                wake_word_pcm_.clear();

                // Stop processing until reactivated
                break;
            }
        }

        // Remove processed chunk from buffer
        wake_word_pcm_.erase(wake_word_pcm_.begin(), wake_word_pcm_.begin() + chunk_size);
    }

    // Limit buffer size to prevent memory issues
    if (wake_word_pcm_.size() > 16000) { // Roughly 1 second at 16kHz
        wake_word_pcm_.erase(wake_word_pcm_.begin(), wake_word_pcm_.end() - 16000);
    }
}

int CustomWakeWord::GetFeedSize()
{
    // Check if the wake word model is initialized
    if (!AudioService::GetInstance().IsWakeWordModelInitialized()) {
        ESP_LOGW(TAG, "Wake word model not initialized, returning feed size 0");
        return 0;
    }

    // Get the model interface
    const esp_mn_iface_t* iface = AudioService::GetInstance().GetWakeWordModelInterface();
    if (iface == nullptr) {
        ESP_LOGW(TAG, "Wake word model interface is null, returning feed size 0");
        return 0;
    }

    // Get the required feed size from the model interface
    int feed_size = esp_mn_get_feed_size(iface);

    if (feed_size <= 0) {
        ESP_LOGW(TAG, "Invalid feed size returned from model: %d", feed_size);
        return 0;
    }

    ESP_LOGD(TAG, "Wake word model feed size: %d samples", feed_size);
    return feed_size;
}

void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t>& audio_data)
{
    if (audio_data.empty()) {
        return;
    }

    // Assuming 16kHz sample rate, 2 seconds = 32000 samples
    // For stereo data, this might need adjustment
    const size_t MAX_SAMPLES = 32000; // 2 seconds at 16kHz mono

    // Add new audio data to the buffer
    wake_word_pcm_.insert(wake_word_pcm_.end(), audio_data.begin(), audio_data.end());

    // If buffer exceeds the maximum size (2 seconds), remove oldest samples
    if (wake_word_pcm_.size() > MAX_SAMPLES) {
        // Calculate how many samples to remove
        size_t samples_to_remove = wake_word_pcm_.size() - MAX_SAMPLES;

        // Remove oldest samples from the beginning
        wake_word_pcm_.erase(wake_word_pcm_.begin(), wake_word_pcm_.begin() + samples_to_remove);
    }

    // Optional: Log buffer status for debugging
    // ESP_LOGD(TAG, "Audio buffer size: %d samples", wake_word_pcm_.size());
}

void CustomWakeWord::EncodeWakeWordData()
{
    // Create a background task for encoding
    auto encode_task = [](void* arg) {
        CustomWakeWord* instance = static_cast<CustomWakeWord*>(arg);

        // Initialize Opus encoder with low complexity settings
        OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
        if (!encoder) {
            ESP_LOGE(TAG, "Failed to create Opus encoder");
            vTaskDelete(nullptr);
            return;
        }

        // Set low complexity encoding
        opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));
        opus_encoder_ctl(encoder, OPUS_SET_BITRATE(16000));

        // Allocate buffer for encoded data
        const size_t pcm_frame_size = 160; // 10ms at 16kHz
        const size_t opus_buffer_size = 4000;
        int16_t* pcm_buffer = (int16_t*)malloc(pcm_frame_size * sizeof(int16_t));
        unsigned char* opus_buffer = (unsigned char*)malloc(opus_buffer_size);

        if (!pcm_buffer || !opus_buffer) {
            ESP_LOGE(TAG, "Failed to allocate encoding buffers");
            free(pcm_buffer);
            free(opus_buffer);
            opus_encoder_destroy(encoder);
            vTaskDelete(nullptr);
            return;
        }

        // Process each PCM segment
        size_t pcm_index = 0;
        instance->wake_word_opus_.clear();

        while (pcm_index + pcm_frame_size <= instance->wake_word_pcm_.size()) {
            // Copy PCM frame
            memcpy(pcm_buffer, &instance->wake_word_pcm_[pcm_index], pcm_frame_size * sizeof(int16_t));

            // Encode to Opus
            int encoded_bytes = opus_encode(encoder, pcm_buffer, pcm_frame_size, opus_buffer, opus_buffer_size);

            if (encoded_bytes > 0) {
                // Append encoded data to opus container
                instance->wake_word_opus_.insert(
                    instance->wake_word_opus_.end(),
                    opus_buffer,
                    opus_buffer + encoded_bytes
                );
            } else {
                ESP_LOGW(TAG, "Opus encoding failed with error: %d", encoded_bytes);
            }

            pcm_index += pcm_frame_size;
        }

        // Append termination marker (OPUS frame of silence or specific marker)
        unsigned char termination_marker[] = {0xF0, 0x0F}; // Example termination marker
        instance->wake_word_opus_.insert(
            instance->wake_word_opus_.end(),
            termination_marker,
            termination_marker + sizeof(termination_marker)
        );

        // Signal availability of encoded data
        instance->OnEncodedDataAvailable();

        // Cleanup
        free(pcm_buffer);
        free(opus_buffer);
        opus_encoder_destroy(encoder);

        ESP_LOGI(TAG, "Wake word encoding completed, %d bytes encoded", instance->wake_word_opus_.size());
        vTaskDelete(nullptr);
    };

    // Allocate task stack
    const size_t stack_size = 4096;
    void* task_stack = malloc(stack_size);

    if (!task_stack) {
        ESP_LOGE(TAG, "Failed to allocate stack for encoding task");
        return;
    }

    // Create background task
    TaskHandle_t task_handle;
    BaseType_t result = xTaskCreate(
        reinterpret_cast<TaskFunction_t>(encode_task),
        "WakeWordEncode",
        stack_size / sizeof(StackType_t),
        this,
        tskIDLE_PRIORITY + 1,
        &task_handle
    );

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create encoding task");
        free(task_stack);
        return;
    }

    ESP_LOGI(TAG, "Started wake word encoding task");
}

