bool CustomWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opus_data)
{
    std::unique_lock<std::mutex> lock(queue_mutex_);

    // Wait until wake word opus data is available
    wake_word_available_cv_.wait(lock, [this]() {
        return !wake_word_opus_.empty();
    });

    // Swap the data to minimize copies
    opus_data.swap(wake_word_opus_);

    // Clear the internal buffer after swap
    wake_word_opus_.clear();

    // Return success based on whether the retrieved data is non-empty
    return !opus_data.empty();
}

XL9555::XL9555(i2c_master_bus_handle_t bus_handle, uint8_t address)
    : I2cDevice(bus_handle, address)
{
    // Configure XL9555 I/O expander
    // Register 0x06: Port 0 configuration (0 = output, 1 = input)
    // Register 0x07: Port 1 configuration (0 = output, 1 = input)

    // Typical configuration: set some pins as outputs, others as inputs
    // For example: Port 0 mostly outputs, Port 1 mixed or mostly inputs
    uint8_t config_port0 = 0x00; // All pins of port 0 as outputs (typical usage)
    uint8_t config_port1 = 0xFF; // All pins of port 1 as inputs (typical usage)

    // Write configuration to register 0x06 (Port 0 direction)
    write_register(0x06, config_port0);

    // Write configuration to register 0x07 (Port 1 direction)
    write_register(0x07, config_port1);
}

void SetOutputState(uint8_t pin, uint8_t level)
{
    // Determine which register to use based on pin number (0-15)
    uint8_t reg_addr = (pin < 8) ? 0x02 : 0x03; // Output Port 0 or 1
    uint8_t bit_pos = pin % 8; // Bit position within the register

    // Read current register value
    uint8_t current_value;
    if (ReadRegister(reg_addr, &current_value, 1) != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read XL9555 output register 0x%02X", reg_addr);
        return;
    }

    // Modify the specific bit based on the desired level
    if (level) {
        // Set the bit (output high)
        current_value |= (1 << bit_pos);
    } else {
        // Clear the bit (output low)
        current_value &= ~(1 << bit_pos);
    }

    // Write the updated value back to the register
    if (WriteRegister(reg_addr, &current_value, 1) != ESP_OK) {
        ESP_LOGE(TAG, "Failed to write XL9555 output register 0x%02X", reg_addr);
        return;
    }
}

void InitializeI2c()
{
    // Configure I2C master interface
    i2c_master_bus_config_t i2c_bus_config = {};
    i2c_bus_config.clk_source = I2C_CLK_SRC_DEFAULT;
    i2c_bus_config.glitch_ignore_cnt = 7;
    i2c_bus_config.i2c_port = I2C_NUM_0;
    i2c_bus_config.scl_io_num = GPIO_NUM_18;  // Typical SCL pin for ESP32-S3
    i2c_bus_config.sda_io_num = GPIO_NUM_17;  // Typical SDA pin for ESP32-S3
    i2c_bus_config.flags.enable_internal_pullup = true;  // Enable internal pull-ups

    // Initialize I2C bus
    ESP_ERROR_CHECK(i2c_new_master_bus(&i2c_bus_config, &this->bus_handle_));

