void InitializeButtons()
{
    // Get reference to the application instance
    auto& app = Application::GetInstance();

    // Initialize the boot button (typically GPIO0 on ESP32 boards)
    Button* bootButton = new Button(GPIO_NUM_0, true); // Assuming active low button

    // Configure button with debounce
    bootButton->SetDebounceTime(50); // 50ms debounce

    // Set up button callback for click event
    bootButton->OnClick([this, &app]() {
        // Check if we're in startup/configuration mode
        if (app.GetState() == Application::State::STARTUP || 
            app.GetState() == Application::State::WIFI_CONFIG) {
            // During startup, enter Wi-Fi configuration mode
            ESP_LOGI(TAG, "Boot button pressed during startup - entering Wi-Fi config mode");
            app.SetState(Application::State::WIFI_CONFIG);
        } else {
            // In normal operation, toggle chat state
            ESP_LOGI(TAG, "Boot button pressed - toggling chat state");
            app.ToggleChatState();
        }
    });

    // Optional: Set up long press for additional functionality
    bootButton->OnLongPress([this, &app]() {
        ESP_LOGI(TAG, "Boot button long press detected");
        // Could be used for factory reset or other special functions
        if (app.GetState() != Application::State::WIFI_CONFIG) {
            // Reset to Wi-Fi config mode on long press in normal operation
            app.SetState(Application::State::WIFI_CONFIG);
        }
    }, 3000); // 3 second long press

    // Store button reference if needed for later use
    // buttons_.push_back(bootButton); // Assuming there's a container for buttons

    ESP_LOGI(TAG, "Buttons initialized successfully");
}

