    // Assuming XL9555 pins are configured for camera control
    // Pin assignments may vary based on actual hardware design

    // Power down the camera first
    // Assuming bit 0 controls camera power, bit 1 controls reset
    writeRegister(0x02, 0x01); // Set power control pin as output
    writeRegister(0x03, 0x02); // Set reset control pin as output
    writeRegister(0x01, 0x00); // Power off camera initially
    vTaskDelay(pdMS_TO_TICKS(10));

    // Power up sequence
    writeRegister(0x01, 0x01); // Enable camera power
    vTaskDelay(pdMS_TO_TICKS(10));

    // Reset sequence
    writeRegister(0x01, 0x03); // Assert reset
    vTaskDelay(pdMS_TO_TICKS(10));
    writeRegister(0x01, 0x01); // Deassert reset
