void ReceiveWifiCredentialsFromAudio(Application *app,
                                   WifiManager *wifi_manager,
                                   Display *display,
                                   size_t sample_rate)
{
    // Constants for AFSK demodulation
    const int kMarkFrequency = 1200;   // Mark frequency in Hz
    const int kSpaceFrequency = 2200;  // Space frequency in Hz
    const int kBaudRate = 1200;        // Baud rate
    const int kSamplesPerSymbol = sample_rate / kBaudRate;

    // Buffer for audio samples
    const size_t kBufferSize = 1024;
    int16_t audio_buffer[kBufferSize];
    int16_t mono_buffer[kBufferSize];

    // Local states
    float phase_mark = 0.0f;
    float phase_space = 0.0f;
    float delta_phase_mark = 2.0f * M_PI * kMarkFrequency / sample_rate;
    float delta_phase_space = 2.0f * M_PI * kSpaceFrequency / sample_rate;

    // Demodulation variables
    int bit_count = 0;
    int byte_value = 0;
    std::vector<uint8_t> received_data;
    bool sync_detected = false;

    ESP_LOGI(kLogTag, "Starting audio WiFi credential reception");
    display->ShowMessage("Listening for WiFi config...");

    while (app->IsInConfigMode()) {
        // Read audio samples (assuming stereo input)
        size_t samples_read = app->ReadAudioSamples(audio_buffer, kBufferSize);

        if (samples_read == 0) {
            continue;
        }

        // Convert stereo to mono if needed
        size_t mono_samples = samples_read;
        if (app->IsStereoInput()) {
            mono_samples = samples_read / 2;
            for (size_t i = 0; i < mono_samples; i++) {
                mono_buffer[i] = (audio_buffer[2*i] + audio_buffer[2*i + 1]) / 2;
            }
        } else {
            memcpy(mono_buffer, audio_buffer, samples_read * sizeof(int16_t));
        }

        // Process samples for AFSK demodulation
        for (size_t i = 0; i < mono_samples; i++) {
            // Generate local oscillator signals
            float cos_mark = cosf(phase_mark);
            float sin_mark = sinf(phase_mark);
            float cos_space = cosf(phase_space);
            float sin_space = sinf(phase_space);

            // Update phases
            phase_mark += delta_phase_mark;
            phase_space += delta_phase_space;
            if (phase_mark >= 2.0f * M_PI) phase_mark -= 2.0f * M_PI;
            if (phase_space >= 2.0f * M_PI) phase_space -= 2.0f * M_PI;

            // Mix with incoming signal
            float sample = static_cast<float>(mono_buffer[i]) / 32768.0f;
            float mark_i = sample * cos_mark;
            float mark_q = sample * sin_mark;
            float space_i = sample * cos_space;
            float space_q = sample * sin_space;

            // Low-pass filter (simple integration over symbol period)
            static float mark_energy = 0.0f;
            static float space_energy = 0.0f;
            static int sample_count = 0;

            mark_energy += mark_i * mark_i + mark_q * mark_q;
            space_energy += space_i * space_i + space_q * space_q;
            sample_count++;

            // When we have enough samples for one symbol
            if (sample_count >= kSamplesPerSymbol) {
                // Determine bit value based on energy comparison
                bool bit_value = (space_energy > mark_energy);

                // Simple NRZ decoding
                if (!sync_detected) {
                    // Look for synchronization pattern (e.g., 0x55 0x55 preamble)
                    // This is a simplified approach - real implementation would be more robust
                    if (bit_count < 8) {
                        byte_value = (byte_value >> 1) | (bit_value ? 0x80 : 0x00);
                        bit_count++;
                    } else {
                        // Check for sync pattern
                        if (byte_value == 0x55) {
                            sync_detected = true;
                            bit_count = 0;
                            byte_value = 0;
                            ESP_LOGI(kLogTag, "Sync detected");
                        } else {
                            // Shift and continue looking
                            byte_value = (byte_value >> 1) | (bit_value ? 0x80 : 0x00);
                        }
                    }
                } else {
                    // Collect data bits
                    byte_value |= (bit_value << bit_count);
                    bit_count++;

                    if (bit_count >= 8) {
                        received_data.push_back(static_cast<uint8_t>(byte_value));
                        bit_count = 0;
                        byte_value = 0;

                        // Check if we have enough data (simplified)
                        if (received_data.size() >= 10) { // Arbitrary threshold
                            // Attempt to parse credentials
                            std::string ssid;
                            std::string password;

                            // Simple parsing - real implementation would include proper framing
                            size_t pos = 0;
                            if (pos < received_data.size()) {
                                uint8_t ssid_len = received_data[pos++];
                                if (pos + ssid_len <= received_data.size()) {
                                    ssid.assign(reinterpret_cast<char*>(received_data.data() + pos), ssid_len);
                                    pos += ssid_len;

                                    if (pos < received_data.size()) {
                                        uint8_t pwd_len = received_data[pos++];
                                        if (pos + pwd_len <= received_data.size()) {
                                            password.assign(reinterpret_cast<char*>(received_data.data() + pos), pwd_len);

                                            // Valid credentials extracted
                                            ESP_LOGI(kLogTag, "WiFi credentials received - SSID: %s", ssid.c_str());
                                            display->ShowMessage("Connecting to WiFi...");

                                            // Connect to WiFi
                                            wifi_manager->ConnectToNetwork(ssid, password);

                                            // Clear sensitive data
                                            std::fill(received_data.begin(), received_data.end(), 0);

                                            return; // Exit after successful connection
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                // Reset for next symbol
                mark_energy = 0.0f;
                space_energy = 0.0f;
                sample_count = 0;
            }
        }

        // Update display periodically
        static uint32_t last_update = 0;
        uint32_t current_time = esp_timer_get_time() / 1000; // ms
        if (current_time - last_update > 1000) {
            display->Update();
            last_update = current_time;
        }
    }

    ESP_LOGI(kLogTag, "Audio WiFi credential reception stopped");
    display->ShowMessage("WiFi config timeout");
}

FrequencyDetector::FrequencyDetector(float frequency, size_t window_size)
    : frequency_(frequency)
    , window_size_(window_size)
    , frequency_bin_(static_cast<size_t>(frequency * window_size / kSampleRate + 0.5f))
    , angular_frequency_(2.0f * M_PI * frequency_ / kSampleRate)
{
    // Initialize the state buffer to zero
    state_.resize(window_size_, 0.0f);

    // Calculate filter coefficients for Goertzel algorithm or similar frequency detection
    // For a simple bandpass filter approach
    float normalized_freq = frequency_ / kSampleRate;
    float bandwidth = 50.0f / kSampleRate; // 50Hz bandwidth

    // Simple resonator coefficients
    float radius = 0.99f; // Pole radius for stability and selectivity
    coeff_a1_ = -2.0f * radius * cosf(angular_frequency_);
    coeff_a2_ = radius * radius;
    coeff_b0_ = 1.0f;

    // Initialize previous samples
    prev_input_ = 0.0f;
    prev_prev_input_ = 0.0f;
    prev_output_ = 0.0f;
    prev_prev_output_ = 0.0f;
}

void FrequencyDetector::Reset()
{
    // Clear the internal state buffer
    std::memset(state_buffer_, 0, sizeof(state_buffer_));

    // Initialize with two zero values
    state_buffer_[0] = 0.0f;
    state_buffer_[1] = 0.0f;

    // Reset any other internal state variables
    current_index_ = 0;
    sample_count_ = 0;
}

float FrequencyDetector::ProcessSample(float input)
{
    // Second-order IIR filter difference equation:
    // y[n] = b0*x[n] + b1*x[n-1] + b2*x[n-2] - a1*y[n-1] - a2*y[n-2]

    // Store previous input samples
    float x_n_minus_2 = x_state_[1];
    float x_n_minus_1 = x_state_[0];
    float y_n_minus_2 = y_state_[1];
    float y_n_minus_1 = y_state_[0];

    // Apply the difference equation
    float output = b0_ * input + 
                   b1_ * x_n_minus_1 + 
                   b2_ * x_n_minus_2 - 
                   a1_ * y_n_minus_1 - 
                   a2_ * y_n_minus_2;

    // Update state buffers for next iteration
    x_state_[1] = x_state_[0];
    x_state_[0] = input;
    y_state_[1] = y_state_[0];
    y_state_[0] = output;

    return output;
}

float FrequencyDetector::GetAmplitude() const
{
    // Check if we have at least two samples in the buffer
    if (state_index_ < 2) {
        return 0.0f;
    }

    // Get the previous two signal samples
    float sample_curr = state_buffer_[state_index_ - 1];
    float sample_prev = state_buffer_[state_index_ - 2];

    // Compute real and imaginary parts using precomputed coefficients
    // Real part: current sample - cos_coefficient * previous sample
    float real_part = sample_curr - cos_coefficient_ * sample_prev;

    // Imaginary part: sin_coefficient * previous sample
    float imag_part = sin_coefficient_ * sample_prev;

    // Calculate amplitude: sqrt(real^2 + imag^2) normalized by window size
    float magnitude_squared = real_part * real_part + imag_part * imag_part;
    float amplitude = sqrtf(magnitude_squared);

    // Normalize by half the window size
    return amplitude / (window_size_ * 0.5f);
}

AudioSignalProcessor::AudioSignalProcessor(size_t sample_rate, size_t bit_rate, size_t mark_freq, size_t space_freq, size_t buffer_size)
    : sample_rate_(sample_rate)
    , bit_rate_(bit_rate)
    , mark_frequency_(mark_freq)
    , space_frequency_(space_freq)
    , buffer_size_(buffer_size)
    , samples_per_bit_(sample_rate / bit_rate)
    , phase_increment_mark_(2.0 * M_PI * mark_freq / sample_rate)
    , phase_increment_space_(2.0 * M_PI * space_freq / sample_rate)
    , current_phase_mark_(0.0)
    , current_phase_space_(0.0)
{
    // Validate that sample rate is divisible by bit rate
    if (sample_rate % bit_rate != 0) {
        ESP_LOGW(kLogTag, "Sample rate (%zu) is not evenly divisible by bit rate (%zu)", sample_rate, bit_rate);
    }

    // Initialize the Goertzel filters or other detection mechanisms
    // Reset internal state
    memset(&detection_state_, 0, sizeof(detection_state_));

    ESP_LOGI(kLogTag, "AudioSignalProcessor initialized: sample_rate=%zu, bit_rate=%zu, mark_freq=%zu, space_freq=%zu", 
             sample_rate, bit_rate, mark_freq, space_freq);
}

std::vector<float> AfskDemodulator::ProcessAudioSamples(const std::vector<float>& samples)
{
    std::vector<float> mark_probabilities;

    // Add new samples to the buffer
    for (float sample : samples) {
        sample_buffer_.push_back(sample);
    }

    // Process buffered samples in windows
    while (sample_buffer_.size() >= window_size_) {
        // Extract a window of samples for processing
        std::vector<float> window(sample_buffer_.begin(), sample_buffer_.begin() + window_size_);

        // Apply Goertzel algorithm to detect mark and space frequencies
        float mark_magnitude = Goertzel(window, mark_frequency_, sample_rate_);
        float space_magnitude = Goertzel(window, space_frequency_, sample_rate_);

        // Calculate probability of mark tone presence
        float total_magnitude = mark_magnitude + space_magnitude;
        float mark_probability = (total_magnitude > 0.0f) ? (mark_magnitude / total_magnitude) : 0.0f;

        // Clamp probability to valid range [0, 1]
        mark_probability = std::max(0.0f, std::min(1.0f, mark_probability));

        mark_probabilities.push_back(mark_probability);

        // Remove processed samples from buffer
        sample_buffer_.erase(sample_buffer_.begin(), sample_buffer_.begin() + window_size_);
    }

    return mark_probabilities;
}

float AfskDemodulator::Goertzel(const std::vector<float>& samples, float frequency, int sample_rate)
{
    int N = samples.size();
    float k = (N * frequency) / sample_rate;
    float omega = (2.0f * M_PI * k) / N;
    float sine = sin(omega);
    float cosine = cos(omega);
    float coeff = 2.0f * cosine;

    float q0 = 0.0f;
    float q1 = 0.0f;
    float q2 = 0.0f;

    // Goertzel algorithm implementation
    for (int i = 0; i < N; i++) {
        q0 = coeff * q1 - q2 + samples[i];
        q2 = q1;
        q1 = q0;
    }

    // Calculate magnitude
    float real = (q1 - q2 * cosine);
    float imag = (q2 * sine);
    float magnitude = sqrt(real * real + imag * imag);

    return magnitude;
}

