void AudioDataBuffer::AudioDataBuffer(size_t max_byte_size, 
                                     const std::vector<uint8_t>& start_marker, 
                                     const std::vector<uint8_t>& end_marker, 
                                     bool enable_checksum)
{
    // Initialize the maximum size of the buffer based on the specified byte size
    max_size_ = max_byte_size;

    // Reserve memory for bit-level data storage
    // Each byte requires 8 bits, so we need max_byte_size * 8 bits
    bit_buffer_.reserve(max_byte_size * 8);

    // Set up the start transmission marker
    start_marker_ = start_marker;

    // Set up the end transmission marker
    end_marker_ = end_marker;

    // Configure checksum validation based on the enable flag
    checksum_enabled_ = enable_checksum;

    // Initialize buffer state variables
    current_bit_count_ = 0;
    current_byte_count_ = 0;
    transmission_started_ = false;
    transmission_ended_ = false;
    buffer_overflow_ = false;

    // Clear any existing data in the buffer
    bit_buffer_.clear();
    byte_buffer_.clear();

    // If the buffer has a predefined maximum size, reserve space for efficiency
    if (max_size_ > 0) {
        byte_buffer_.reserve(max_size_);
    }

    // Initialize checksum related variables if enabled
    if (checksum_enabled_) {
        calculated_checksum_ = 0;
        received_checksum_ = 0;
    }

    // Reset state machine for packet detection
    packet_state_ = 0;

    // Log the buffer initialization
    ESP_LOGD(kLogTag, "AudioDataBuffer initialized with max size: %d bytes, checksum: %s", 
             max_byte_size, enable_checksum ? "enabled" : "disabled");
}

