void ProcessProbabilityData(const std::vector<float>& probabilities, float threshold) {
    // Define states for the receiver
    enum class ReceiverState {
        INACTIVE,
        WAITING_FOR_START,
        RECEIVING_DATA,
        VALIDATION
    };

    // Static variables to maintain state between calls
    static ReceiverState state = ReceiverState::INACTIVE;
    static std::vector<uint8_t> bitBuffer;
    static std::vector<uint8_t> byteBuffer;
    static size_t bitCount = 0;

    // Predefined start and end identifiers (example values - should match transmitter)
    static const uint16_t START_IDENTIFIER = 0xAAAA;  // 16-bit start pattern
    static const uint16_t END_IDENTIFIER = 0x5555;    // 16-bit end pattern

    // Process each probability value
    for (float prob : probabilities) {
        // Convert probability to binary bit
        uint8_t bit = (prob >= threshold) ? 1 : 0;

        switch (state) {
            case ReceiverState::INACTIVE:
                // Look for start identifier pattern
                bitBuffer.push_back(bit);
                if (bitBuffer.size() > 16) {
                    bitBuffer.erase(bitBuffer.begin());  // Keep only last 16 bits
                }

                // Check if we have enough bits to form start identifier
                if (bitBuffer.size() == 16) {
                    uint16_t currentPattern = 0;
                    for (size_t i = 0; i < 16; ++i) {
                        currentPattern = (currentPattern << 1) | bitBuffer[i];
                    }

                    if (currentPattern == START_IDENTIFIER) {
                        state = ReceiverState::WAITING_FOR_START;
                        bitBuffer.clear();
                        bitCount = 0;
                        byteBuffer.clear();
                        ESP_LOGI(kLogTag, "Start identifier detected, entering waiting state");
                    }
                }
                break;

            case ReceiverState::WAITING_FOR_START:
                // Confirm start sequence and begin data reception
                bitBuffer.push_back(bit);
                bitCount++;

                // Wait for confirmation bits (e.g., next 8 bits)
                if (bitCount >= 8) {
                    state = ReceiverState::RECEIVING_DATA;
                    bitBuffer.clear();
                    bitCount = 0;
                    ESP_LOGI(kLogTag, "Confirmed start, beginning data reception");
                }
                break;

            case ReceiverState::RECEIVING_DATA:
                // Collect data bits
                bitBuffer.push_back(bit);
                bitCount++;

                // When we have 8 bits, form a byte
                if (bitCount >= 8) {
                    uint8_t byte = 0;
                    for (size_t i = 0; i < 8; ++i) {
                        byte = (byte << 1) | bitBuffer[i];
                    }
                    byteBuffer.push_back(byte);
                    bitBuffer.erase(bitBuffer.begin(), bitBuffer.begin() + 8);
                    bitCount -= 8;

                    // Check if we have enough data to look for end identifier
                    if (byteBuffer.size() >= 2) {
                        // Check last two bytes for end identifier
                        uint16_t lastTwoBytes = (static_cast<uint16_t>(byteBuffer[byteBuffer.size()-2]) << 8) | 
                                               byteBuffer[byteBuffer.size()-1];

                        if (lastTwoBytes == END_IDENTIFIER) {
                            state = ReceiverState::VALIDATION;
                            ESP_LOGI(kLogTag, "End identifier detected, validating data");
                        }
                    }
                }
                break;

            case ReceiverState::VALIDATION:
                // Validate received data (checksum verification)
                if (byteBuffer.size() >= 3) {  // Need at least data + checksum bytes
                    bool checksumValid = true;

                    // Simple checksum validation (example - XOR all data bytes)
                    uint8_t calculatedChecksum = 0;
                    for (size_t i = 0; i < byteBuffer.size() - 3; ++i) {  // Exclude identifier and checksum
                        calculatedChecksum ^= byteBuffer[i];
                    }

                    uint8_t receivedChecksum = byteBuffer[byteBuffer.size() - 3];

                    if (calculatedChecksum == receivedChecksum) {
                        ESP_LOGI(kLogTag, "Checksum validation passed");

                        // Extract WiFi credentials (assuming they're in the buffer)
                        if (byteBuffer.size() > 4) {
                            // Skip first two bytes (start identifier) and process remaining data
                            std::string ssid;
                            std::string password;

                            // Parse SSID and password from buffer (implementation depends on format)
                            size_t dataIndex = 0;
                            if (dataIndex < byteBuffer.size() - 3) {
                                uint8_t ssidLen = byteBuffer[dataIndex++];
                                if (dataIndex + ssidLen <= byteBuffer.size() - 3) {
                                    ssid.assign(byteBuffer.begin() + dataIndex, 
                                               byteBuffer.begin() + dataIndex + ssidLen);
                                    dataIndex += ssidLen;

                                    if (dataIndex < byteBuffer.size() - 3) {
                                        uint8_t passLen = byteBuffer[dataIndex++];
                                        if (dataIndex + passLen <= byteBuffer.size() - 3) {
                                            password.assign(byteBuffer.begin() + dataIndex, 
                                                           byteBuffer.begin() + dataIndex + passLen);
                                        }
                                    }
                                }
                            }

                            if (!ssid.empty()) {
                                ESP_LOGI(kLogTag, "Received WiFi credentials - SSID: %s", ssid.c_str());

                                // Store credentials using ssid_manager
                                if (app != nullptr) {
                                    // Assuming there's a method to set WiFi credentials
                                    // This would depend on the Application class implementation
                                    // app->setWiFiCredentials(ssid, password);
                                }

                                // Update display
                                Display::getInstance().showStatus("WiFi Config Received");
                            }
                        }
                    } else {
                        ESP_LOGW(kLogTag, "Checksum validation failed");
                    }
                }

                // Reset to inactive state regardless of validation result
                state = ReceiverState::INACTIVE;
                bitBuffer.clear();
                byteBuffer.clear();
                bitCount = 0;
                break;
        }
    }
}

std::vector<uint8_t> AfskDemod::ConvertBitsToBytes(const std::vector<uint8_t>& bits) const
{
    if (bits.empty()) {
        return std::vector<uint8_t>();
    }

    // Calculate the number of complete bytes we can form
    size_t num_bytes = bits.size() / 8;
    std::vector<uint8_t> bytes(num_bytes);

    // Process each group of 8 bits
    for (size_t i = 0; i < num_bytes; ++i) {
        uint8_t byte_value = 0;
        // Process 8 bits for each byte (MSB first)
        for (int bit_pos = 0; bit_pos < 8; ++bit_pos) {
            size_t bit_index = i * 8 + bit_pos;
            if (bit_index < bits.size() && bits[bit_index] == 1) {
                byte_value |= (1 << (7 - bit_pos));  // MSB first
            }
        }
        bytes[i] = byte_value;
    }

    return bytes;
}

