void Backlight::RestoreBrightness()
{
    // Retrieve saved brightness level from settings
    int brightness = Settings::GetDisplayBrightness();

    // Validate brightness value, default to 10 if zero or invalid
    if (brightness <= 0) {
        brightness = 10;
    }

    // Apply brightness to backlight using LEDC
    // Assuming LEDC channel 0 is used for backlight control
    // and maximum duty cycle is 100 (can be adjusted based on actual implementation)
    ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, brightness);
    ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);

    ESP_LOGI(TAG, "Restored brightness level: %d", brightness);
}

void Backlight::SetBrightness(uint8_t brightness, bool save)
{
    // Clamp brightness to valid range
    if (brightness > 100) {
        brightness = 100;
    }

    // Prevent redundant updates
    if (brightness == mCurrentBrightness) {
        return;
    }

    // Store target brightness
    mTargetBrightness = brightness;

    // Save setting if requested
    if (save) {
        Settings::GetInstance()->SetBacklightBrightness(brightness);
    }

    // If we have a transition timer running, restart it
    if (mTransitionTimer != nullptr) {
        esp_timer_stop(mTransitionTimer);
        esp_timer_start_periodic(mTransitionTimer, TRANSITION_INTERVAL_US);
    } else {
        // For immediate change or first time, set directly
        uint32_t duty = (brightness * LEDC_MAX_DUTY) / 100;
        ledc_set_duty(LEDC_MODE, LEDC_CHANNEL, duty);
        ledc_update_duty(LEDC_MODE, LEDC_CHANNEL);
        mCurrentBrightness = brightness;
    }
}

void Backlight::OnTransitionTimer()
{
    // Get the current and target brightness levels
    int currentBrightness = GetCurrentBrightness();
    int targetBrightness = GetTargetBrightness();

    // Check if we've reached the target brightness
    if (currentBrightness == targetBrightness) {
        // Stop the transition timer as we've reached our target
        if (m_transitionTimer) {
            esp_timer_stop(m_transitionTimer);
        }
        return;
    }

    // Calculate the next brightness step
    int newBrightness = currentBrightness;
    if (currentBrightness < targetBrightness) {
        // Increase brightness gradually
        newBrightness = std::min(currentBrightness + m_brightnessStep, targetBrightness);
    } else {
        // Decrease brightness gradually
        newBrightness = std::max(currentBrightness - m_brightnessStep, targetBrightness);
    }

    // Update the current brightness
    SetCurrentBrightness(newBrightness);

    // Apply the new brightness to the hardware using LEDC
    uint32_t duty = (newBrightness * m_maxDuty) / 100;
    ledc_set_duty(LEDC_MODE, LEDC_CHANNEL, duty);
    ledc_update_duty(LEDC_MODE, LEDC_CHANNEL);

    // If we've now reached the target, stop the timer
    if (newBrightness == targetBrightness) {
        if (m_transitionTimer) {
            esp_timer_stop(m_transitionTimer);
        }
        ESP_LOGI(TAG, "Backlight transition completed. Brightness: %d%%", newBrightness);
    } else {
        ESP_LOGD(TAG, "Backlight transition in progress. Current: %d%%, Target: %d%%", 
                 newBrightness, targetBrightness);
    }
}

Backlight::Backlight(gpio_num_t gpio_pin, bool inverted, uint32_t frequency)
{
    // Configure LEDC timer
    ledc_timer_config_t timer_conf = {};
    timer_conf.speed_mode = LEDC_LOW_SPEED_MODE;
    timer_conf.timer_num = LEDC_TIMER_0;
    timer_conf.duty_resolution = LEDC_TIMER_10_BIT;  // 10-bit resolution (0-1023)
    timer_conf.freq_hz = frequency;
    timer_conf.clk_cfg = LEDC_AUTO_CLK;

    esp_err_t ret = ledc_timer_config(&timer_conf);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to configure LEDC timer: %s", esp_err_to_name(ret));
        return;
    }

    // Configure LEDC channel
    ledc_channel_config_t channel_conf = {};
    channel_conf.gpio_num = gpio_pin;
    channel_conf.speed_mode = LEDC_LOW_SPEED_MODE;
    channel_conf.channel = LEDC_CHANNEL_0;
    channel_conf.intr_type = LEDC_INTR_DISABLE;
    channel_conf.timer_sel = LEDC_TIMER_0;
    channel_conf.duty = inverted ? 1023 : 0;  // Start with off state
    channel_conf.point_num = 0;
    channel_conf.flags.output_invert = inverted ? 1 : 0;

    ret = ledc_channel_config(&channel_conf);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to configure LEDC channel: %s", esp_err_to_name(ret));
        return;
    }

    // Initialize with default brightness (off)
    setBrightness(0);

    ESP_LOGI(TAG, "PWM backlight initialized on GPIO %d, frequency: %d Hz, inverted: %s", 
             gpio_pin, frequency, inverted ? "true" : "false");
}

void PwmBacklight::SetBrightnessImpl(uint8_t brightness)
{
    // Clamp brightness to valid range (0-100%)
    if (brightness > 100) {
        brightness = 100;
    }

    // Map brightness percentage (0-100) to 10-bit PWM range (0-1023)
    uint32_t duty_cycle = (brightness * 1023) / 100;

    // Update the LEDC channel with new duty cycle
    ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, duty_cycle);
    ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);

    ESP_LOGD(TAG, "Backlight brightness set to %d%% (duty cycle: %d)", brightness, duty_cycle);
}

Board::Board() {
    // Initialize the board hardware
    ESP_LOGI(TAG, "Initializing board");

    // Load UUID from persistent storage
    char uuid_str[37]; // UUID string format: 8-4-4-4-12 = 36 characters + null terminator
    if (Settings::getInstance()->getUUID(uuid_str, sizeof(uuid_str))) {
        ESP_LOGI(TAG, "Loaded existing UUID: %s", uuid_str);
    } else {
        ESP_LOGI(TAG, "No existing UUID found, generating new one");

        // Generate new UUID
        uint8_t uuid_bytes[16];
        for (int i = 0; i < 16; i++) {
            uuid_bytes[i] = esp_random() & 0xFF;
        }

        // Set UUID version (4) and variant (RFC 4122)
        uuid_bytes[6] = (uuid_bytes[6] & 0x0F) | 0x40; // Version 4
        uuid_bytes[8] = (uuid_bytes[8] & 0x3F) | 0x80; // Variant

        // Convert to string format
        snprintf(uuid_str, sizeof(uuid_str), 
                "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
                uuid_bytes[0], uuid_bytes[1], uuid_bytes[2], uuid_bytes[3],
                uuid_bytes[4], uuid_bytes[5], uuid_bytes[6], uuid_bytes[7],
                uuid_bytes[8], uuid_bytes[9], uuid_bytes[10], uuid_bytes[11],
                uuid_bytes[12], uuid_bytes[13], uuid_bytes[14], uuid_bytes[15]);

        // Save UUID to persistent storage
        if (Settings::getInstance()->setUUID(uuid_str)) {
            ESP_LOGI(TAG, "Generated and saved new UUID: %s", uuid_str);
        } else {
            ESP_LOGE(TAG, "Failed to save UUID to persistent storage");
        }
    }

    // Initialize other board components
    SystemInfo::getInstance()->initialize();

    ESP_LOGI(TAG, "Board initialization completed");
}

std::string Board::GenerateUuid() {
    uint8_t uuid[16];

    // Generate 16 random bytes using ESP32 hardware RNG
    for (int i = 0; i < 16; i++) {
        uuid[i] = esp_random() & 0xFF;
    }

    // Set the UUID version to 4 (random)
    // Version is in bits 12-15 of byte 6 (0-indexed)
    uuid[6] = (uuid[6] & 0x0F) | 0x40;

    // Set the UUID variant to RFC 4122
    // Variant is in bits 6-7 of byte 8 (0-indexed)
    uuid[8] = (uuid[8] & 0x3F) | 0x80;

    // Format as UUID string: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
    char uuid_str[37];
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

