    json += "\"hardware\":{";
    json += "\"chip_model\":\"";

    switch (chip_info.model) {
        case CHIP_ESP32:
            json += "ESP32";
            break;
        case CHIP_ESP32S2:
            json += "ESP32-S2";
            break;
        case CHIP_ESP32S3:
            json += "ESP32-S3";
            break;
        case CHIP_ESP32C3:
            json += "ESP32-C3";
            break;
        case CHIP_ESP32H2:
            json += "ESP32-H2";
            break;
        default:
            json += "Unknown";
            break;
    }

    json += "\",\"cores\":" + std::to_string(chip_info.cores);
    json += ",\"revision\":" + std::to_string(chip_info.revision);
    json += ",\"flash_size\":" + std::to_string(esp_flash_get_size(NULL) / (1024 * 1024));

