             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    json += ",\"mac_address\":\"" + std::string(mac_str) + "\"";

    json += "},";

    // Application metadata
    const esp_app_desc_t* app_desc = esp_app_get_description();
    json += "\"application\":{";
    json += "\"name\":\"" + std::string(app_desc->project_name) + "\"";
    json += ",\"version\":\"" + std::string(app_desc->version) + "\"";
    json += ",\"compile_time\":\"" + std::string(app_desc->time) + " " + std::string(app_desc->date) + "\"";
    json += "},";

    // Partition information
    const esp_partition_t* running_part = esp_ota_get_running_partition();
    json += "\"partition\":{";
    if (running_part) {
        json += "\"name\":\"" + std::string(running_part->label) + "\"";
        json += ",\"type\":" + std::to_string(running_part->type);
        json += ",\"subtype\":" + std::to_string(running_part->subtype);
        json += ",\"address\":" + std::to_string(running_part->address);
        json += ",\"size\":" + std::to_string(running_part->size);
    } else {
        json += "\"name\":\"unknown\"";
    }
    json += "},";

    // Runtime information
    json += "\"runtime\":{";
    json += "\"min_free_heap\":" + std::to_string(esp_get_minimum_free_heap_size());
    json += ",\"current_free_heap\":" + std::to_string(esp_get_free_heap_size());

    // UUID from settings (assuming it's available)
    // This would depend on how UUID is stored in your settings
    // For now, let's generate a placeholder or retrieve from settings
    json += ",\"uuid\":\"";

    // Try to get UUID from settings or generate one
    // This is a simplified approach - you might have a specific way to store/retrieve UUID
    uint32_t chip_id = (mac[0] << 16) | (mac[1] << 8) | mac[2];
    char uuid_str[37];
    snprintf(uuid_str, sizeof(uuid_str), "%08X-%04X-%04X-%04X-%02X%02X%02X%02X",
             chip_id,
             (mac[3] << 8) | mac[4],
             (mac[5] << 8) | (chip_info.chip_revision >> 16),
             chip_info.chip_revision & 0xFFFF,
             mac[0], mac[1], mac[2], mac[3]);
    json += std::string(uuid_str);

    json += "\"";
    json += "}";

    json += "}";

    return json;
}

