Button::Button(gpio_num_t gpio_num, bool active_level, uint16_t short_press_threshold, uint16_t long_press_threshold, bool power_save)
{
    // Initialize button configuration
    this->gpio_num = gpio_num;
    this->active_level = active_level;
    this->short_press_threshold = short_press_threshold;
    this->long_press_threshold = long_press_threshold;
    this->power_save = power_save;

    // Initialize button state variables
    this->last_state = !active_level;  // Assume initial state is inactive
    this->current_state = !active_level;
    this->press_start_time = 0;
    this->last_press_duration = 0;

    // Configure GPIO if valid pin is provided
    if (gpio_num != GPIO_NUM_NC) {
        // Configure GPIO as input
        gpio_config_t io_conf = {};
        io_conf.intr_type = GPIO_INTR_DISABLE;  // Disable interrupt initially
        io_conf.mode = GPIO_MODE_INPUT;
        io_conf.pin_bit_mask = (1ULL << gpio_num);
        io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
        io_conf.pull_up_en = GPIO_PULLUP_ENABLE;  // Enable pull-up by default

        esp_err_t err = gpio_config(&io_conf);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to configure GPIO %d for button", gpio_num);
        }

        // If power saving is enabled, we might want to configure interrupts
        // instead of polling
        if (power_save) {
            // Configure interrupt for both rising and falling edges
            io_conf.intr_type = GPIO_INTR_ANYEDGE;
            gpio_config(&io_conf);

            // TODO: Register interrupt handler if needed
            // This would typically involve setting up ISR and adding to
            // the system's input handling framework
        }
    }

    // Add button to system input handling framework
    // This would typically register the button with a global button manager
    // or input event system
    register_button(this);

    ESP_LOGI(TAG, "Button initialized on GPIO %d, active_level=%s, power_save=%s", 
             gpio_num, 
             active_level ? "HIGH" : "LOW",
             power_save ? "ENABLED" : "DISABLED");
}

