void Button::OnMultipleClick(std::function<void()> callback, uint8_t click_count) {
    if (click_count == 0) {
        ESP_LOGW(TAG, "Invalid click count: %d", click_count);
        return;
    }

    // Store the callback and click count for later use
    this->multiple_click_callback_ = callback;
    this->expected_click_count_ = click_count;
    this->current_click_count_ = 0;

    // Set up the event handler for multiple click detection
    // This typically involves detecting press-release cycles within a timeout
    auto handler = [this](ButtonEvent event) {
        switch (event) {
            case ButtonEvent::Pressed:
                // Start press timer if needed
                break;

            case ButtonEvent::Released:
                // Increment click counter
                this->current_click_count_++;

                // If we've reached the expected count, trigger callback
                if (this->current_click_count_ >= this->expected_click_count_) {
                    if (this->multiple_click_callback_) {
                        this->multiple_click_callback_();
                    }
                    this->current_click_count_ = 0;
                } else {
                    // Reset the multi-click timer to detect more clicks
                    this->ResetMultiClickTimer();
                }
                break;

            case ButtonEvent::LongPressed:
                // Reset multi-click sequence on long press
                this->current_click_count_ = 0;
                break;

            default:
                break;
        }
    };

    // Register the handler with the button
    this->SetEventHandler(handler);
}

