I2cDevice::I2cDevice(i2c_master_bus_handle_t i2c_bus, uint8_t addr)
{
    i2c_device_config_t dev_cfg = {
        .dev_addr_length = I2C_ADDR_BIT_7,
        .device_address = addr,
        .scl_speed_hz = 100000,
        .flags = {
            .disable_ack_check = false,
        },
    };

    esp_err_t err = i2c_master_bus_add_device(i2c_bus, &dev_cfg, &device_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to add I2C device at address 0x%02X: %s", addr, esp_err_to_name(err));
        assert(false);
    }

    assert(device_handle_ != nullptr);
}

esp_err_t I2cDevice::WriteReg(uint8_t reg, uint8_t value)
{
    uint8_t buffer[2] = {reg, value};
    return i2c_master_transmit(i2c_bus_, buffer, sizeof(buffer), 100 / portTICK_PERIOD_MS);
}

uint8_t I2cDevice::ReadReg(uint8_t reg_addr)
{
    uint8_t data = 0;
    esp_err_t result = i2c_master_write_read_device(i2c_bus_, addr_, &reg_addr, 1, &data, 1, -1);

    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read register 0x%02X from device 0x%02X, error: %d", reg_addr, addr_, result);
        return 0; // Return 0 on error, though this could be ambiguous if 0 is valid data
    }

    ESP_LOGD(TAG, "Read register 0x%02X: 0x%02X", reg_addr, data);
    return data;
}

WifiBoard::WifiBoard() {
    auto disp = Board::GetInstance().GetDisplay();

    // Initialize WiFi connection timeout timer
    // Create a one-shot timer that will trigger if connection takes too long
    connection_timeout_timer = xTimerCreate(
        "wifi_connect_timeout",
        pdMS_TO_TICKS(CONNECT_TIMEOUT_SEC * 1000),
        pdFALSE,  // One-shot timer
        this,     // Timer ID - pass this object instance
        [](TimerHandle_t xTimer) {
            // Timer callback - get the WifiBoard instance and handle timeout
            WifiBoard* board = static_cast<WifiBoard*>(pvTimerGetTimerID(xTimer));
            if (board) {
                board->handleConnectionTimeout();
            }
        }
    );

    if (connection_timeout_timer == NULL) {
        ESP_LOGE(TAG, "Failed to create WiFi connection timeout timer");
    }

    // Initialize other WiFi related components
    wifi_manager_init();

    // Register WiFi event handlers
    wifi_manager_set_callback(EVENT_STA_GOT_IP, [](void* ctx, wifi_manager_event_t event, void* data) {
        WifiBoard* board = static_cast<WifiBoard*>(ctx);
        if (board) {
            board->onWiFiConnected();
        }
    }, this);

    wifi_manager_set_callback(EVENT_STA_DISCONNECTED, [](void* ctx, wifi_manager_event_t event, void* data) {
        WifiBoard* board = static_cast<WifiBoard*>(ctx);
        if (board) {
            board->onWiFiDisconnected();
        }
    }, this);
}

WifiBoard::~WifiBoard() {
    // Stop and delete the WiFi connection timer to prevent resource leaks
    if (connect_timer_handle != nullptr) {
        // Stop the timer first
        esp_timer_stop(connect_timer_handle);
        // Delete the timer to free resources
        esp_timer_delete(connect_timer_handle);
        connect_timer_handle = nullptr;
    }

    // Additional cleanup for WiFi related resources if needed
    // This ensures proper cleanup when the WifiBoard object is destroyed
    ESP_LOGD(TAG, "WifiBoard destructor called - timers cleaned up");
}

void WifiBoard::StartNetwork()
{
    // Get system information for SSID prefix
    SystemInfo sysInfo;
    std::string ssidPrefix = sysInfo.GetDeviceName();

    // Get current language setting
    std::string language = Settings::GetInstance().GetLanguage();

    // Initialize WiFi manager with SSID prefix and language
    WifiManager& wifiManager = WifiManager::GetInstance();
    wifiManager.SetSsidPrefix(ssidPrefix);
    wifiManager.SetLanguage(language);

    // Set up unified event callback for WiFi events
    wifiManager.SetEventCallback([this](WifiEvent event, const std::string& data) {
        HandleWifiEvent(event, data);
    });

    // Attempt to connect to known networks
    ESP_LOGI(TAG, "Attempting to connect to WiFi network");

    // Check if we have saved credentials
    if (wifiManager.HasSavedCredentials()) {
        // Try to connect with saved credentials
        wifiManager.Connect();

        // Wait for connection with timeout
        int timeout = CONNECT_TIMEOUT_SEC;
        while (timeout > 0 && !wifiManager.IsConnected()) {
            vTaskDelay(pdMS_TO_TICKS(1000));
            timeout--;

            // Check if user requested config mode
            if (wifiManager.IsConfigModeRequested()) {
                break;
            }
        }

        // If still not connected, enter config mode
        if (!wifiManager.IsConnected() && !wifiManager.IsConfigModeRequested()) {
            ESP_LOGI(TAG, "Connection failed, entering configuration mode");
            wifiManager.EnterConfigMode();
        }
    } else {
        // No saved credentials, enter config mode directly
        ESP_LOGI(TAG, "No saved credentials found, entering configuration mode");
        wifiManager.EnterConfigMode();
    }
}

// Helper function to handle WiFi events (would be defined elsewhere in the class)
void WifiBoard::HandleWifiEvent(WifiEvent event, const std::string& data)
{
    switch (event) {
        case WifiEvent::SCANNING:
            ESP_LOGI(TAG, "WiFi scanning started");
            // Update display to show scanning status
            break;

        case WifiEvent::CONNECTING:
            ESP_LOGI(TAG, "Connecting to network: %s", data.c_str());
            // Update display to show connecting status
            break;

        case WifiEvent::CONNECTED:
            ESP_LOGI(TAG, "Successfully connected to WiFi");
            // Update display with connection success
            break;

        case WifiEvent::DISCONNECTED:
            ESP_LOGI(TAG, "WiFi disconnected: %s", data.c_str());
            // Handle disconnection, possibly try to reconnect
            break;

        case WifiEvent::ENTER_CONFIG_MODE:
            ESP_LOGI(TAG, "Entering WiFi configuration mode");
            // Display configuration interface
            break;

        case WifiEvent::EXIT_CONFIG_MODE:
            ESP_LOGI(TAG, "Exiting WiFi configuration mode");
            // Return to normal operation display
            break;

        default:
            ESP_LOGW(TAG, "Unhandled WiFi event: %d", static_cast<int>(event));
            break;
    }
}

void WifiBoard::TryWifiConnect() {
    auto disp = Board::GetInstance().GetDisplay();

    // Check if we have saved WiFi credentials
    if (SsidManager::HasSavedCredentials()) {
        // Display connection attempt message
        disp->Clear();
        disp->Print(ICON_WIFI " " LANG_CONNECTING);
        disp->Display();

        // Initialize WiFi station
        WifiStation::Initialize();

        // Start connection attempt
        WifiStation::Connect();

        // Wait for connection with timeout
        int timeout = CONNECT_TIMEOUT_SEC;
        while (timeout > 0 && !WifiStation::IsConnected()) {
            vTaskDelay(pdMS_TO_TICKS(1000)); // Wait 1 second
            timeout--;

            // Update display with countdown or status
            disp->SetCursor(0, 1);
            disp->Printf("%s %d%s", LANG_TIMEOUT_IN, timeout, LANG_SECONDS);
            disp->Display();
        }

        if (WifiStation::IsConnected()) {
            // Successfully connected
            disp->Clear();
            disp->Print(ICON_WIFI " " LANG_CONNECTED);
            disp->SetCursor(0, 1);
            disp->Print(WifiStation::GetSSID());
            disp->Display();

            // Store connection info in system
            SystemInfo::SetWiFiStatus(true);
            SystemInfo::SetIPAddress(WifiStation::GetIP());

            // Delay to show success message
            vTaskDelay(pdMS_TO_TICKS(2000));
            return;
        } else {
            // Connection failed, disconnect
            WifiStation::Disconnect();
            disp->Clear();
            disp->Print(ICON_WIFI " " LANG_CONNECTION_FAILED);
            disp->Display();
            vTaskDelay(pdMS_TO_TICKS(2000));
        }
    }

    // No credentials saved or connection failed - start configuration mode
    disp->Clear();
    disp->Print(ICON_WIFI " " LANG_CONFIG_MODE);
    disp->SetCursor(0, 1);
    disp->Print(LANG_WAITING_FOR_CONFIG);
    disp->Display();

    // Start WiFi manager for configuration
    WifiManager::StartConfigurationMode();

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // If Blufi is enabled, also start Blufi provisioning
    Blufi::StartProvisioning();
#endif

    // Keep the configuration mode running
    // This typically blocks until configuration is complete
    WifiManager::HandleConfiguration();
}

void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string &data) {
    switch (event) {
        case NetworkEvent::CONNECTED:
            ESP_LOGI(TAG, "WiFi connected");
            m_isConnected = true;
            m_isConnecting = false;

            // Stop any connection timeout timers
            if (m_connectTimer) {
                xTimerStop(m_connectTimer, 0);
            }

            // Release provisioning resources if they exist
            #ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
            if (m_blufiEnabled) {
                blufi_stop();
                m_blufiEnabled = false;
            }
            #endif

            // Update display to show connected state
            UpdateDisplayConnectionStatus(true);

            // Save successful connection settings
            if (m_saveCredentials) {
                SaveWifiCredentials();
            }

            break;

        case NetworkEvent::DISCONNECTED:
            ESP_LOGI(TAG, "WiFi disconnected");
            m_isConnected = false;
            m_isConnecting = false;

            // Stop any connection timeout timers
            if (m_connectTimer) {
                xTimerStop(m_connectTimer, 0);
            }

            // Update display to show disconnected state
            UpdateDisplayConnectionStatus(false);

            // Attempt reconnection if not in config mode
            if (!m_inConfigMode && m_autoReconnect) {
                StartReconnectionTimer();
            }

            break;

        case NetworkEvent::CONNECTING:
            ESP_LOGI(TAG, "WiFi connecting");
            m_isConnecting = true;
            m_isConnected = false;

            // Start connection timeout timer
            if (m_connectTimer) {
                xTimerStart(m_connectTimer, 0);
            }

            // Update display to show connecting state
            UpdateDisplayConnectionStatus(false, true);

            break;

        case NetworkEvent::SCAN_COMPLETE:
            ESP_LOGI(TAG, "WiFi scan complete");
            m_scanComplete = true;

            // Process scan results
            ProcessScanResults();

            break;

        case NetworkEvent::CONFIG_MODE_ENTERED:
            ESP_LOGI(TAG, "Entered configuration mode");
            m_inConfigMode = true;
            m_isConnected = false;
            m_isConnecting = false;

            // Stop any ongoing connection attempts
            if (m_connectTimer) {
                xTimerStop(m_connectTimer, 0);
            }

            // Start provisioning service
            #ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
            if (!m_blufiEnabled) {
                blufi_start();
                m_blufiEnabled = true;
            }
            #endif

            // Update display for config mode
            UpdateDisplayConfigMode(true);

            break;

        case NetworkEvent::CONFIG_MODE_EXITED:
            ESP_LOGI(TAG, "Exited configuration mode");
            m_inConfigMode = false;

            // Stop provisioning service
            #ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
            if (m_blufiEnabled) {
                blufi_stop();
                m_blufiEnabled = false;
            }
            #endif

            // Update display to exit config mode
            UpdateDisplayConfigMode(false);

            // Attempt to connect with new credentials
            if (m_autoReconnect) {
                StartReconnectionTimer();
            }

            break;

        case NetworkEvent::CONNECTION_FAILED:
            ESP_LOGW(TAG, "WiFi connection failed: %s", data.c_str());
            m_isConnected = false;
            m_isConnecting = false;

            // Stop any connection timeout timers
            if (m_connectTimer) {
                xTimerStop(m_connectTimer, 0);
            }

            // Update display to show failure
            UpdateDisplayConnectionStatus(false);

            // Handle specific failure cases
            if (data.find("auth") != std::string::npos) {
                // Authentication failed - may want to clear saved credentials
                HandleAuthFailure();
            }

            // Attempt reconnection if enabled
            if (m_autoReconnect) {
                StartReconnectionTimer();
            }

            break;

        default:
            ESP_LOGW(TAG, "Unknown network event: %d", static_cast<int>(event));
            break;
    }

    // Notify external callback if set
    if (m_networkCallback) {
        m_networkCallback(event, data);
    }
}

void WifiBoard::OnWifiConnectTimeout(void *arg)
{
    ESP_LOGW(TAG, "WiFi connection timeout occurred after %d seconds", CONNECT_TIMEOUT_SEC);

    // Stop the current WiFi station connection attempt
    wifi_station_stop();

    // Disconnect from any current network
    esp_wifi_disconnect();

    // Stop the WiFi station mode
    wifi_manager_stop_sta();

    // Update system status to reflect connection failure
    SystemInfo::GetInstance().SetNetworkStatus(SystemInfo::NetworkStatus::kDisconnected);

    // Get display instance to show configuration prompt
    auto disp = Board::GetInstance().GetDisplay();
    if (disp) {
        disp->Clear();
        disp->SetFont(Font::kSmall);
        disp->DrawString(0, 0, ICON_WIFI " " + lang_config.wifi_connection_failed);
        disp->DrawString(0, 20, lang_config.wifi_timeout_message);
        disp->DrawString(0, 40, lang_config.wifi_enter_config_mode);
        disp->Display();
    }

    // Start configuration mode - either Blufi or AP mode
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    blufi_start();
#else
    // Fallback to AP mode for configuration
    wifi_manager_start_ap();
#endif

    // Notify application about the state change
    Application::GetInstance().OnNetworkStateChanged(
        Application::NetworkState::kConfigurationMode);

    ESP_LOGI(TAG, "Entered WiFi configuration mode due to timeout");
}

void WifiBoard::StartWifiConfigMode() {
    ESP_LOGI(TAG, "Starting Wi-Fi configuration mode");

    // Set the application state to configuring mode
    auto& app = Application::GetInstance();
    app.SetState(Application::State::kConfiguring);

    // Get display instance for user feedback
    auto disp = Board::GetInstance().GetDisplay();

    // Clear display and show configuration start message
    disp->Clear();
    disp->SetCursor(0, 0);
    disp->Print(lang_config_wifi_config_mode);
    disp->Display();

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Bluetooth Low Energy provisioning via Blufi
    ESP_LOGI(TAG, "Starting Blufi provisioning");
    disp->SetCursor(0, 56);
    disp->Print(lang_config_blufi_mode);
    disp->Display();

    // Initialize and start Blufi service
    blufi_init();

#elif defined(CONFIG_USE_ACOUSTIC_PROVISIONING)
    // Acoustic provisioning through audio input
    ESP_LOGI(TAG, "Starting acoustic provisioning");
    disp->SetCursor(0, 56);
    disp->Print(lang_config_acoustic_mode);
    disp->Display();

    // Initialize AFSK demodulator for acoustic provisioning
    afsk_demod_init();

#else
    // Default hotspot-based configuration
    ESP_LOGI(TAG, "Starting hotspot-based configuration");
    disp->SetCursor(0, 56);
    disp->Print(lang_config_hotspot_mode);
    disp->Display();

    // Start WiFi manager for hotspot configuration
    wifi_manager_start();

    // Show SSID and password information if available
    std::string ssid = ssid_manager_get_ap_ssid();
    std::string password = ssid_manager_get_ap_password();

    if (!ssid.empty()) {
        disp->SetCursor(0, 72);
        disp->Print("SSID: ");
        disp->Print(ssid.c_str());
        disp->Display();
    }

    if (!password.empty() && password != "") {
        disp->SetCursor(0, 88);
        disp->Print("PWD: ");
        disp->Print(password.c_str());
        disp->Display();
    }
#endif

    // Additional user instructions
    disp->SetCursor(0, 104);
    disp->Print(lang_config_follow_instructions);
    disp->Display();

    ESP_LOGI(TAG, "Wi-Fi configuration mode started successfully");
}

void WifiBoard::EnterWifiConfigMode() {
    ESP_LOGI(TAG, "Entering Wi-Fi configuration mode");

    // Get display instance for notifications
    auto disp = Board::GetInstance().GetDisplay();
    if (disp) {
        // Display notification about entering config mode
        disp->Clear();
        disp->SetFont(Font::MEDIUM);
        disp->DrawString(0, 0, ICON_WIFI " " + lang_config.wifi_config_mode);
        disp->DrawString(0, 20, lang_config.please_connect_to_ap);
        disp->DrawString(0, 40, "AP: " + Settings::GetInstance().GetDeviceName());
        disp->Display();
    }

    // Validate current state - check if already in config mode
    if (wifi_manager_is_started()) {
        ESP_LOGW(TAG, "Wi-Fi manager already running");
        return;
    }

    // Gracefully shut down active audio/communication processes
    // Stop AFSK demodulation if active
    if (afsk_demod_is_running()) {
        ESP_LOGI(TAG, "Stopping AFSK demodulator");
        afsk_demod_stop();
    }

    // Stop any other active communication processes
    Application::GetInstance().SuspendActiveTasks();

    // Disconnect from current Wi-Fi network if connected
    if (wifi_station_is_connected()) {
        ESP_LOGI(TAG, "Disconnecting from current Wi-Fi network");
        wifi_station_disconnect();
        vTaskDelay(pdMS_TO_TICKS(1000)); // Allow time for disconnection
    }

    // Reset network interfaces
    esp_network_deinit();

    // Start Wi-Fi configuration process
    ESP_LOGI(TAG, "Starting Wi-Fi manager");

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Use Blufi provisioning if configured
    blufi_start_provisioning();
#else
    // Use standard Wi-Fi manager
    wifi_manager_start();
#endif

    // Update system info
    SystemInfo::GetInstance().SetWifiConfigMode(true);

    ESP_LOGI(TAG, "Wi-Fi configuration mode started successfully");
}

esp_network_interface_t* WifiBoard::GetNetwork()
{
    static wifi_station_t* network_instance = nullptr;

    if (network_instance == nullptr) {
        // Initialize the network instance if not already created
        network_instance = wifi_station_get_instance();

        if (network_instance == nullptr) {
            ESP_LOGE(TAG, "Failed to get network instance");
            return nullptr;
        }
    }

    return reinterpret_cast<esp_network_interface_t*>(network_instance);
}

uint16_t WifiBoard::GetNetworkStateIcon() {
    // Check if in configuration/provisioning mode
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    if (Blufi::IsProvisioningActive()) {
        return FA_WIFI_CONFIG; // Or appropriate config mode icon
    }
#endif

    // Check WiFi connection status
    wifi_manager_state_t wifi_state = wifi_manager_get_state();

    switch (wifi_state) {
        case WIFI_MANAGER_STATE_IDLE:
        case WIFI_MANAGER_STATE_DISCONNECTED:
            return FA_WIFI_OFF; // Disconnected icon

        case WIFI_MANAGER_STATE_CONNECTING:
            return FA_WIFI_SPINNER; // Connecting/rotating icon

        case WIFI_MANAGER_STATE_CONNECTED:
            {
                // Get RSSI to determine signal strength
                int8_t rssi = wifi_station_get_rssi();

                // Determine signal strength level
                if (rssi >= -50) {
                    return FA_WIFI_STRONG; // Strong signal
                } else if (rssi >= -70) {
                    return FA_WIFI_FAIR;   // Fair signal
                } else if (rssi >= -80) {
                    return FA_WIFI_WEAK;   // Weak signal
                } else {
                    return FA_WIFI_POOR;   // Very poor signal
                }
            }

        default:
            return FA_WIFI_UNKNOWN; // Unknown state
    }
}

std::string WifiBoard::GetBoardJson() {
    std::string json = "{";

    // Add basic board information
    json += "\"type\":\"wifi\",";
    json += "\"name\":\"" + std::string(SystemInfo::GetDeviceName()) + "\",";

    // Add MAC address
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X", 
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    json += "\"mac\":\"" + std::string(mac_str) + "\"";

    // Check if we're in normal mode (not configuration mode) and add WiFi details
    if (!wifi_manager_is_in_config_mode()) {
        wifi_ap_record_t ap_info;
        if (esp_wifi_sta_get_ap_info(&ap_info) == ESP_OK) {
            // Add SSID
            json += ",\"ssid\":\"" + std::string((char*)ap_info.ssid) + "\"";

            // Add RSSI
            json += ",\"rssi\":" + std::to_string(ap_info.rssi);

            // Add channel
            json += ",\"channel\":" + std::to_string(ap_info.primary);

            // Add IP address if connected
            tcpip_adapter_ip_info_t ip_info;
            if (tcpip_adapter_get_ip_info(TCPIP_ADAPTER_IF_STA, &ip_info) == ESP_OK) {
                char ip_str[16];
                snprintf(ip_str, sizeof(ip_str), IPSTR, IP2STR(&ip_info.ip));
                json += ",\"ip\":\"" + std::string(ip_str) + "\"";
            }
        }
    }

    json += "}";
    return json;
}

void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level) {
    wifi_ps_type_t wifiPsLevel;

    // Map general power save levels to WiFi specific levels
    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            wifiPsLevel = WIFI_PS_MIN_MODEM;
            break;
        case PowerSaveLevel::BALANCED:
            wifiPsLevel = WIFI_PS_MAX_MODEM;
            break;
        case PowerSaveLevel::PERFORMANCE:
            wifiPsLevel = WIFI_PS_NONE;
            break;
        default:
            ESP_LOGW(TAG, "Unknown power save level, using balanced mode");
            wifiPsLevel = WIFI_PS_MAX_MODEM;
            break;
    }

    // Apply the power save setting through WiFi manager
    auto wifiManager = WifiManager::GetInstance();
    if (wifiManager) {
        esp_err_t result = wifiManager->SetPowerSaveMode(wifiPsLevel);
        if (result != ESP_OK) {
            ESP_LOGE(TAG, "Failed to set WiFi power save level: %s", esp_err_to_name(result));
        } else {
            ESP_LOGI(TAG, "WiFi power save level set to %d", static_cast<int>(wifiPsLevel));
        }
    } else {
        ESP_LOGE(TAG, "WiFi manager instance not available");
    }
}

std::string WifiBoard::GetDeviceStatusJson() {
    std::string json = "{";
    char buffer[1024];

    // Audio speaker volume - assuming Settings class has this
    int volume = Settings::Get()->GetVolume();
    json += "\"audio_volume\":" + std::to_string(volume) + ",";

    // Screen brightness and theme
    auto& display = Board::GetInstance().GetDisplay();
    int brightness = display.GetBrightness();
    // Assuming theme is stored in settings
    std::string theme = Settings::Get()->GetThemeName();
    json += "\"screen_brightness\":" + std::to_string(brightness) + ",";
    json += "\"screen_theme\":\"" + theme + "\",";

    // Battery level and charging state
    int battery_level = SystemInfo::GetBatteryLevel();
    bool is_charging = SystemInfo::IsCharging();
    json += "\"battery_level\":" + std::to_string(battery_level) + ",";
    json += "\"is_charging\":" + std::string(is_charging ? "true" : "false") + ",";

    // WiFi network details (SSID and signal strength)
    std::string ssid = "disconnected";
    int rssi = -100;

    wifi_ap_record_t ap_info;
    esp_err_t err = esp_wifi_sta_get_ap_info(&ap_info);
    if (err == ESP_OK) {
        ssid = reinterpret_cast<const char*>(ap_info.ssid);
        rssi = ap_info.rssi;
    } else if (err == ESP_ERR_WIFI_NOT_CONNECT) {
        ssid = "not_connected";
    }

    // Escape quotes in SSID for JSON
    std::string escaped_ssid = ssid;
    size_t pos = 0;
    while ((pos = escaped_ssid.find("\"", pos)) != std::string::npos) {
        escaped_ssid.replace(pos, 1, "\\\"");
        pos += 2;
    }

    json += "\"wifi_ssid\":\"" + escaped_ssid + "\",";
    json += "\"wifi_rssi\":" + std::to_string(rssi) + ",";

    // Chip temperature
    float temperature = SystemInfo::GetChipTemperature();
    snprintf(buffer, sizeof(buffer), "%.2f", temperature);
    json += "\"chip_temperature\":" + std::string(buffer);

    json += "}";

    return json;
}

