    }
}

SingleLed::SingleLed(gpio_num_t gpio)
{
    // Initialize member variables
    this->gpio = gpio;
    this->blink_count = 0;
    this->is_blinking = false;
    this->current_brightness = DEFAULT_BRIGHTNESS;

    // Configure LED strip with RMT
    led_strip_config_t strip_config = {};
    strip_config.strip_gpio_num = gpio;
    strip_config.max_leds = 1;  // Single LED
    strip_config.led_pixel_format = LED_PIXEL_FORMAT_GRB;
    strip_config.led_model = LED_MODEL_WS2812;
    strip_config.flags.invert_out = false;

    // RMT configuration
    led_strip_rmt_config_t rmt_config = {};
    rmt_config.resolution_hz = 10 * 1000 * 1000; // 10MHz resolution
    rmt_config.flags.with_dma = false;

    // Install LED strip driver
    ESP_ERROR_CHECK(led_strip_new_rmt_device(&strip_config, &rmt_config, &this->led_strip));

    // Clear the LED (turn off)
    this->led_strip->clear(this->led_strip, 100);

    // Initialize timer for blinking functionality
    const esp_timer_create_args_t timer_args = {
        .callback = &SingleLed::timer_callback,
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
        .name = "led_blink_timer",
        .skip_unhandled_events = false
    };

    ESP_ERROR_CHECK(esp_timer_create(&timer_args, &this->blink_timer));

    ESP_LOGI(TAG, "Single LED initialized on GPIO %d", gpio);
}

SingleLed::~SingleLed()
{
    // Stop the blink timer if it's running
    if (blink_timer_handle != nullptr) {
        esp_timer_stop(blink_timer_handle);
        esp_timer_delete(blink_timer_handle);
        blink_timer_handle = nullptr;
    }

    // Deallocate LED strip resource if it exists
    if (led_strip != nullptr) {
        // Turn off the LED before deallocating
        led_strip->clear(led_strip, 100);
        // Free the LED strip resource
        led_strip->del(led_strip);
        led_strip = nullptr;
    }
}

void SingleLed::SetColor(uint8_t r, uint8_t g, uint8_t b)
{
    // Store the RGB color values in internal member variables
    this->red = r;
    this->green = g;
    this->blue = b;

    // Update internal state to indicate color has been set
    this->color_set = true;
}

void SingleLed::TurnOn()
{
    std::lock_guard<std::mutex> lock(mutex_);

    // Stop any ongoing blink timer
    if (blinkTimer_ != nullptr) {
        esp_timer_stop(blinkTimer_);
    }

    // Set the LED to configured RGB values
    // Assuming there are rgb_ member variables or similar configuration
    // and a method to set the LED hardware
    SetHardwareLed(rgb_.r, rgb_.g, rgb_.b);

    // Refresh the LED strip to display the change immediately
    Refresh();

    // Update internal state to indicate LED is on
    isOn_ = true;
}

void SingleLed::TurnOff()
{
    // Acquire mutex lock for thread safety
    std::lock_guard<std::mutex> lock(m_mutex);

    // Stop any active blinking timer
    if (m_blinkTimer != nullptr) {
        esp_timer_stop(m_blinkTimer);
    }

    // Check if LED strip is initialized before accessing it
    if (m_ledStrip != nullptr) {
        // Clear the LED strip state (set all LEDs to off)
        m_ledStrip->clear();

        // Set brightness to 0 or turn off the specific LED
        m_ledStrip->set_pixel(0, 0, 0, 0); // RGB values set to 0

        // Refresh the LED strip to apply changes
        m_ledStrip->refresh();
    }

    // Update internal state
    m_isOn = false;
    m_blinkCount = 0;
    m_currentBlinkState = false;
}

void SingleLed::StartBlinkTask(int num_blinks, int interval_ms)
{
    // Check if LED is initialized (exit early if not)
    if (!this->initialized) {
        ESP_LOGW(TAG, "LED not initialized, cannot start blink task");
        return;
    }

    // Stop any existing blink task/timer
    if (this->blink_timer != nullptr) {
        esp_timer_stop(this->blink_timer);
        esp_timer_delete(this->blink_timer);
        this->blink_timer = nullptr;
    }

    // Store blink parameters
    this->blink_count = 0;
    this->total_blinks = num_blinks;
    this->blink_interval = interval_ms;
    this->current_state = false; // Start with LED off

    // Configure timer arguments
    esp_timer_create_args_t timer_args = {};
    timer_args.callback = [](void* arg) {
        SingleLed* led = static_cast<SingleLed*>(arg);
        led->BlinkTimerCallback();
    };
    timer_args.arg = this;
    timer_args.name = "led_blink_timer";

    // Create and start the timer
    esp_err_t err = esp_timer_create(&timer_args, &this->blink_timer);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create blink timer: %s", esp_err_to_name(err));
        return;
    }

    // Start timer with interval in microseconds
    uint64_t interval_us = static_cast<uint64_t>(interval_ms) * 1000;
    err = esp_timer_start_periodic(this->blink_timer, interval_us);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start blink timer: %s", esp_err_to_name(err));
        esp_timer_delete(this->blink_timer);
        this->blink_timer = nullptr;
        return;
    }

    ESP_LOGI(TAG, "Started blink task: %d blinks, %d ms interval", num_blinks, interval_ms);
}

void SingleLed::OnBlinkTimer()
{
    // Acquire mutex for thread-safe access
    xSemaphoreTake(m_mutex, portMAX_DELAY);

    // Toggle LED state
    m_state = !m_state;
    gpio_set_level(m_gpio, m_state);

    // Handle blink count decrement
    if (m_blink_count != BLINK_INFINITE && m_blink_count > 0) {
        m_blink_count--;

        // Stop timer when blink sequence is complete
        if (m_blink_count == 0) {
            if (m_timer) {
                esp_timer_stop(m_timer);
            }
        }
    }

    // Release mutex
    xSemaphoreGive(m_mutex);
}

void SingleLed::OnStateChanged()
{
    // Stop any ongoing blink pattern first
    ledc_stop(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, 0);

    switch (Application::GetCurrentState()) {
        case Application::State::STARTING:
            // Slow blinking blue - system booting up
            SetColor(0, 0, DEFAULT_BRIGHTNESS); // Blue
            Blink(500, 500, BLINK_INFINITE);
            break;

        case Application::State::WIFI_CONFIG:
            // Fast blinking cyan - WiFi configuration mode
            SetColor(0, DEFAULT_BRIGHTNESS, DEFAULT_BRIGHTNESS); // Cyan
            Blink(200, 200, BLINK_INFINITE);
            break;

        case Application::State::IDLE:
            // Solid green - system ready and idle
            SetColor(0, HIGH_BRIGHTNESS, 0); // Green
            SetSolid();
            break;

        case Application::State::CONNECTING:
            // Rapid blinking yellow - attempting connection
            SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS, 0); // Yellow
            Blink(100, 100, BLINK_INFINITE);
            break;

        case Application::State::LISTENING:
            // Pulsing blue - waiting for voice input
            SetColor(0, 0, HIGH_BRIGHTNESS); // Blue
            Pulse(1000);
            break;

        case Application::State::SPEAKING:
            // Solid white - actively speaking
            SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS, HIGH_BRIGHTNESS); // White
            SetSolid();
            break;

        case Application::State::UPGRADING:
            // Fast alternating red/yellow - firmware upgrade in progress
            SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS, 0); // Yellow
            Blink(50, 50, BLINK_INFINITE);
            break;

        case Application::State::ACTIVATING:
            // Fast double blink green - activation sequence
            SetColor(0, HIGH_BRIGHTNESS, 0); // Green
            Blink(100, 100, 2); // Two quick blinks
            break;

        default:
            // Unknown state - slow red blinking
            SetColor(HIGH_BRIGHTNESS, 0, 0); // Red
            Blink(1000, 1000, BLINK_INFINITE);
            break;
    }
}

MqttProtocol::MqttProtocol() {
    // Initialize the network interface
    auto network = Board::GetInstance().GetNetwork();

    // Create event group for synchronization
    mqtt_event_group = xEventGroupCreate();

    // Initialize reconnect timer
    reconnect_timer = nullptr;

    // Initialize MQTT client configuration
    esp_mqtt_client_config_t mqtt_cfg = {};
    mqtt_cfg.host = Settings::GetInstance().GetMqttBrokerHost();
    mqtt_cfg.port = Settings::GetInstance().GetMqttBrokerPort();
    mqtt_cfg.username = Settings::GetInstance().GetMqttUsername();
    mqtt_cfg.password = Settings::GetInstance().GetMqttPassword();
    mqtt_cfg.client_id = Settings::GetInstance().GetDeviceId();

    // Create MQTT client
    client = esp_mqtt_client_init(&mqtt_cfg);

    // Register MQTT event handler
    esp_mqtt_client_register_event(client, ESP_EVENT_ANY_ID, mqtt_event_handler, this);

    // Initialize reconnection state
    reconnect_attempts = 0;
    max_reconnect_attempts = Settings::GetInstance().GetMqttMaxReconnectAttempts();
    reconnect_interval_ms = Settings::GetInstance().GetMqttReconnectIntervalMs();

    // Create reconnect timer for periodic reconnection attempts
    reconnect_timer = xTimerCreate(
        "MQTT_Reconnect_Timer",
        pdMS_TO_TICKS(reconnect_interval_ms),
        pdFALSE, // One-shot timer, will be restarted as needed
        this,
        reconnect_timer_callback
    );

    ESP_LOGI(TAG, "MQTT Protocol initialized");
}

// Static event handler callback
void MqttProtocol::mqtt_event_handler(void* handler_args, esp_event_base_t base, int32_t event_id, void* event_data) {
    MqttProtocol* protocol = static_cast<MqttProtocol*>(handler_args);
    esp_mqtt_event_handle_t event = static_cast<esp_mqtt_event_handle_t>(event_data);

    switch (event_id) {
        case MQTT_EVENT_CONNECTED:
            ESP_LOGI(TAG, "MQTT Connected");
            xEventGroupSetBits(protocol->mqtt_event_group, MQTT_CONNECTED_BIT);
            protocol->reconnect_attempts = 0;
            break;

        case MQTT_EVENT_DISCONNECTED:
            ESP_LOGW(TAG, "MQTT Disconnected");
            xEventGroupClearBits(protocol->mqtt_event_group, MQTT_CONNECTED_BIT);
            // Schedule reconnection attempt
            if (protocol->reconnect_timer) {
                xTimerStart(protocol->reconnect_timer, 0);
            }
            break;

        case MQTT_EVENT_DATA:
            ESP_LOGD(TAG, "MQTT Data received");
            protocol->handle_incoming_message(event);
            break;

        default:
            break;
    }
}

// Reconnect timer callback
void MqttProtocol::reconnect_timer_callback(TimerHandle_t xTimer) {
    MqttProtocol* protocol = static_cast<MqttProtocol*>(pvTimerGetTimerID(xTimer));

    // Check if we're in a state where reconnection is appropriate
    if (!Application::GetInstance().IsInActiveOperation()) {
        // Attempt to reconnect
        esp_mqtt_client_start(protocol->client);
        protocol->reconnect_attempts++;

        // Reschedule if max attempts not reached
        if (protocol->reconnect_attempts < protocol->max_reconnect_attempts) {
            xTimerStart(protocol->reconnect_timer, 0);
        } else {
            ESP_LOGE(TAG, "Max MQTT reconnection attempts reached");
        }
    } else {
        // Device is busy, reschedule reconnection attempt
        xTimerStart(protocol->reconnect_timer, 0);
    }
}

MqttProtocol::~MqttProtocol()
{
    // Mark instance as inactive first to prevent new operations
    m_active = false;

    // Stop the MQTT client if it's running
    if (m_mqtt_client) {
        esp_mqtt_client_stop(m_mqtt_client);
    }

    // Stop and delete the reconnect timer
    if (m_reconnect_timer) {
        esp_timer_stop(m_reconnect_timer);
        esp_timer_delete(m_reconnect_timer);
        m_reconnect_timer = nullptr;
    }

    // Delete the MQTT client instance
    if (m_mqtt_client) {
        esp_mqtt_client_destroy(m_mqtt_client);
        m_mqtt_client = nullptr;
    }

    // Release the event group
    if (m_event_group) {
        vEventGroupDelete(m_event_group);
        m_event_group = nullptr;
    }

    // Reset UDP resources if any
    if (m_udp_socket >= 0) {
        close(m_udp_socket);
        m_udp_socket = -1;
    }

    // Clear any pending callbacks or references
    m_connection_callback = nullptr;
    m_data_callback = nullptr;
}

bool MqttProtocol::StartMqttClient(bool enableReconnect) {
    // Get MQTT configuration from settings
    const auto& settings = Settings::GetInstance();
    const auto& mqttConfig = settings.GetMqttConfig();

    // Check if MQTT is enabled
    if (!mqttConfig.enabled) {
        ESP_LOGI(TAG, "MQTT is disabled in settings");
        return false;
    }

    // Validate required configuration
    if (mqttConfig.brokerUrl.empty() || mqttConfig.clientId.empty()) {
        ESP_LOGE(TAG, "Invalid MQTT configuration: missing broker URL or client ID");
        return false;
    }

    ESP_LOGI(TAG, "Initializing MQTT client for broker: %s", mqttConfig.brokerUrl.c_str());

    try {
        // Initialize MQTT client configuration
        esp_mqtt_client_config_t mqtt_cfg = {};

        // Set broker URL
        mqtt_cfg.broker.address.uri = mqttConfig.brokerUrl.c_str();
        mqtt_cfg.credentials.client_id = mqttConfig.clientId.c_str();

        // Set credentials if provided
        if (!mqttConfig.username.empty()) {
            mqtt_cfg.credentials.username = mqttConfig.username.c_str();
        }
        if (!mqttConfig.password.empty()) {
            mqtt_cfg.credentials.authentication.password = mqttConfig.password.c_str();
        }

        // Set LWT (Last Will and Testament)
        if (!mqttConfig.lwtTopic.empty()) {
            mqtt_cfg.session.last_will.topic = mqttConfig.lwtTopic.c_str();
            mqtt_cfg.session.last_will.msg = mqttConfig.lwtMessage.c_str();
            mqtt_cfg.session.last_will.qos = mqttConfig.lwtQos;
            mqtt_cfg.session.last_will.retain = mqttConfig.lwtRetain;
        }

        // Create MQTT client
        mqttClient = esp_mqtt_client_init(&mqtt_cfg);
        if (!mqttClient) {
            ESP_LOGE(TAG, "Failed to initialize MQTT client");
            return false;
        }

        // Register event handler
        esp_mqtt_client_register_event(mqttClient, MQTT_EVENT_ANY, 
                                     MqttProtocol::MqttEventHandler, this);

        // Start MQTT client
        esp_err_t err = esp_mqtt_client_start(mqttClient);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to start MQTT client: %s", esp_err_to_name(err));
            esp_mqtt_client_destroy(mqttClient);
            mqttClient = nullptr;
            return false;
        }

        ESP_LOGI(TAG, "MQTT client started successfully");
        reconnectEnabled = enableReconnect;
        isConnected = true;

        return true;

    } catch (const std::exception& e) {
        ESP_LOGE(TAG, "Exception during MQTT client initialization: %s", e.what());
        if (mqttClient) {
            esp_mqtt_client_destroy(mqttClient);
            mqttClient = nullptr;
        }
        return false;
    }
}

// Static event handler wrapper
void MqttProtocol::MqttEventHandler(void* handler_args, esp_event_base_t base, 
                                   int32_t event_id, void* event_data) {
    MqttProtocol* protocol = static_cast<MqttProtocol*>(handler_args);
    if (protocol) {
        protocol->HandleMqttEvent(event_id, static_cast<esp_mqtt_event_handle_t>(event_data));
    }
}

// Member function to handle MQTT events
void MqttProtocol::HandleMqttEvent(int32_t event_id, esp_mqtt_event_handle_t event) {
    switch (event_id) {
        case MQTT_EVENT_CONNECTED:
            ESP_LOGI(TAG, "MQTT connected");
            isConnected = true;
            OnMqttConnected();
            break;

        case MQTT_EVENT_DISCONNECTED:
            ESP_LOGW(TAG, "MQTT disconnected");
            isConnected = false;
            OnMqttDisconnected();
            if (reconnectEnabled) {
                ScheduleReconnect();
            }
            break;

        case MQTT_EVENT_SUBSCRIBED:
            ESP_LOGI(TAG, "MQTT subscribed to topic, msg_id=%d", event->msg_id);
            break;

        case MQTT_EVENT_UNSUBSCRIBED:
            ESP_LOGI(TAG, "MQTT unsubscribed from topic, msg_id=%d", event->msg_id);
            break;

        case MQTT_EVENT_PUBLISHED:
            ESP_LOGD(TAG, "MQTT published, msg_id=%d", event->msg_id);
            break;

        case MQTT_EVENT_DATA:
            ESP_LOGD(TAG, "MQTT received data, topic=%.*s, data=%.*s",
                    event->topic_len, event->topic,
                    event->data_len, event->data);
            HandleIncomingMessage(event);
            break;

        case MQTT_EVENT_ERROR:
            ESP_LOGE(TAG, "MQTT error encountered");
            if (event->error_handle) {
                LogMqttError(event->error_handle);
            }
            break;

        default:
            ESP_LOGD(TAG, "MQTT event id: %d", event_id);
            break;
    }
}

// Handle incoming MQTT messages
void MqttProtocol::HandleIncomingMessage(esp_mqtt_event_handle_t event) {
    try {
        // Parse topic and data
        std::string topic(event->topic, event->topic_len);
        std::string payload(event->data, event->data_len);

        // Parse JSON payload
        cJSON* json = cJSON_Parse(payload.c_str());
        if (!json) {
            ESP_LOGW(TAG, "Failed to parse JSON payload from topic: %s", topic.c_str());
            return;
        }

        // Handle different message types based on topic or payload content
        ProcessJsonMessage(topic, json);

        cJSON_Delete(json);

    } catch (const std::exception& e) {
        ESP_LOGE(TAG, "Exception handling MQTT message: %s", e.what());
    }
}

// Process JSON message and trigger appropriate actions
void MqttProtocol::ProcessJsonMessage(const std::string& topic, cJSON* json) {
    // Example implementation - would need to be adapted based on actual requirements

    // Check for session management commands
    cJSON* sessionCmd = cJSON_GetObjectItem(json, "session");
    if (sessionCmd && cJSON_IsString(sessionCmd)) {
