bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    if (!packet || packet->data == nullptr || packet->size == 0) {
        ESP_LOGE(TAG, "Invalid audio packet");
        return false;
    }

    // Thread-safe access to UDP channel
    std::lock_guard<std::mutex> lock(udp_mutex_);

    // Update sequence number
    uint32_t sequence_number = ++sequence_number_;

    // Get current timestamp
    uint64_t timestamp = static_cast<uint64_t>(esp_timer_get_time());

    // Create dynamic nonce for AES-CTR
    uint8_t nonce[16] = {0};
    uint32_t packet_size = htonl(packet->size);
    uint64_t ts = htobe64(timestamp);
    uint32_t seq = htonl(sequence_number);

    memcpy(nonce, &packet_size, sizeof(packet_size));
    memcpy(nonce + 4, &ts, sizeof(ts));
    memcpy(nonce + 12, &seq, sizeof(seq));

    // Prepare encrypted buffer
    std::vector<uint8_t> encrypted_data(packet->size);

    // Perform AES-CTR encryption
    mbedtls_aes_context aes_ctx;
    mbedtls_aes_init(&aes_ctx);

    // Initialize AES key (assuming key is stored in class member)
    if (mbedtls_aes_setkey_enc(&aes_ctx, encryption_key_, 128) != 0) {
        ESP_LOGE(TAG, "Failed to set AES key");
        mbedtls_aes_free(&aes_ctx);
        return false;
    }

    // Initialize counter for CTR mode
    uint8_t stream_block[16] = {0};
    size_t nc_off = 0;

    // Encrypt the audio data
    int ret = mbedtls_aes_crypt_ctr(&aes_ctx, packet->size, &nc_off, nonce, 
                                   stream_block, packet->data, encrypted_data.data());

    mbedtls_aes_free(&aes_ctx);

    if (ret != 0) {
        ESP_LOGE(TAG, "AES encryption failed: %d", ret);
        return false;
    }

    // Prepare UDP packet header + encrypted data
    AudioUdpPacket udp_packet;
    udp_packet.sequence_number = sequence_number;
    udp_packet.timestamp = timestamp;
    udp_packet.data_size = packet->size;
    udp_packet.encrypted_data = std::move(encrypted_data);

    // Transmit over UDP
    if (!network_ || !network_->IsConnected()) {
        ESP_LOGE(TAG, "Network not available for UDP transmission");
        return false;
    }

    // Serialize packet for transmission
    std::vector<uint8_t> tx_buffer(sizeof(AudioUdpHeader) + packet->size);
    AudioUdpHeader header;
    header.sequence_number = htonl(sequence_number);
    header.timestamp = htobe64(timestamp);
    header.data_size = htonl(packet->size);

    memcpy(tx_buffer.data(), &header, sizeof(header));
    memcpy(tx_buffer.data() + sizeof(header), udp_packet.encrypted_data.data(), packet->size);

    // Send via UDP
    ssize_t sent_bytes = network_->SendUdpData(tx_buffer.data(), tx_buffer.size());

    if (sent_bytes != static_cast<ssize_t>(tx_buffer.size())) {
        ESP_LOGE(TAG, "UDP transmission failed. Sent %d of %d bytes", 
                 static_cast<int>(sent_bytes), static_cast<int>(tx_buffer.size()));
        return false;
    }

    ESP_LOGD(TAG, "Audio packet sent successfully. Seq: %u, Size: %u", 
             sequence_number, packet->size);

    return true;
}

void MqttProtocol::CloseAudioChannel() {
    ESP_LOGI(TAG, "Closing audio channel");

    // Reset UDP connection
    if (audio_udp_socket_ >= 0) {
        close(audio_udp_socket_);
        audio_udp_socket_ = -1;
    }

    // Send goodbye message to server
    if (network_ && network_->IsConnected()) {
        std::string goodbye_message = "AUDIO_BYE";
        mqtt_client_->publish(audio_topic_ + "/control", goodbye_message.c_str(), 
                             goodbye_message.length(), 1, false);
        ESP_LOGD(TAG, "Sent goodbye message to server");
    }

    // Reset audio session state
    is_audio_streaming_ = false;
    audio_server_port_ = 0;
    memset(&audio_server_addr_, 0, sizeof(audio_server_addr_));

    // Trigger callback notification
    if (audio_channel_callback_) {
        audio_channel_callback_(AudioChannelEvent::CLOSED, nullptr);
    }

    ESP_LOGI(TAG, "Audio channel closed successfully");
}

bool MqttProtocol::OpenAudioChannel() {
    ESP_LOGI(TAG, "Opening audio channel");

    // Get network instance
    auto network = Board::GetInstance().GetNetwork();
    if (!network) {
        ESP_LOGE(TAG, "Failed to get network instance");
        return false;
    }

    // Check if we're connected to WiFi/network
    if (!network->IsConnected()) {
        ESP_LOGE(TAG, "Network not connected");
        return false;
    }

    // Connect to MQTT broker
    Settings& settings = Settings::GetInstance();
    std::string mqtt_server = settings.GetMqttServer();
    uint16_t mqtt_port = settings.GetMqttPort();
    std::string client_id = settings.GetDeviceId();

    ESP_LOGI(TAG, "Connecting to MQTT broker %s:%d", mqtt_server.c_str(), mqtt_port);

    // Initialize MQTT connection (this would typically use esp-mqtt library)
    // For now, assuming there's an MQTT client member variable
    if (!mqtt_client_) {
        ESP_LOGE(TAG, "MQTT client not initialized");
        return false;
    }

    // Connect to MQTT server
    esp_mqtt_client_config_t mqtt_cfg = {};
    mqtt_cfg.host = mqtt_server.c_str();
    mqtt_cfg.port = mqtt_port;
    mqtt_cfg.client_id = client_id.c_str();

    // Configure authentication if needed
    std::string username = settings.GetMqttUsername();
    std::string password = settings.GetMqttPassword();
    if (!username.empty()) {
        mqtt_cfg.username = username.c_str();
        if (!password.empty()) {
            mqtt_cfg.password = password.c_str();
        }
    }

    // Set up TLS if required
    if (settings.IsMqttTlsEnabled()) {
        mqtt_cfg.transport = MQTT_TRANSPORT_OVER_SSL;
        // Configure certificate paths if needed
    }

    // Start MQTT connection
    esp_mqtt_client_start(mqtt_client_);

    // Wait for connection with timeout
    int timeout_ms = 5000;
    int elapsed = 0;
    const int poll_interval = 100;

    while (elapsed < timeout_ms && !is_mqtt_connected_) {
        vTaskDelay(pdMS_TO_TICKS(poll_interval));
        elapsed += poll_interval;
    }

    if (!is_mqtt_connected_) {
        ESP_LOGE(TAG, "MQTT connection timeout");
        return false;
    }

    ESP_LOGI(TAG, "MQTT connected successfully");

    // Subscribe to audio control topic
    std::string audio_control_topic = "device/" + client_id + "/audio/control";
    esp_mqtt_client_subscribe(mqtt_client_, audio_control_topic.c_str(), 1);

    // Send hello message to initiate audio session
    std::string hello_topic = "device/" + client_id + "/audio/hello";
    std::string hello_payload = "{\"action\":\"open_channel\",\"timestamp\":" + 
                               std::to_string(esp_timer_get_time() / 1000) + "}";

    esp_mqtt_client_publish(mqtt_client_, hello_topic.c_str(), 
                           hello_payload.c_str(), hello_payload.length(), 1, 0);

    // Wait for server response
    elapsed = 0;
    timeout_ms = 10000; // 10 second timeout for handshake

    while (elapsed < timeout_ms && !audio_session_ready_) {
        vTaskDelay(pdMS_TO_TICKS(poll_interval));
        elapsed += poll_interval;
    }

    if (!audio_session_ready_) {
        ESP_LOGE(TAG, "Audio session handshake timeout");
        CloseAudioChannel();
        return false;
    }

    ESP_LOGI(TAG, "Audio session established");

    // Set up UDP socket for audio streaming
    udp_socket_ = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (udp_socket_ < 0) {
        ESP_LOGE(TAG, "Failed to create UDP socket");
        CloseAudioChannel();
        return false;
    }

    // Bind to local port for receiving audio packets
    struct sockaddr_in local_addr;
    memset(&local_addr, 0, sizeof(local_addr));
    local_addr.sin_family = AF_INET;
    local_addr.sin_port = htons(settings.GetAudioUdpPort());
    local_addr.sin_addr.s_addr = INADDR_ANY;

    if (bind(udp_socket_, (struct sockaddr*)&local_addr, sizeof(local_addr)) < 0) {
        ESP_LOGE(TAG, "Failed to bind UDP socket");
        CloseAudioChannel();
        return false;
    }

    // Set socket to non-blocking mode
    int flags = fcntl(udp_socket_, F_GETFL, 0);
    fcntl(udp_socket_, F_SETFL, flags | O_NONBLOCK);

    // Start audio receive task
    audio_running_ = true;
    BaseType_t ret = xTaskCreate(AudioReceiveTask, "AudioRecv", 4096, this, 5, &audio_task_handle_);
    if (ret != pdPASS) {
        ESP_LOGE(TAG, "Failed to create audio receive task");
        CloseAudioChannel();
        return false;
    }

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

// Helper task function for receiving audio packets
void MqttProtocol::AudioReceiveTask(void* pvParameters) {
    MqttProtocol* protocol = static_cast<MqttProtocol*>(pvParameters);
    const size_t buffer_size = 2048;
    uint8_t* buffer = new uint8_t[buffer_size];
    struct sockaddr_in source_addr;
    socklen_t source_addr_len = sizeof(source_addr);

    while (protocol->audio_running_) {
        ssize_t len = recvfrom(protocol->udp_socket_, buffer, buffer_size, 0,
                              (struct sockaddr*)&source_addr, &source_addr_len);

        if (len > 0) {
            // Decrypt the OPUS packet
            std::vector<uint8_t> decrypted_data;
            if (protocol->DecryptOpusPacket(buffer, len, decrypted_data)) {
                // Validate packet sequence
                if (protocol->ValidatePacketSequence(decrypted_data)) {
                    // Pass to audio callback
                    if (protocol->audio_callback_) {
                        protocol->audio_callback_(decrypted_data.data(), decrypted_data.size());
                    }
                } else {
                    ESP_LOGW(TAG, "Invalid packet sequence detected");
                }
            } else {
                ESP_LOGW(TAG, "Failed to decrypt audio packet");
            }
        } else if (len < 0 && errno != EAGAIN && errno != EWOULDBLOCK) {
            ESP_LOGW(TAG, "UDP receive error: %d", errno);
        }

        vTaskDelay(pdMS_TO_TICKS(1)); // Small delay to prevent busy looping
    }

    delete[] buffer;
    vTaskDelete(NULL);
}

bool MqttProtocol::DecryptOpusPacket(const uint8_t* encrypted_data, size_t data_len, 
                                    std::vector<uint8_t>& decrypted_data) {
    // Placeholder for actual decryption logic
    // This would typically involve AES decryption or similar
    // For now, just copy the data (assuming no encryption for demo)

    decrypted_data.resize(data_len);
