bool MqttProtocol::ValidatePacketSequence(const std::vector<uint8_t>& packet) {
    // Simple sequence validation - check if we have at least timestamp/header
    if (packet.size() < sizeof(uint32_t)) {
        return false;
    }

    // Extract sequence number (assuming first 4 bytes are sequence/timestamp)
    uint32_t seq_num = ntohl(*reinterpret_cast<const uint32_t*>(packet.data()));

    // Check for reasonable sequence progression
    if (seq_num <= last_packet_seq_ && last_packet_seq_ != 0) {
        // Allow for some out-of-order packets but flag significant issues
        if (last_packet_seq_ - seq_num > 100) {
            ESP_LOGW(TAG, "Significant sequence number regression: %u -> %u", last_packet_seq_, seq_num);
            return false;
        }
    }

    last_packet_seq_ = seq_num;
    return true;
}

void MqttProtocol::CloseAudioChannel() {
    audio_running_ = false;

    // Stop audio receive task
    if (audio_task_handle_) {
        vTaskDelete(audio_task_handle_);
        audio_task_handle_ = nullptr;
    }

    // Close UDP socket
    if (udp_socket_ >= 0) {
        close(udp_socket_);
        udp_socket_ = -1;
    }

    // Send close message via MQTT
    if (mqtt_client_ && is_mqtt_connected_) {
        Settings& settings = Settings::GetInstance();
        std::string client_id = settings.GetDeviceId();
        std::string close_topic = "device/" + client_id + "/audio/close";
        std::string close_payload = "{\"action\":\"close_channel\",\"timestamp\":" + 
                                   std::to_string(esp_timer_get_time() / 1000) + "}";

        esp_mqtt_client_publish(mqtt_client_, close_topic.c_str(), 
                               close_payload.c_str(), close_payload.length(), 1, 0);
    }

    last_packet_seq_ = 0;
    audio_session_ready_ = false;
}

std::string MqttProtocol::GetHelloMessage() {
    // Get device information
    auto& board = Board::GetInstance();
    auto network = board.GetNetwork();
    auto settings = Settings::GetInstance();

    // Get device capabilities
    bool hasAec = board.HasAecSupport();
    bool hasMcp = board.HasMcpSupport();

    // Get audio parameters from settings
    auto audioFormat = settings.GetAudioFormat();
    uint32_t sampleRate = settings.GetSampleRate();
    uint32_t frameDuration = settings.GetFrameDuration();

    // Get device ID and network info
    std::string deviceId = board.GetDeviceId();
    std::string localIp = network->GetLocalIpAddress();

    // Create JSON message
    char jsonBuffer[512];
    int len = snprintf(jsonBuffer, sizeof(jsonBuffer),
        "{"
        "\"type\":\"hello\","
        "\"deviceId\":\"%s\","
        "\"ip\":\"%s\","
        "\"capabilities\":{"
            "\"aec\":%s,"
            "\"mcp\":%s"
        "},"
        "\"audio\":{"
            "\"format\":\"%s\","
            "\"sampleRate\":%u,"
            "\"frameDuration\":%u"
        "}"
        "}",
        deviceId.c_str(),
        localIp.c_str(),
        hasAec ? "true" : "false",
        hasMcp ? "true" : "false",
        audioFormat.c_str(),
        sampleRate,
        frameDuration
    );

    if (len < 0 || len >= (int)sizeof(jsonBuffer)) {
        ESP_LOGE(TAG, "Failed to generate hello message - buffer too small");
        return "{}";
    }

    ESP_LOGI(TAG, "Generated hello message: %s", jsonBuffer);

    return std::string(jsonBuffer);
}

void MqttProtocol::ParseServerHello(const cJSON* json) {
    if (!json) {
        ESP_LOGE(TAG, "Invalid JSON received in server hello");
        return;
    }

    // Extract UDP transport settings
    cJSON* server_addr = cJSON_GetObjectItem(json, "server_addr");
    cJSON* server_port = cJSON_GetObjectItem(json, "server_port");
    cJSON* encryption_key = cJSON_GetObjectItem(json, "encryption_key");
    cJSON* nonce = cJSON_GetObjectItem(json, "nonce");

    if (server_addr && server_port && encryption_key && nonce) {
        // Configure UDP transport settings
        strncpy(udp_server_addr_, server_addr->valuestring, sizeof(udp_server_addr_) - 1);
        udp_server_addr_[sizeof(udp_server_addr_) - 1] = '\0';

        udp_server_port_ = server_port->valueint;

        // Handle encryption key (assuming base64 or hex encoded string)
        strncpy(encryption_key_, encryption_key->valuestring, sizeof(encryption_key_) - 1);
        encryption_key_[sizeof(encryption_key_) - 1] = '\0';

        // Handle nonce
        strncpy(nonce_, nonce->valuestring, sizeof(nonce_) - 1);
        nonce_[sizeof(nonce_) - 1] = '\0';

        ESP_LOGI(TAG, "UDP Server: %s:%d", udp_server_addr_, udp_server_port_);
    } else {
        ESP_LOGE(TAG, "Missing required UDP transport parameters in server hello");
        return;
    }

    // Extract audio parameters
    cJSON* sample_rate = cJSON_GetObjectItem(json, "sample_rate");
    cJSON* frame_duration = cJSON_GetObjectItem(json, "frame_duration");

    if (sample_rate && frame_duration) {
        audio_sample_rate_ = sample_rate->valueint;
        audio_frame_duration_ = frame_duration->valueint;

        ESP_LOGI(TAG, "Audio params: %d Hz, %d ms frames", audio_sample_rate_, audio_frame_duration_);
    } else {
        ESP_LOGW(TAG, "Missing audio parameters in server hello, using defaults");
        // Set default values if not provided
        audio_sample_rate_ = 16000;  // Default sample rate
        audio_frame_duration_ = 20;  // Default frame duration in ms
    }

    // Initialize AES encryption
    if (InitializeAesEncryption()) {
        ESP_LOGI(TAG, "AES encryption initialized successfully");
    } else {
        ESP_LOGE(TAG, "Failed to initialize AES encryption");
        return;
    }

    // Signal successful processing
    server_hello_processed_ = true;

    ESP_LOGI(TAG, "Server hello processed successfully, ready for secure UDP audio communication");
}

