uint8_t MqttProtocol::CharToHex(char c) {
    if (c >= '0' && c <= '9') {
        return c - '0';
    } else if (c >= 'A' && c <= 'F') {
        return c - 'A' + 10;
    } else if (c >= 'a' && c <= 'f') {
        return c - 'a' + 10;
    } else {
        return 0;
    }
}

std::string MqttProtocol::DecodeHexString(const std::string& hexString) {
    std::string result;

    // Check if the string has even length
    if (hexString.length() % 2 != 0) {
        ESP_LOGW(TAG, "Invalid hex string length: %d", hexString.length());
        return result;
    }

    // Process two characters at a time
    for (size_t i = 0; i < hexString.length(); i += 2) {
        // Extract two characters
        std::string byteString = hexString.substr(i, 2);

        // Validate that both characters are valid hex digits
        if (!isxdigit(byteString[0]) || !isxdigit(byteString[1])) {
            ESP_LOGW(TAG, "Invalid hex character at position %d", i);
            result.clear();
            return result;
        }

        // Convert hex string to byte
        char* endPtr;
        long byteValue = strtol(byteString.c_str(), &endPtr, 16);

        // Append the byte to result
        result.push_back(static_cast<char>(byteValue));
    }

    return result;
}

