bool Protocol::IsTimeout() const
{
    uint32_t current_time = esp_timer_get_time() / 1000000; // Convert microseconds to seconds
    uint32_t elapsed_time = current_time - last_incoming_message_time_;

    if (elapsed_time > 120) {
        ESP_LOGE(TAG, "Channel timeout: %lu seconds since last message", elapsed_time);
        return true;
    }

    return false;
}

