void WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (!packet || !IsConnected()) {
        ESP_LOGW(TAG, "Cannot send audio: invalid packet or not connected");
        return;
    }

    // Check if WebSocket is ready for sending
    if (xEventGroupGetBits(event_group_handle_) & WEBSOCKET_CONNECTED_BIT == 0) {
        ESP_LOGW(TAG, "WebSocket not connected, cannot send audio");
        return;
    }

    uint8_t* payload = nullptr;
    size_t payload_size = 0;

    // Format packet based on protocol version
    switch (negotiated_protocol_version_) {
        case PROTOCOL_VERSION_V2: {
            // V2 format: [header(4 bytes)][timestamp(4 bytes)][audio_data]
            payload_size = 4 + 4 + packet->data_size;
            payload = new uint8_t[payload_size];

            // Header: version + flags
            uint32_t header = htonl((PROTOCOL_VERSION_V2 << 24) | (AUDIO_PACKET_TYPE << 16));
            memcpy(payload, &header, 4);

            // Timestamp in milliseconds
            uint32_t timestamp = htonl(static_cast<uint32_t>(packet->timestamp_ms));
            memcpy(payload + 4, &timestamp, 4);

            // Audio data
            memcpy(payload + 8, packet->data.get(), packet->data_size);
            break;
        }

        case PROTOCOL_VERSION_V3: {
            // V3 format: [header(4 bytes)][timestamp(8 bytes)][payload_size(4 bytes)][audio_data]
            payload_size = 4 + 8 + 4 + packet->data_size;
            payload = new uint8_t[payload_size];

            // Header: version + flags
            uint32_t header = htonl((PROTOCOL_VERSION_V3 << 24) | (AUDIO_PACKET_TYPE << 16));
            memcpy(payload, &header, 4);

            // 64-bit timestamp
            uint64_t timestamp = htonll(static_cast<uint64_t>(packet->timestamp_ms));
            memcpy(payload + 4, &timestamp, 8);

            // Payload size
            uint32_t data_size = htonl(static_cast<uint32_t>(packet->data_size));
            memcpy(payload + 12, &data_size, 4);

            // Audio data
            memcpy(payload + 16, packet->data.get(), packet->data_size);
            break;
        }

        default: // Raw payload
        case PROTOCOL_VERSION_RAW: {
            // Raw format: just the audio data
            payload_size = packet->data_size;
            payload = new uint8_t[payload_size];
            memcpy(payload, packet->data.get(), packet->data_size);
            break;
        }
    }

    // Send the formatted packet
    esp_err_t result = websocket_send_binary(payload, payload_size);
    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to send audio packet: %s", esp_err_to_name(result));
        delete[] payload;
        return;
    }

    ESP_LOGD(TAG, "Sent audio packet: size=%d, timestamp=%llu, protocol=v%d", 
             payload_size, packet->timestamp_ms, negotiated_protocol_version_);

    delete[] payload;
}

bool WebsocketProtocol::SendText(const std::string& text)
{
    // Check if WebSocket is connected
    if (!IsConnected()) {
        ESP_LOGE(TAG, "WebSocket is not connected");
        SetServerErrorState(true);
        return false;
    }

    // Attempt to send the text message
    esp_err_t err = websocket_client_send_text(text.c_str(), text.length(), portMAX_DELAY);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to send WebSocket text message: %s", esp_err_to_name(err));
        SetServerErrorState(true);
        return false;
    }

    // Clear server error state on successful send
    SetServerErrorState(false);
    return true;
}

bool WebsocketProtocol::OpenAudioChannel()
{
    // Get system information and settings
    SystemInfo* sys_info = SystemInfo::GetInstance();
    Settings* settings = Settings::GetInstance();

    // Configure WebSocket URL for audio streaming
    std::string audio_url = settings->GetAudioStreamUrl();
    if (audio_url.empty()) {
        ESP_LOGE(TAG, "Audio stream URL not configured");
        return false;
    }

    // Create WebSocket client configuration
    websocket_client_config_t config = {};
    config.uri = audio_url.c_str();

    // Set authentication headers
    std::string auth_token = settings->GetAuthToken();
    if (!auth_token.empty()) {
        config.headers = reinterpret_cast<const char**>(malloc(sizeof(char*) * 2));
        config.headers[0] = reinterpret_cast<const char*>(malloc(256));
        snprintf(const_cast<char*>(config.headers[0]), 256, "Authorization: Bearer %s", auth_token.c_str());
        config.headers_count = 1;
    }

    // Set protocol version header
    int protocol_version = settings->GetAudioProtocolVersion();
    if (config.headers_count > 0) {
        config.headers = reinterpret_cast<const char**>(realloc(const_cast<char**>(config.headers), sizeof(char*) * (config.headers_count + 1)));
    } else {
        config.headers = reinterpret_cast<const char**>(malloc(sizeof(char*) * 1));
        config.headers_count = 0;
    }

    config.headers[config.headers_count] = reinterpret_cast<const char*>(malloc(128));
    snprintf(const_cast<char*>(config.headers[config.headers_count]), 128, "X-Protocol-Version: %d", protocol_version);
    config.headers_count++;

    // Add device identifier
    std::string device_id = sys_info->GetDeviceId();
    if (!device_id.empty()) {
        config.headers = reinterpret_cast<const char**>(realloc(const_cast<char**>(config.headers), sizeof(char*) * (config.headers_count + 1)));
        config.headers[config.headers_count] = reinterpret_cast<const char*>(malloc(128));
        snprintf(const_cast<char*>(config.headers[config.headers_count]), 128, "X-Device-ID: %s", device_id.c_str());
        config.headers_count++;
    }

    // Create WebSocket client
    client_ = esp_websocket_client_init(&config);
    if (!client_) {
        ESP_LOGE(TAG, "Failed to create WebSocket client");
        // Clean up headers
        for (int i = 0; i < config.headers_count; i++) {
            free(const_cast<char*>(config.headers[i]));
        }
        free(const_cast<char**>(config.headers));
        return false;
    }

    // Set up data handler for binary audio packets
    esp_websocket_register_events(client_, WEBSOCKET_EVENT_DATA, 
                                [](void* handler_args, esp_event_base_t base, int32_t event_id, void* event_data) {
        websocket_event_data_t* data = static_cast<websocket_event_data_t*>(event_data);
        WebsocketProtocol* protocol = static_cast<WebsocketProtocol*>(handler_args);

        if (data->op_code == WS_TRANSPORT_OPCODES_BINARY) {
            protocol->HandleAudioData(data->data_ptr, data->data_len, protocol->protocol_version_);
        }
    }, this);

    // Store protocol version for use in callback
    protocol_version_ = protocol_version;

    // Start WebSocket connection
    esp_err_t err = esp_websocket_client_start(client_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start WebSocket client: %s", esp_err_to_name(err));
        esp_websocket_client_destroy(client_);
        client_ = nullptr;
        // Clean up headers
        for (int i = 0; i < config.headers_count; i++) {
            free(const_cast<char*>(config.headers[i]));
        }
        free(const_cast<char**>(config.headers));
        return false;
    }

    ESP_LOGI(TAG, "Audio channel opened successfully with protocol version %d", protocol_version);

    // Clean up headers
    for (int i = 0; i < config.headers_count; i++) {
        free(const_cast<char*>(config.headers[i]));
    }
    free(const_cast<char**>(config.headers));

    return true;
}

void WebsocketProtocol::HandleAudioData(uint8_t* data, size_t len, int protocol_version)
{
    if (!data || len == 0) {
        return;
    }

    switch (protocol_version) {
        case 2: {
            // Protocol v2 handling
            if (len < sizeof(uint32_t)) {
                ESP_LOGW(TAG, "Insufficient data for protocol v2 header");
                return;
            }

            // Extract payload length (assuming big-endian format)
            uint32_t payload_length = ntohl(*reinterpret_cast<uint32_t*>(data));

            if (len < sizeof(uint32_t) + payload_length) {
                ESP_LOGW(TAG, "Incomplete payload for protocol v2");
                return;
            }

            // Extract actual audio payload
            uint8_t* audio_payload = data + sizeof(uint32_t);

            // Process audio payload
            ProcessAudioPayload(audio_payload, payload_length);
            break;
        }

        case 3: {
            // Protocol v3 handling
            if (len < 2 * sizeof(uint32_t)) {
                ESP_LOGW(TAG, "Insufficient data for protocol v3 header");
                return;
            }

            // Extract sequence number and payload length (assuming big-endian format)
            uint32_t sequence_number = ntohl(*reinterpret_cast<uint32_t*>(data));
            uint32_t payload_length = ntohl(*reinterpret_cast<uint32_t*>(data + sizeof(uint32_t)));

            if (len < 2 * sizeof(uint32_t) + payload_length) {
                ESP_LOGW(TAG, "Incomplete payload for protocol v3");
                return;
            }

            // Extract actual audio payload
            uint8_t* audio_payload = data + 2 * sizeof(uint32_t);

            // Process audio payload with sequence number
            ProcessAudioPayload(audio_payload, payload_length, sequence_number);
            break;
        }

        default:
            ESP_LOGW(TAG, "Unsupported protocol version: %d", protocol_version);
            break;
    }
}

