std::string WebsocketProtocol::GetHelloMessage()
{
    char *json_string = nullptr;
    std::string result;

    // Create JSON object
    cJSON *root = cJSON_CreateObject();
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to create JSON root object");
        return "";
    }

    // Add protocol version
    cJSON_AddNumberToObject(root, "version", 1);

    // Add supported features
    cJSON *features = cJSON_CreateObject();
    if (features == nullptr) {
        cJSON_Delete(root);
        ESP_LOGE(TAG, "Failed to create features object");
        return "";
    }
    cJSON_AddBoolToObject(features, "aec", true);  // Acoustic Echo Cancellation
    cJSON_AddBoolToObject(features, "mcp", true);  // Media Control Protocol
    cJSON_AddItemToObject(root, "features", features);

    // Add transport method
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add audio parameters
    cJSON *audio = cJSON_CreateObject();
    if (audio == nullptr) {
        cJSON_Delete(root);
        ESP_LOGE(TAG, "Failed to create audio object");
        return "";
    }

    // Typical audio parameters for embedded systems
    cJSON_AddStringToObject(audio, "format", "pcm");        // PCM format
    cJSON_AddNumberToObject(audio, "sample_rate", 16000);   // 16kHz sample rate
    cJSON_AddNumberToObject(audio, "channels", 1);          // Mono
    cJSON_AddNumberToObject(audio, "frame_duration", 20);   // 20ms frames

    cJSON_AddItemToObject(root, "audio", audio);

    // Convert to string
    json_string = cJSON_PrintUnformatted(root);
    if (json_string == nullptr) {
        cJSON_Delete(root);
        ESP_LOGE(TAG, "Failed to print JSON string");
        return "";
    }

    result = std::string(json_string);

    // Clean up
    cJSON_Delete(root);
    free(json_string);

    ESP_LOGI(TAG, "Generated hello message: %s", result.c_str());

    return result;
}

bool WebsocketProtocol::ParseServerHello(const cJSON* json)
{
    if (!json) {
        ESP_LOGE(TAG, "Invalid JSON received in server hello");
        return false;
    }

    // Parse session ID
    cJSON* session_id = cJSON_GetObjectItemCaseSensitive(json, "sessionId");
    if (!session_id || !cJSON_IsString(session_id)) {
        ESP_LOGE(TAG, "Missing or invalid sessionId in server hello");
        return false;
    }

    // Store session ID (assuming class has a member for this)
    strncpy(session_id_, session_id->valuestring, sizeof(session_id_) - 1);
    session_id_[sizeof(session_id_) - 1] = '\0';

    // Parse transport type
    cJSON* transport = cJSON_GetObjectItemCaseSensitive(json, "transport");
    if (!transport || !cJSON_IsString(transport)) {
        ESP_LOGE(TAG, "Missing or invalid transport in server hello");
        return false;
    }

    // Validate transport type
    if (strcmp(transport->valuestring, "websocket") != 0) {
        ESP_LOGE(TAG, "Unsupported transport type: %s", transport->valuestring);
        return false;
    }

    // Parse audio configuration
    cJSON* audio_config = cJSON_GetObjectItemCaseSensitive(json, "audio");
    if (!audio_config || !cJSON_IsObject(audio_config)) {
        ESP_LOGE(TAG, "Missing or invalid audio configuration");
        return false;
    }

    // Parse sample rate
    cJSON* sample_rate = cJSON_GetObjectItemCaseSensitive(audio_config, "sampleRate");
    if (!sample_rate || !cJSON_IsNumber(sample_rate)) {
        ESP_LOGE(TAG, "Missing or invalid sampleRate in audio config");
        return false;
    }
    sample_rate_ = sample_rate->valueint;

    // Parse frame duration
    cJSON* frame_duration = cJSON_GetObjectItemCaseSensitive(audio_config, "frameDuration");
    if (!frame_duration || !cJSON_IsNumber(frame_duration)) {
        ESP_LOGE(TAG, "Missing or invalid frameDuration in audio config");
        return false;
    }
    frame_duration_ms_ = frame_duration->valueint;

    // Additional optional parameters could be parsed here
    // For example: channels, bit depth, etc.

    // Set event flag to signal successful parsing
    xEventGroupSetBits(event_group_handle_, SERVER_HELLO_RECEIVED_BIT);

    ESP_LOGI(TAG, "Server hello parsed successfully - Session: %s, Sample Rate: %d, Frame Duration: %dms", 
             session_id_, sample_rate_, frame_duration_ms_);

    return true;
}
